, "chiefComplaints": {"type": "array", "items": {"type": "string"}}, "emergencyContact": {"type": "array", "items": {"type": "object", "properties": {"number": {"type": "string", "description": "Contact number(s)"}, "purpose": {"type": "string", "description": "Purpose (e.g., ''For Appointments'', ''For Medical Emergency'')"}}}, "description": "Emergency contact list"}, "orderedRadiology": {"type": "array", "items": {"type": "object", "properties": {"date": {"type": "string", "description": "Order/result date"}, "status": {"type": "string", "description": "routine, resulted, or pending"}, "study_name": {"type": "string", "description": "Study name"}}}, "description": "Radiology/imaging orders"}, "historyOfPresentIllness": {"type": "object", "properties": {"adl_status": {"type": "string", "description": "Activities of Daily Living status"}, "last_visit": {"type": "string", "description": "Last visit date and doctor"}, "recent_labs": {"type": "string", "description": "Recent lab values"}, "activity_status": {"type": "string", "description": "Activity status"}, "negative_symptoms": {"type": "string", "description": "Symptoms denied"}, "current_complaints": {"type": "string", "description": "Current complaints with details"}, "current_medications": {"type": "array", "items": {"type": "object", "properties": {"name": {"type": "string", "description": "Medication name with strength"}, "schedule": {"type": "string", "description": "Schedule (e.g., ''OD'', ''BD'', ''HS'', ''SOS'')"}}}, "description": "Current medications"}, "other_specialty_medications": {"type": "string", "description": "Medications from other specialists"}}, "description": "History of present illness with current status"}}}', '2026-05-06 03:20:34.810494+00', 'segment_definition:PRESCRIPTION:update', 'e324e84af22c9aaf563a96aba80f7ec49528ce26fd3d1e9db1f07e390cf70c39', '53e17600e6043f542e7d3cd14cdc78f1340c4314c5cd449842edd74df3ce174a', '{}', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, N