      "evening_qty": "0",
      "night_qty": "1",
      "timeToTake": "Before meals",
      "durationDays": "7"
    },
    {
      "name": "Vitamin D3 60000 IU",
      "form": "",
      "remarks": "Once weekly",
      "morning_qty": "1",
      "noon_qty": "0",
      "evening_qty": "0",
      "night_qty": "0",
      "timeToTake": "After breakfast",
      "durationDays": "28"
    },
    {
      "name": "Paracetamol 650mg",
      "form": "Tablet",
      "remarks": "SOS - take if fever above 100°F",
      "morning_qty": "0",
      "noon_qty": "0",
