{% endif %}

{{ RT_PREPARATION }}

{% if simulation_status %}{{ simulation_status }}{% endif %}

{{ FINAL_CONSENT }}

{% if orders %}
{{ ORDERS_HEADER }}
{% for o in orders %}- {{ o }}
{% endfor %}
{% endif %}

{% if onward_referrals %}
{{ REFERRALS_HEADER }}
{% for r in onward_referrals %}- {{ r }}
{% endfor %}
{% endif %}

{% if advice %}
{{ ADVICE_HEADER }}
{% for a in advice %}- {{ a }}
{% endfor %}
{% endif %}

{{ CLOSING }}
') ON CONFLICT DO NOTHING;
