''X-Ray Chest PA View'', ''ECG'')"}, "type": {"type": "string", "description": "Category: Laboratory, Imaging, or Other"}}}}, "chiefComplaints": {"type": "string", "description": "Present complaints as a single narrative string. Empty string if no complaints."}, "generalExamination": {"type": "object", "properties": {"eyes": {"type": "string", "description": "Findings in eyes"}, "face": {"type": "string", "description": "Findings in face region"}, "legs": {"type": "string", "description": "Findings in lower limbs"}, "neck": {"type": "string", "description": "Findings in neck region"}, "others": {"type": "string", "description": "Findings not fitting above categories"}}}, "comorbiditiesNephro": {"type": "object", "properties": {"bp": {"type": "object", "properties": {"since": {"type": "string"}, "status": {"type": "string"}}}, "dm": {"type": "object", "properties": {"since": {"type": "string"}, "status": {"type": "string"}}}, "cough": {"type": "object", "properties": {"since": {"type": "string"}, "status": {"type": "string"}}}, "edema": {"type": "object", "properties": {"since": {"type": "string"}, "status": {"type": "string"}}}, "fever": {"type": "object", "properties": {"since": {"type": "string"}, "status": {"type": "string"}}}, "nausea": {"type": "object", "properties": {"since": {"type": "string"}, "status": {"type": "string"}}}, "stones": {"type": "object", "properties": {"since": {"type": "string"}, "status": {"type": "string"}}}, "smoking": {"type": "object", "properties": {"status": {"type": "string"}}}, "dyspnoea": {"type": "object", "properties": {"since": {"type": "string"}, "status": {"type": "string"}}}, "nocturia": {"type": "object", "properties": {"since": {"type": "string"}, "status": {"type": "string"}}}, "pruritus": {"type": "object", "properties": {"since": {"type": "string"}, "status": {"type": "string"}}}, "vomiting": {"type": "object", "properties": {"since": {"type": "string"}, "status": {"type": "string"}}}, "frequency": {"type": "object", "properties": {"since": {"type": "string"}, "status": {"type": "string"}}}, "hematuria": {"type": "object", "properties": {"since": {"type": "string"}, "status": {"type": "string"}}}, "skin_rash": {"type": "object", "properties": {"since": {"type": "string"}, "status": {"type": "string"}}}, "straining": {"type": "object", "properties": {"since": {"type": "string"}, "status": {"type": "string"}}}}}, "systemicExamination": {"type": "object", "properties": {"rs": {"type": "string", "description": "Respiratory system findings"}, "cns": {"type": "string", "description": "Central nervous system findings"}, "cvs": {"type": "string", "description": "Cardiovascular system findings"}, "abdomen_gi": {"type": "string", "description": "Abdomen / GI system findings"}, "local_examination": {"type": "string", "description": "Any local/focused exam findings not in above systems"}}}, "nutritionalScreening": {"type": "object", "properties": {"bmi": {"type": "string", "description": "BMI value, e.g., ''24.9''. Compute from height/weight if both provided."}, "height": {"type": "string", "description": "Height in cm, e.g., ''170''. Empty string if not measured."}, "weight": {"type": "string", "description": "Weight in kg, e.g., ''72''. Empty string if not measured."}, "bmi_flag": {"type": "string", "description": "Category: ''below_18_5'', ''normal'', or ''above_24_5''. Empty string if BMI not computed."}}}, "historyOfPresentIllness": {"type": "object", "properties": {"drug_history": {"type": "string", "description": "Concatenated list of current medications and other-specialty meds"}, "history_of_presenting_illness": {"type": "string", "description": "Labeled narrative of HPI context"}}}}}', '2026-05-12 03:39:06.218818+00', 'system_prompt_config:fc1599cb-78da-454b-a3d3-fe29f83af10c:update', '0a98c794968c112bca60db5ea36e13a5f2c5663db557589a214b2b47c94c2b69', '17209fbea122a1863d2c88563e46046f3e1c3697464bca20a22dc3b61ce6ef1b', '{}', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL,