ring"}, "drinks_8_glasses_water_daily": {"enum": ["No", "Yes", ""], "type": "string"}, "fresh_fruit_servings_per_day": {"enum": ["0", "1–2", "3–5", "6+", ""], "type": "string"}, "vegetable_oil_meals_per_week": {"enum": ["0–1", "2–5", "6–11", "12+", ""], "type": "string"}, "eats_5_handfuls_nuts_per_week": {"enum": ["No", "Yes", ""], "type": "string"}, "omega3_plant_sources_adequate": {"enum": ["No", "Maybe", "Not sure", "Yes", ""], "type": "string"}, "post_emotional_eating_feeling": {"enum": ["Relieved", "Neutral", "Guilty / uncomfortable", "More tired", ""], "type": "string"}, "cow_milk_or_cream_days_per_week": {"enum": ["0", "1–2", "3–5", "6–7", ""], "type": "string"}, "sweets_salty_snacks_consumption": {"enum": ["Minimal", "Light", "Medium", "Heavy", ""], "type": "string"}, "meat_poultry_fish_meals_per_week": {"enum": ["0–1", "2–5", "6–11", "12+", ""], "type": "string"}, "whole_vegetables_servings_per_day": {"enum": ["0", "1–2", "3–5", "6+", ""], "type": "string"}, "caffeinated_beverages_cups_per_day": {"enum": ["0", "1", "2", "3", "4+", ""], "type": "string"}, "added_sugar_elimination_seriousness": {"enum": ["You bet", "Fairly", "Not very", "No", ""], "type": "string"}, "uses_natural_or_artificial_sweeteners": {"enum": ["No", "Yes", ""], "type": "string"}, "whole_grains_legumes_starches_per_day": {"enum": ["0", "1–2", "3–5", "6+", ""], "type": "string"}, "restaurant_or_fast_food_meals_per_week": {"enum": ["0", "1", "2", "3", "4+", ""], "type": "string"}}}, "nutritionRecommendation": {"type": "object", "properties": {"recommendations": {"type": "array", "items": {"type": "string"}, "description": "Actionable plan bullets stated by the consultant"}, "assessment_summary": {"type": "string", "description": "sentence consultant synthesis connecting findings to working hypothesis"}}}}}', '2026-04-29 18:02:35.380342+00', 'system_prompt_config:cf3a7647-49b1-4211-9be7-1cb265e40787:update', 'e2bdb157bedcd77cab5a00b9db1820fa08907ea7c285ca62fec454d2d9a51322', '26603d08a194af