additional_notes": "string", "mr_contraindication": "string", "contrast_allergy_ct_mri": "string", "connective_tissue_disorder": "string", "diabetes_or_kidney_disease": "string", "previous_radiation_exposure": "string"}, "impressionAndPlan": {"impression": "string", "cancer_staging": "string", "risk_stratification": "string", "treatment_decision_summary": "string"}, "associatedSymptoms": {"associated_symptoms": "string"}, "pastMedicalHistory": {"allergies": ["string"], "comorbidities": "string", "current_medications": ["string"]}, "investigationImaging": {"imaging": ["string"]}, "investigationsBiopsy": {"hpr_findings": "string", "biopsy_details": "string"}, "presentingComplaints": {"presenting_complaints": "string"}, "initialOutsideTreatment": {"prior_radiation": "string", "surgery_details": "string", "chemotherapy_details": ["string"], "prior_treatment_summary": "string"}, "discussionConsentClosing": {"advice": ["string"], "orders": ["string"], "onward_referrals": ["string"], "simulation_status": "string", "discussion_summary": "string", "patient_understanding_and_consent": "string"}, "investigationsBloodworks": {"hb_g_dl": "string", "sodium_meq_l": "string", "albumin_mg_dl": "string", "anc_cells_mm3": "string", "calcium_mg_dl": "string", "wbc_cells_mm3": "string", "neutrophils_pct": "string", "potassium_meq_l": "string", "creatinine_mg_dl": "string", "platelets_lakhs_mm3": "string"}}}', '2026-05-02 07:12:37.620076+00', 'system_prompt_config:5664d8ad-dfa3-44fa-8257-c5b41a3a625e:update', 'f0df60a05718434e251f22cb074c7a24ea7a193ba6138244e0bfa16cbd4dac7c', 'a0f808ef5d6372757cfbeff21f9d5bd1d4ba784515427f6fd922e3f930ebbc9b', '{}', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '
{{ GREETING_SALUTATION }}

{{ GREETING_OPENING }}

