)"}, "recommendations": {"type": "array", "items": {"type": "string"}, "description": "Suggestions for communication improvement if applicable"}, "secondary_style": {"type": "string", "description": "Secondary communication style if applicable"}, "style_consistency": {"type": "string", "description": "Was communication style consistent (Highly consistent, Mostly consistent, Variable)"}, "empathy_indicators": {"type": "array", "items": {"type": "string"}, "description": "Specific empathetic statements or behaviors observed"}, "areas_for_improvement": {"type": "array", "items": {"type": "string"}, "description": "Communication aspects that could be enhanced"}, "clinical_significance": {"type": "string", "description": "Impact on patient care (High, Medium, Low)"}, "patient_anxiety_impact": {"type": "string", "description": "How doctor''s style affected patient anxiety (Reduced, No effect, Increased)"}, "active_listening_rating": {"type": "string", "description": "Active listening quality (Excellent, Good, Fair, Poor)"}, "communication_strengths": {"type": "array", "items": {"type": "string"}, "description": "Positive aspects of doctor''s communication"}, "reassurance_effectiveness": {"type": "string", "description": "How effective were reassurance attempts (High, Medium, Low, None attempted)"}, "patient_concerns_addressed": {"type": "string", "description": "Were patient concerns adequately addressed (Fully, Mostly, Partially, Not addressed)"}}}, "TEXT_EMOTION_TREATMENT_COMPLIANCE_LIKELIHOOD": {"type": "object", "required": ["likelihood", "positive_factors", "negative_factors", "confidence"], "properties": {"notes": {"type": "string", "description": "Additional observations"}, "confidence": {"type": "string", "description": "Confidence in this assessment (Low, Medium, High)"}, "likelihood": {"type": "string", "description": "Overall likelihood of treatment compliance (High, Moderate, Low, Very Low)"}, "key_barriers": {"type": "array", "items": {"type": "object", "requ