 voice-based assessment"}, "trajectory": {"enum": ["Improved", "Stable", "Worsened"], "type": "string", "description": "How anxiety changed from start to end based on voice"}, "pre_consultation": {"type": "object", "required": ["level", "confidence"], "properties": {"level": {"enum": ["None", "Mild", "Moderate", "Severe"], "type": "string", "description": "Anxiety level from voice at consultation start"}, "rationale": {"type": "string", "description": "Explanation of voice evidence for this level"}, "confidence": {"enum": ["Low", "Medium", "High"], "type": "string"}, "indicators": {"type": "array", "items": {"type": "string"}, "description": "Specific voice indicators detected (e.g., voice tremor, rapid speech)"}}}, "post_consultation": {"type": "object", "required": ["level", "confidence"], "properties": {"level": {"enum": ["None", "Mild", "Moderate", "Severe"], "type": "string", "description": "Anxiety level from voice at consultation end"}, "rationale": {"type": "string", "description": "Explanation of voice evidence for this level"}, "confidence": {"enum": ["Low", "Medium", "High"], "type": "string"}, "indicators": {"type": "array", "items": {"type": "string"}, "description": "Specific voice indicators detected"}}}, "trajectory_rationale": {"type": "string", "description": "Explanation of voice change trajectory"}}}, "AUDIO_FINANCIAL_CONCERNS": {"type": "object", "required": ["concerns_present", "severity", "confidence"], "properties": {"severity": {"enum": ["None", "Mild", "Moderate", "Severe"], "type": "string", "description": "Overall severity of financial concern from voice"}, "rationale": {"type": "string", "description": "Explanation of voice evidence supporting this assessment"}, "confidence": {"enum": ["Low", "Medium", "High"], "type": "string", "description": "Confidence in assessment"}, "concerns_present": {"type": "boolean", "description": "Were any financial voice stress indicators detected?"}, "specific_concerns": {"type": "array", "items": {"type": "object", "properties": {"severity": {"enum": ["Mild", "Moderate", "Severe"], "type": "string"}, "concern_type": {"type": "string", "description": "Type: Treatment cost, Medication cost, Test cost, Follow-up cost, General financial"}, "voice_evidence": {"type": "string", "description": "Specific voice indicator (e.g., pitch elevated when medication price mentioned)"}}}, "description": "Specific financial concerns detected from voice timing"}, "alternative_requested_voice_cue": {"type": "boolean", "description": "Did voice patterns suggest interest in cheaper alternatives?"}}}, "AUDIO_INTERACTION_DYNAMICS": {"type": "object", "required": ["turn_taking_balance", "conversation_flow", "mutual_engagement", "rapport_quality", "confidence"], "properties": {"rationale": {"type": "string", "description": "Explanation of interaction patterns observed"}, "confidence": {"enum": ["Low", "Medium", "High"], "type": "string", "description": "Confidence in assessment"}, "rapport_quality": {"enum": ["Excellent", "Good", "Fair", "Poor"], "type": "string", "description": "Overall doctor-patient rapport quality from voice"}, "conversation_flow": {"enum": ["Natural", "Mostly natural", "Somewhat stilted", "Stilted"], "type": "string", "description": "Overall conversation flow quality"}, "mutual_engagement": {"enum": ["High", "Medium", "Low"], "type": "string", "description": "Level of mutual engagement between doctor and patient"}, "turn_taking_balance": {"enum": ["Doctor-dominated", "Balanced", "Patient-dominated"], "type": "string", "description": "Balance assessment of who dominated the conversation"}, "interaction_indicators": {"type": "array", "items": {"type": "string"}, "description": "Specific voice interaction patterns (e.g., natural turn-taking, minimal interruptions)"}}}, "AUDIO_COMPLIANCE_INDICATORS": {"type": "object", "required": ["likelihood", "positive_factors", "negative_factors", "confidence"], "properties": {"rationale": {"type": "string", "description": "Explanation o