INSERT INTO public.segment_definitions VALUES ('5d3ba718-912f-4977-bbf1-03432b99c685', 'EXAMINATION', 'Examination', 'Extract vital signs with units and complete urogynecologic examination findings.

**Extraction Rules:**
- Vital Signs: Weight (Kg), Height (cm), Pulse (/min), BP (mmHg)
- Examination: Face, Hair, Breast, P/A (Normal/Lax, Stretch Mark Yes/No), L/E, Leakage, Colour, Labia, Genital Hiatus, Perineum, Vagina, Discharge, Cervix, Uterus, Anus
- ✅ Extract exact values with units as stated
- ✅ For P/A, capture both Normal/Lax status and Stretch Mark Yes/No
- ✅ Use standard abbreviations
- ❌ Do NOT fabricate examination findings
- ❌ Empty string for areas not examined or not mentioned

**Example Vital Signs:**
Weight: "72 Kg", Height: "158 cm", Pulse: "78/min", BP: "130/80 mmHg"
**Example Examination Findings:**
Face: "Normal" | Hair: "Normal, no hirsutism" | Breast: "Normal" | P/A: "Lax, Stretch Mark: Yes" | L/E: "Normal external genitalia" | Leakage: "Positive cough stress test" | Colour: "Pale pink, mild atrophic changes" | Labia: "Normal" | Genital Hiatus: "4 cm" | Perineum: "Deficient perineal body" | Vagina: "Anterior wall descent with straining" | Discharge: "Minimal white, non-offensive" | Cervix: "At hymen with straining" | Uterus: "Normal size, anteverted" | Anus: "Normal tone"
', '{"type": "object", "properties": {"anus": {"type": "string"}, "face": {"type": "string"}, "hair": {"type": "string"}, "labia": {"type": "string"}, "breast": {"type": "string"}, "cervix": {"type": "string"}, "colour": {"type": "string"}, "uterus": {"type": "string"}, "vagina": {"type": "string"}, "leakage": {"type": "string"}, "perineum": {"type": "string"}, "discharge": {"type": "string"}, "per_abdomen": {"type": "string"}, "vital_signs": {"type": "object", "properties": {"bp": {"type": "string"}, "pulse": {"type": "string"}, "height": {"type": "string"}, "weight": {"type": "string"}}}, "stretch_mark": {"type": "string"}, "genital_hiatus": {"type": "string"}, "local_examination": {"type": "string"}}}', 'core', false, 999, NULL, 'balanced', 'medical_terms', NULL, true, '2026-03-23 13:11:12.559558+00', '2026-03-23 13:11:12.559558+00', 'active', NULL, NULL, NULL, false, NULL, false, NULL, NULL) ON CONFLICT DO NOTHING;
