INSERT INTO public.segment_definitions VALUES ('a80aca54-a76c-47da-b4d3-f4947e8c7c9c', 'TREATMENT_DETAILS', 'Treatment Details', '### 10. TREATMENT DETAILS

**Description:** Detailed procedural information for surgical/interventional procedures.

**Sub-categories:**
1. **Procedure Name**: Exact name of surgical/interventional procedure
2. **Anesthesia Type**: GA, Spinal, Local, Regional
3. **Patient Position**: Supine, Prone, Lateral, Lithotomy, Trendelenburg
4. **Intraoperative Findings**: What was discovered during procedure
5. **Operation Notes**: Step-by-step procedural narrative
6. **Construction Details**: Reconstruction specifics

**Extraction Rules:**
- ✅ Include complete procedural details organized by sub-categories
- ✅ Use standard medical abbreviations (GA = General Anesthesia)
- ✅ Document findings chronologically as procedure progressed
- ✅ Include procedure date (DD-MM-YYYY), duration, blood loss, complications

**Example:**
Procedure: "Laparoscopic RYGB" | Anesthesia: "GA" | Position: "Reverse Trendelenburg with legs split" | Findings: "Livery fatty and bulky, Stoma size 2.5 cms"', '{"type": "object", "properties": {"duration": {"type": "string"}, "blood_loss": {"type": "string"}, "complications": {"type": "string"}, "procedure_date": {"type": "string"}, "procedure_name": {"type": "string"}, "anesthesia_type": {"type": "string"}, "operation_notes": {"type": "string"}, "patient_position": {"type": "string"}, "construction_details": {"type": "string"}, "intraoperative_findings": {"type": "string"}}}', 'core', false, 9, 'system', 'detailed', 'medical_terms', 'Detailed procedural information including operation notes', true, '2025-11-05 06:19:30.422688+00', '2025-11-29 08:00:47.388855+00', 'active', NULL, NULL, NULL, false, NULL, false, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.segment_definitions VALUES ('ff16aeb3-505d-4290-b86e-dca721587903', 'CAUTION', 'Caution during patient treatment', 'Extract any allergies (drug, food, environmental), medical reactions, fear, religious limitations etc. that will impact prescribed treatment plan for the patient

❌ Do NOT include drug class side-effect warnings, standard-of-care monitoring items, or general procedure/radiation safety notes — only patient-specific cautions the doctor or patient actually mentioned.

**Examples**
"Claustrophobic for MRI scans"

"Allergic to sulphur based medicines"', '{"type": "string", "description": "Limitations to be aware while prescribing treatment plan"}', 'core', false, 999, 'system', 'balanced', 'medical_terms', 'Cloned from SUMMARY: None', true, '2025-12-10 14:34:02.173315+00', '2026-04-21 09:31:14.743794+00', 'active', NULL, NULL, 'SUMMARY', true, '2025-12-10 14:34:02.173315+00', false, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.segment_definitions VALUES ('48622bbe-17a3-4122-9800-9b5abc99cd59', 'NIDHANA_PANCHAKA', 'Fivefold Diagnosis (Nidhana Panchaka)', '**Description:** Extract the first four components of the Fivefold Diagnostic Framework (Nidhana Panchaka = the five-fold framework of diagnosis). This segment captures the consultant''s diagnostic reasoning in free-text form, using the consultant''s own Sanskrit-English bilingual phrasing.

**Important note on structure:** The classical Nidhana Panchaka has FIVE components: Nidhana (etiology), Poorvarupa (premonitory symptoms), Rupa (clinical features), Upashaya (relieving factors), and Samprapti (pathophysiology). On this form, the first four are free-text fields captured here. The fifth â€” Samprapti â€” is its own SEPARATE structured segment (SAMPRAPTI) because it contains seven categorical sub-fields. So this segment has 4 fields, not 5.

**Sanskrit-English glossary for this segment:**
- **Nidhana Panchaka** = the five-fold (panchaka) diagnostic framework (nidhana = cause / examination)
- **Nidhana** = etiology / causative factors (the *cause* of the disease)
- **Poorvarupa** = premonitory symptoms (the *warning signs* that preceded the current presentation)
- **Rupa** = clinical features (the *cardinal features* / full clinical picture as it now presents)
- **Upashaya** = relieving factors (things that *relieve or aggravate* the condition, including therapeutic trials)
- **Samprapti** = pathophysiology â€” captured in a separate segment, NOT here

**Required Fields (all free text strings, NO {status, remarks} wrapper):**

- **nidhana_etiology** â€” Causative factors as stated by the consultant. Often phrased in Sanskrit-English bilingual form (e.g., "Ahita Ahara vihara" â€” meaning "improper diet and lifestyle"). Use "" if not stated.
- **poorvarupa_premonitory_symptoms** â€” Early or warning symptoms that preceded the current presentation, as stated by the consultant. Use "" if not stated.
- **rupa_clinical_features** â€” The full clinical picture / cardinal features as articulated by the consultant. Use "" if not stated.
- **upashaya_relieving_factors** â€” Things that relieve or aggravate the condition, including therapeutic trials, as stated by the consultant. Use "" if not stated.

**Extraction Rules:**
- âœ… Capture the consultant''s verbatim wording, preserving Sanskrit terminology in transliteration (e.g., "Ahita Ahara vihara", "Ama", "Tridosha prakopa")
- âœ… If the consultant gives both an English explanation and a Sanskrit term, capture both (e.g., "Ahita Ahara vihara (improper diet and lifestyle)")
- âœ… Use "" (empty string) for fields not addressed by the consultant
- âœ… A dash ("-"), em-dash ("â€”"), or "Nil" placeholder used by the consultant as a form-design empty marker (not as an affirmative answer) maps to "" (empty string), NOT to the literal "-" or "Nil". The form uses dashes to mark un-filled fields.
- âŒ Do NOT infer Nidhana from history captured elsewhere (e.g., the patient saying "I eat a lot of spicy food" does not become Nidhana unless the consultant explicitly framed it as the causative factor in their assessment)
- âŒ Do NOT fabricate Rupa or Poorvarupa from symptoms in SROTAS_EXAMINATION â€” only capture what the consultant explicitly articulated in their diagnostic reasoning
- âŒ Do NOT duplicate findings already captured in other segments unless the consultant repeats them as part of the diagnostic framework

**Example (from the sample filled client â€” only Nidhana addressed, others left as dashes by the consultant):**
```json
{
  "nidhana_etiology": "Ahita Ahara vihara",
  "poorvarupa_premonitory_symptoms": "",
  "rupa_clinical_features": "",
  "upashaya_relieving_factors": ""
}
```', '{"type": "object", "properties": {"nidhana_etiology": {"type": "string"}, "rupa_clinical_features": {"type": "string"}, "upashaya_relieving_factors": {"type": "string"}, "poorvarupa_premonitory_symptoms": {"type": "string"}}}', 'core', false, 999, NULL, 'balanced', 'medical_terms', NULL, true, '2026-05-25 17:37:44.691518+00', '2026-05-25 17:37:44.691518+00', 'active', NULL, NULL, NULL, false, NULL, false, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.segment_definitions VALUES ('7c4eaf02-797b-47df-9194-bc9ac961a3f6', 'DOCTOR_COMMUNICATION_STYLE', 'Doctor Communication Style', '### Doctor Communication Style Analysis', '{"type": "object", "required": ["primary_style", "confidence"], "properties": {"notes": {"type": "string", "description": "Additional observations"}, "source": {"enum": ["text_only", "audio_only", "combined", "text", "both"], "type": "string", "description": "Analysis source mode"}, "mismatch": {"type": "boolean", "description": "Whether text and audio analysis disagreed"}, "rationale": {"type": "string", "description": "Combined rationale from text and audio analysis"}, "confidence": {"enum": ["Low", "Medium", "High"], "type": "string", "description": "Confidence in this assessment"}, "text_style": {"type": "string", "description": "Communication style from text analysis"}, "audio_style": {"type": "string", "description": "Communication style from audio analysis"}, "voice_warmth": {"type": "string", "description": "Voice warmth level from audio analysis"}, "primary_style": {"type": "string", "description": "Primary communication style"}, "clarity_rating": {"type": "string", "description": "Rating of communication clarity"}, "tone_consistency": {"type": "string", "description": "Tone consistency from audio analysis"}, "empathy_indicators": {"type": "array", "items": {"type": "string"}, "description": "Indicators of empathy shown"}, "areas_for_improvement": {"type": "array", "items": {"type": "string"}, "description": "Areas where communication could improve"}, "patient_anxiety_impact": {"enum": ["Reduced", "No effect", "Increased"], "type": "string", "description": "Impact on patient anxiety"}, "communication_strengths": {"type": "array", "items": {"type": "string"}, "description": "Communication strengths observed"}}}', 'additional', false, 1005, 'system', 'balanced', 'medical_terms', 'Analysis of doctor''s communication approach', true, '2025-12-16 01:23:58.849054+00', '2025-12-26 16:18:34.713211+00', 'active', NULL, NULL, NULL, false, NULL, false, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.segment_definitions VALUES ('161cbdb3-e0b9-43b7-9ddd-b1af23bb2fe7', 'HISTORY', 'Cardiac history', '**Description:** Comprehensive cardiac history specific to cardiology consultations.

**Required Fields:**
- primary_consultant: "Dr.AP"
- comorbidities: "Systemic hypertension, Type II diabetes mellitus"
