INSERT INTO public.segment_definitions VALUES ('e60d27ef-f1e5-4385-9438-7e5730c080ab', 'OCCUPATION', 'Occupation of patient', 'Extract occupation of patient, as mentioned during consultation since it will be relevant for diagnosis and to understand the context behind symptoms 

