INSERT INTO public.segment_definitions VALUES ('daa63416-22bd-486d-b3df-f1f06e79839f', 'WARNINGS', 'Warnings about allergies', '⚠️ MANDATORY SAFETY CHECK - Check the ''**PATIENT SAFETY ALERTS - AGGREGATED FROM PAST CONSULTATIONS (CRITICAL):**'' text in the user prompt and perform the following checks

1. **ALLERGY CHECK**: For EACH medicine in the prescription:
   - Compare against ALL allergies listed in the text
   - If potential match or similar drug class: FLAG as "ALLERGY_ALERT"
   - If no match found: Record as "CLEARED"

2. **CONTRAINDICATION CHECK**: For EACH medicine:
   - Check against contraindications and medical conditions text
   - If contraindicated: FLAG as "CONTRAINDICATION_ALERT"
   - If caution needed: FLAG as "CAUTION_REQUIRED"

3. Output JSON schema FORMAT RULES:
   - allergy_checks: Semicolon-separated list of "MedicineName:STATUS" or "MedicineName:STATUS(matched: X, note: Y)"
   - contraindication_checks: Semicolon-separated list of "MedicineName:STATUS" or "MedicineName:STATUS(reason: X)"
   - safety_summary: "Status:SAFE|ALERTS_PRESENT|REVIEW_REQUIRED|NO_HISTORY_AVAILABLE | Critical:[comma-separated alerts or ''None'']"

4. If NO allergies/contraindications are known, set safety_summary to "Status:NO_HISTORY_AVAILABLE | Critical:[None]"
1. **ALLERGY CHECK**: For EACH medicine in the prescription:
   - Compare against ALL allergies listed in the text
   - If potential match or similar drug class: FLAG as "ALLERGY_ALERT"
   - If no match found: Record as "CLEARED"

2. **CONTRAINDICATION CHECK**: For EACH medicine:
   - Check against contraindications and medical conditions in the text
   - If contraindicated: FLAG as "CONTRAINDICATION_ALERT"
   - If caution needed: FLAG as "CAUTION_REQUIRED"

3. If NO allergies/contraindications are known, set overall_safety_status to "NO_HISTORY_AVAILABLE"', '{"type": "object", "required": ["allergy_checks", "contraindication_checks", "safety_summary"], "properties": {"allergy_checks": {"type": "string", "description": "JSON string array of allergy checks. Each item: {medicine, status (CLEARED|ALLERGY_ALERT), matched_allergy, notes}"}, "safety_summary": {"type": "string", "description": "JSON string with overall_safety_status (SAFE|ALERTS_PRESENT|REVIEW_REQUIRED) and critical_alerts array"}, "contraindication_checks": {"type": "string", "description": "JSON string array of contraindication checks. Each item: {medicine, status (CLEARED|CONTRAINDICATION_ALERT|CAUTION_REQUIRED), reason}"}}}', 'core', false, 999, 'system', 'balanced', 'medical_terms', NULL, true, '2025-12-13 06:00:32.227699+00', '2025-12-13 06:00:32.227699+00', 'active', NULL, NULL, NULL, false, NULL, false, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.segment_definitions VALUES ('8053edbd-0982-43e7-80e4-edcfd1c99208', 'ICD', 'ICD 10 codes for OP', 'Determine ICD-10 codes for primary and secondary diagnoses

**Extraction Rules:**
- Use accurate or possible ICD-10 codes
- It is okay to leave as n/a if ICD-10 code is not clear for the diagnoses
- If multiple ICD-10 codes are inferred for the different diagnoses, then use comma to separate each ICD-10 code

**Example"
"I50.9, I48.91"', '{"type": "string", "description": "ICD 10 codes for all diagnoses"}', 'core', false, 999, 'system', 'balanced', 'medical_terms', NULL, true, '2025-12-23 10:17:29.019765+00', '2025-12-23 10:20:56.808505+00', 'active', NULL, NULL, NULL, false, NULL, false, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.segment_definitions VALUES ('f545ef18-7893-4f79-b8c9-09109e6ad850', 'TREATMENT_PLAN', 'Cardiac Treatment plan', '**Description:** Summary of visit with clinical notes and advice.

**Required Fields:**
- patient_summary: "Patient history noted"
- current_vitals_summary: "BP- 170/80 mmHg"
- ecg_summary: "ECG- AF with SVR, HR - 40bpm"
- labs_summary: "Blood reports:CR- 1.0, K+ 5.3"
- diet_advice: "Potassium free diet"
- medication_changes: Array of changes
- other_advice: Additional instructions
- assisted_by: "assisted by Akila"

**Medication Changes Format:**
```json
[
  {"action": "Hold", "medication": "Tab. Cardivas CR", "reason": "due to bradycardia, c/of tiredness"},
  {"action": "Decrease", "medication": "Tab. Aldactone", "reason": "25MG OD"},
  {"action": "Increase", "medication": "Tab. Minipress XL", "reason": "5mg OD"},
  {"action": "Continue", "medication": "other medications", "reason": ""}
]
```

**Actions:** Hold, Decrease, Increase, Continue, Start, Stop', '{"type": "object", "properties": {"assisted_by": {"type": "string", "description": "Name of assistant"}, "diet_advice": {"type": "string", "description": "Dietary advice"}, "ecg_summary": {"type": "string", "description": "ECG findings"}, "labs_summary": {"type": "string", "description": "Key lab values"}, "other_advice": {"type": "string", "description": "Other advice"}, "patient_summary": {"type": "string", "description": "Brief summary"}, "medication_changes": {"type": "array", "items": {"type": "object", "properties": {"action": {"type": "string", "description": "Action: Hold, Decrease, Increase, Continue, Start, Stop"}, "reason": {"type": "string", "description": "Reason for change"}, "medication": {"type": "string", "description": "Medication name"}}}, "description": "Medication changes"}, "current_vitals_summary": {"type": "string", "description": "Key vitals"}}, "description": "Care plan and advice summary"}', 'core', false, 11, 'system', 'balanced', 'medical_terms', NULL, true, '2025-12-01 02:49:14.778071+00', '2025-12-01 06:13:37.790737+00', 'active', NULL, NULL, NULL, false, NULL, false, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.segment_definitions VALUES ('890b7aba-d486-432d-b646-ca0bf290fed6', 'PATIENT_INFORMATION', 'Patient Information Opthalmology', '**Description:** Extract basic demographics and admission details. Do NOT extract any patient-identifying information.

**HIPAA PHI EXCLUSION - Do NOT extract:**
- Patient name (use "the patient" instead)
- Patient address
- Patient phone/contact number
- Registration/MRN numbers
- IP numbers

**Extraction Rules:**
- Age must be numeric value only
- Convert admission/discharge dates to DD-MM-YYYY format
- Include ward details if mentioned
- Use "" for any field not mentioned

**Example:**
"Patient John Doe, 45 years old, admitted on January 15th" → `{"age": "45", "gender": "", "admission_date": "15-01-2025"}`
Note: Name is NOT extracted.', '{"type": "object", "properties": {"age": {"type": "string"}, "gender": {"type": "string"}, "ward_name": {"type": "string"}, "bed_number": {"type": "string"}, "admission_date": {"type": "string"}, "discharge_date": {"type": "string"}}}', 'core', false, 999, 'system', 'balanced', 'medical_terms', 'Cloned from PATIENT_INFORMATION: Basic demographics and admission details', true, '2025-12-02 12:40:24.58182+00', '2026-03-24 02:37:43.299815+00', 'active', NULL, NULL, 'PATIENT_INFORMATION', true, '2025-12-02 12:40:24.58182+00', false, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.segment_definitions VALUES ('0a494cde-4593-4293-9426-d0a689b85b10', 'HISTORY', 'Patient History Urogynec', 'Patient medical background covering medical problems, medication history, surgical history, personal history (urinary and bowel habits), and family history.

**Sub-categories:**
1. **Medical Problems**: Previous/current medical conditions (Yes/No, then list)
2. **Medication History**: Current and past medications
3. **Surgical History**: Previous surgeries with years (Yes/No, then list)
4. **Urinary Habit**: Leakage (Yes/No), frequency, fluid intake
5. **Bowel Habit**: Bowel pattern, constipation, incontinence
6. **Family History**: Cancer (Yes/No), other relevant family conditions

**Extraction Rules:**
- ✅ Use standard medical notation: OD = Once Daily, BD = Twice Daily, TDS = Three times daily
- ✅ Include following in current medications object fields: medication_name, dosage, frequency (1-0-0, 1-0-1)
- ✅ For medical problems and surgical history, note Yes/No and then list items
- ✅ Capture leakage type, frequency, and fluid intake details for urinary habit
- ❌ Empty string or empty array if not discussed

**Example:**
```json
{
  "medical_problems": {
    "present": "Yes",
    "conditions": ["Type 2 Diabetes Mellitus", "Hypertension", "Hypothyroidism"]
  },
  "medication_history": [
    {"medication_name": "Metformin 500mg", "dosage": "500mg", "frequency": "1-0-1"},
    {"medication_name": "Amlodipine 5mg", "dosage": "5mg", "frequency": "1-0-0"},
    {"medication_name": "Thyroxine 50mcg", "dosage": "50mcg", "frequency": "1-0-0"}
  ],
  "surgical_history": {
    "present": "Yes",
    "surgeries": ["LSCS - 2015", "Appendectomy - 2010"]
  },
  "urinary_habit": {
    "leakage": "Yes",
    "frequency": "8-10 times/day, 2 times at night",
    "intake": "2 litres/day, 3 cups coffee/day"
  },
  "bowel_habit": "Constipation, straining at stool",
  "family_history": {
    "cancer": "No",
    "other": "Mother had urinary incontinence after menopause"
  }
}
```', '{"type": "object", "properties": {"bowel_habit": {"type": "string"}, "urinary_habit": {"type": "object", "properties": {"intake": {"type": "string"}, "leakage": {"type": "string"}, "frequency": {"type": "string"}}}, "family_history": {"type": "object", "properties": {"other": {"type": "string"}, "cancer": {"type": "string"}}}, "medical_problems": {"type": "object", "properties": {"present": {"type": "string"}, "conditions": {"type": "array", "items": {"type": "string"}}}}, "surgical_history": {"type": "object", "properties": {"present": {"type": "string"}, "surgeries": {"type": "array", "items": {"type": "string"}}}}, "medication_history": {"type": "array", "items": {"type": "object", "properties": {"dosage": {"type": "string"}, "frequency": {"type": "string"}, "medication_name": {"type": "string"}}}}}}', 'core', false, 999, 'system', 'balanced', 'medical_terms', 'Cloned from PATIENT_HISTORY: None', true, '2026-03-24 09:52:57.125791+00', '2026-03-24 09:52:57.125791+00', 'active', NULL, NULL, 'PATIENT_HISTORY', true, '2026-03-24 09:52:57.125791+00', true, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.segment_definitions VALUES ('1c12b2d4-eb55-40f9-a040-046bb5c3dc19', 'VITALS', 'Vitals (KG Cardio)', '**VITALS:** 

Extract vital signs from the consultation.
Output each field as a string value (no units). Leave unmeasured vitals as "".

 Fields:
 - temperature: Temperature in Fahrenheit, e.g., "98.6"
 - pulse: Pulse rate in beats per minute, e.g., "78"
 - respiratory_rate: Respiratory rate in breaths per minute, e.g., "16"
 - blood_pressure: Format as "SBP/DBP", e.g., "120/80". If only one value is mentioned, output that single number.
 - spo2: Oxygen saturation percentage, e.g., "98"

 Do NOT include units in the values. Do NOT negate measurements ("normal" ≠ extract).', '{"type": "object", "properties": {"spo2": {"type": "string", "description": "SpO2 percentage, e.g., ''98''. Empty string if not measured."}, "pulse": {"type": "string", "description": "Pulse rate in bpm, e.g., ''78''. Empty string if not measured."}, "temperature": {"type": "string", "description": "Temperature in F, e.g., ''98.6''. Empty string if not measured."}, "blood_pressure": {"type": "string", "description": "Blood pressure as ''SBP/DBP'', e.g., ''120/80''. Empty string if not measured."}, "respiratory_rate": {"type": "string", "description": "Respiratory rate in breaths/min, e.g., ''16''. Empty string if not measured."}}}', 'core', false, 1, 'system', 'balanced', 'medical_terms', NULL, true, '2026-02-16 07:52:34.478674+00', '2026-04-06 00:03:28.923033+00', 'active', NULL, NULL, NULL, false, NULL, false, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.segment_definitions VALUES ('1dc68706-c381-4a5a-8778-ee677e6bc7e8', 'PROCEDURE_NOTES', 'PSG Procedure Notes', '**PROCEDURE_NOTES:**
Extract procedure details if any procedure was performed.

**Required Fields:**
- procedure_date_time: Date and time of procedure
- consent_tag: "Availed" / "Not"
- procedure_done_by: Name of person who performed procedure
- procedure_name: Name of the procedure
- findings: Procedure findings
- notes: Additional notes
- post_procedure_instructions: Instructions given after procedure

***Example:***
```json
{"procedure_date_time": "26-01-2026 10:30 AM", "consent_tag": "Availed", "procedure_done_by": "Dr. Kumar", "procedure_name": "Fine Needle Aspiration Cytology", "findings": "Aspirate sent for cytology", "notes": "Procedure completed without complications", "post_procedure_instructions": "Apply pressure for 5 minutes"}
```

**Extraction Rules:**
- Extract all procedure details if mentioned
- If no procedure performed, leave fields empty', '{"type": "object", "properties": {"notes": {"type": "string"}, "findings": {"type": "string"}, "consent_tag": {"type": "string", "description": "Availed / Not"}, "procedure_name": {"type": "string"}, "procedure_done_by": {"type": "string"}, "procedure_date_time": {"type": "string"}, "post_procedure_instructions": {"type": "string"}}}', 'additional', false, 11, 'system', 'balanced', 'medical_terms', 'Procedure details including consent, findings, and post-procedure instructions', true, '2026-01-26 02:31:09.256757+00', '2026-01-26 02:31:09.256757+00', 'active', NULL, NULL, NULL, false, NULL, false, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.segment_definitions VALUES ('3c1acff7-8784-4185-b0fb-6f6b7014c83f', 'EXAMINATION', 'Obstetrics Examination', '**Description:** General, systemic, and obstetric examination findings.

