INSERT INTO public.segment_definitions VALUES ('566b0d2a-4a50-4ef0-931d-6a8ef4f77993', 'NUTRITIONAL_SCREENING', 'Nutritional Screening', '**NUTRITIONAL_SCREENING:** Extract anthropometric measurements and compute BMI.

 Fields:
 - height: Height in cm (not feet/inches), e.g., "170"
 - weight: Weight in kg (not pounds), e.g., "72"
 - bmi: Compute BMI = weight_kg / (height_m)^2, rounded to one decimal. If height or weight is missing, output "".
 - bmi_flag: Categorize BMI:
   - "below_18_5" if BMI < 18.5
   - "normal" if BMI between 18.5 and 24.5 (inclusive)
   - "above_24_5" if BMI > 24.5
   - "" if BMI cannot be computed

 Output values as strings (no units)', '{"type": "object", "properties": {"bmi": {"type": "string", "description": "BMI value, e.g., ''24.9''. Compute from height/weight if both provided."}, "height": {"type": "string", "description": "Height in cm, e.g., ''170''. Empty string if not measured."}, "weight": {"type": "string", "description": "Weight in kg, e.g., ''72''. Empty string if not measured."}, "bmi_flag": {"type": "string", "description": "Category: ''below_18_5'', ''normal'', or ''above_24_5''. Empty string if BMI not computed."}}}', 'core', false, 999, NULL, 'balanced', 'medical_terms', NULL, true, '2026-04-06 00:05:07.18642+00', '2026-04-06 00:05:07.18642+00', 'active', NULL, NULL, NULL, false, NULL, false, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.segment_definitions VALUES ('97b2ac27-823c-4b45-9c45-3e66e1a767c4', 'ANXIETY_POST_CONSULTATION', 'Post-Consultation Anxiety Level', '## Post-Consultation Anxiety Level

Assess the patient''s anxiety level at the **end** of the consultation based on:
- Final tone and confidence level
- Relief or continued worry
- Understanding of treatment plan
- Comfort with next steps

**Compare to pre-consultation anxiety:**
- Did doctor reassure effectively?
- Did clear explanations reduce anxiety?
- Are new concerns introduced?

**Severity Levels:**
- **None**: Fully reassured, confident in plan
- **Mild**: Some residual concern but manageable
- **Moderate**: Still worried about treatment/outcome
- **Severe**: Highly anxious despite reassurance

Document change from pre to post consultation (improved, unchanged, worsened).', '{"type": "object", "required": ["level", "confidence"], "properties": {"level": {"enum": ["None", "Mild", "Moderate", "Severe"], "type": "string", "description": "Anxiety severity at consultation end"}, "notes": {"type": "string", "description": "Additional clinical observations"}, "source": {"enum": ["text_only", "audio_only", "combined"], "type": "string", "description": "Analysis source mode"}, "mismatch": {"type": "boolean", "description": "Whether text and audio analysis disagreed"}, "rationale": {"type": "string", "description": "Combined rationale from text and audio analysis"}, "confidence": {"enum": ["Low", "Medium", "High"], "type": "string", "description": "Confidence in this assessment"}, "indicators": {"type": "array", "items": {"type": "string"}, "description": "Specific behaviors or statements indicating anxiety"}, "trajectory": {"type": "object", "properties": {"mismatch": {"type": "boolean"}, "trajectory": {"enum": ["Improved", "Stable", "Worsened", "Unable to determine"], "type": "string"}, "text_change": {"type": "string"}, "audio_trajectory": {"type": "string"}}, "description": "Anxiety trajectory (combined mode)"}, "timestamp_end": {"type": "string", "description": "Approximate timestamp when assessment ends"}, "change_from_pre": {"enum": ["Improved", "Unchanged", "Worsened", "Unable to determine"], "type": "string", "description": "Change in anxiety from pre to post consultation"}, "pre_consultation": {"type": "object", "properties": {"level": {"enum": ["None", "Mild", "Moderate", "Severe"], "type": "string"}, "source": {"enum": ["text_higher", "audio_higher", "both_agree"], "type": "string"}, "mismatch": {"type": "boolean"}, "rationale": {"type": "string"}, "text_level": {"type": "string"}, "audio_level": {"type": "string"}, "combined_score": {"type": "number"}}, "description": "Pre-consultation anxiety (combined mode)"}, "post_consultation": {"type": "object", "properties": {"level": {"enum": ["None", "Mild", "Moderate", "Severe"], "type": "string"}, "source": {"enum": ["text_higher", "audio_higher", "both_agree"], "type": "string"}, "mismatch": {"type": "boolean"}, "rationale": {"type": "string"}, "text_level": {"type": "string"}, "audio_level": {"type": "string"}, "combined_score": {"type": "number"}}, "description": "Post-consultation anxiety (combined mode)"}}}', 'additional', false, 1001, 'system', 'balanced', 'medical_terms', NULL, true, '2025-11-11 02:48:48.088627+00', '2025-12-26 16:18:34.713211+00', 'active', NULL, NULL, NULL, false, NULL, false, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.segment_definitions VALUES ('5ea817a7-231b-4707-ba78-4bd90b810539', 'FINANCIAL_CONCERNS', 'Financial Concerns Detected', '## Financial Concerns Detected

Identify any concerns about treatment costs, affordability, or financial barriers:

**Direct Concerns:**
- Questions about treatment cost
- Requests for generic alternatives
- Concerns about insurance coverage
- Mentions of financial hardship

**Indirect Concerns:**
- Hesitation when expensive treatment mentioned
- Questions about necessity of tests/procedures
- Requests for payment plans
- Delaying care due to cost

**Alternative Treatment Requests:**
- Asking for cheaper medications
- Questioning if less expensive option exists
- Skipping recommended tests/procedures
- Reducing dosage to save money

**Severity:**
- **High**: May skip treatment entirely due to cost
- **Medium**: Will treat but with financial stress
- **Low**: Concerned but manageable

Document exact statements and assess impact on treatment compliance.', '{"type": "object", "required": ["concerns_present", "severity"], "properties": {"notes": {"type": "string", "description": "Additional context"}, "source": {"enum": ["text_only", "audio_only", "combined", "text_higher", "audio_higher", "both_agree"], "type": "string", "description": "Analysis source mode"}, "mismatch": {"type": "boolean", "description": "Whether text and audio analysis disagreed"}, "severity": {"enum": ["None", "Mild", "Moderate", "Severe"], "type": "string", "description": "Severity of financial concerns"}, "rationale": {"type": "string", "description": "Combined rationale from text and audio analysis"}, "confidence": {"enum": ["Low", "Medium", "High"], "type": "string", "description": "Confidence in this assessment"}, "text_severity": {"type": "string", "description": "Text analysis severity level"}, "audio_severity": {"type": "string", "description": "Audio analysis severity level"}, "combined_score": {"type": "number", "description": "Numeric score for severity (combined mode)"}, "concerns_present": {"type": "boolean", "description": "Were any financial concerns detected?"}, "specific_concerns": {"type": "array", "items": {"type": "object", "required": ["concern_type", "evidence"], "properties": {"evidence": {"type": "string"}, "concern_type": {"enum": ["Treatment cost", "Medication cost", "Test/procedure cost", "Insurance coverage", "Alternative options", "Payment plans", "Other"], "type": "string"}, "impact_on_compliance": {"enum": ["High risk", "Moderate risk", "Low risk"], "type": "string"}}}, "description": "List of specific financial concerns"}, "alternative_treatment_requested": {"type": "boolean", "description": "Did patient request cheaper alternatives?"}}}', 'additional', false, 1003, 'system', 'balanced', 'medical_terms', NULL, true, '2025-11-11 02:48:48.088627+00', '2025-12-26 16:18:34.713211+00', 'active', NULL, NULL, NULL, false, NULL, false, NULL, NULL) ON CON