INSERT INTO public.segment_definitions VALUES ('e0353785-c8d3-4e1c-95e5-74c04d0c153f', 'HISTORY_OF_PRESENT_ILLNESS', 'Obstetrics - History of present illness', '**Description:** Narrative format combining key obstetric details.

