no complaints
normal bowel &bladder habits
```', '{"type": "string", "description": "Narrative HPI with age, married duration, gestational age, etc."}', 'core', false, 8, 'system', 'balanced', 'medical_terms', NULL, true, '2025-12-01 03:28:11.440623+00', '2025-12-01 06:00:29.124892+00', 'active', NULL, NULL, NULL, false, NULL, false, NULL, NULL) ON CONFLICT DO NOTHING;
