INSERT INTO public.segment_definitions VALUES ('a085ce97-56c3-4c94-b514-e052bcf143b2', 'NUTRITION_NOTES', 'Notes', '**Description:** Extract the client''s top priorities from nutrition therapy and any free-text notes the consultant should know.

**Required Fields:**

- top_priorities: array, multi-select â€” "Better energy" / "Improved digestion" / "Weight regulation" / "Reduced cravings" / "Better stress-eating control" / "Long-term healthy aging"
- consultant_should_know: free text â€” anything important the client wants the consultant to know, or ""

**Extraction Rules:**
- âœ… Output exact enum strings for top_priorities â€” do not paraphrase
- âœ… Multiple priorities allowed (return as array even for single value)
- âœ… Use [] (empty array) if no priorities selected
- âœ… Capture consultant_should_know in client''s own words verbatim
- âŒ Do NOT infer priorities from other parts of the conversation â€” only from the explicit goals question

**Example:**
```json
{
  "top_priorities": ["Better energy", "Improved digestion", "Weight regulation"],
  "consultant_should_know": "Long working hours, frequent travel makes meal timing inconsistent"
}
```', '{"type": "object", "properties": {"top_priorities": {"type": "array", "items": {"enum": ["Better energy", "Improved digestion", "Weight regulation", "Reduced cravings", "Better stress-eating control", "Long-term healthy aging"], "type": "string"}}, "consultant_should_know": {"type": "string"}}}', 'core', false, 999, NULL, 'balanced', 'medical_terms', NULL, true, '2026-04-29 16:59:17.660772+00', '2026-04-29 16:59:17.660772+00', 'active', NULL, NULL, NULL, false, NULL, false, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.segment_definitions VALUES ('f8205c54-7099-459e-93f1-884102dd73be', 'OTHER_EMOTIONS_DETECTED', 'Other Emotions Detected', '## Other Emotions Detected

Identify medically relevant emotional states beyond anxiety:

**Distress:**
- Emotional pain, suffering
- Difficulty coping with diagnosis
- Overwhelming feelings

**Agitation:**
- Restlessness, irritability
- Difficulty staying focused
- Frustration with symptoms or care

**Fear:**
- Specific phobias (needles, procedures)
- Fear of death, disability, chronic illness
- Fear of hospitalization

**Depression/Sadness:**
- Flat affect, hopelessness
- Loss of interest in treatment
- Withdrawal from care decisions

**Anger/Frustration:**
- With healthcare system, costs, access
- With prior treatment failures
- With symptom progression

**Relief/Hope:**
- Positive emotions after reassurance
- Hope for recovery
- Gratitude for care

List all detected emotions with evidence and clinical significance.', '{"type": "object", "required": ["emotions_detected"], "properties": {"notes": {"type": "string", "description": "Additional observations"}, "source": {"enum": ["text_only", "audio_only", "combined", "text", "audio", "both"], "type": "string", "description": "Analysis source mode"}, "mismatch": {"type": "boolean", "description": "Whether text and audio analysis disagreed"}, "rationale": {"type": "string", "description": "Combined rationale from text and audio analysis"}, "confidence": {"enum": ["Low", "Medium", "High"], "type": "string", "description": "Confidence in this assessment"}, "text_emotions": {"type": "array", "items": {"type": "string"}, "description": "Emotions detected from text analysis"}, "audio_dominant": {"type": "string", "description": "Dominant emotion from audio analysis"}, "dominant_emotion": {"type": "string", "description": "Most prominent emotion throughout consultation"}, "emotions_detected": {"type": "array", "items": {"oneOf": [{"type": "string"}, {"type": "object", "properties": {"emotion": {"type": "string"}, "evidence": {"type": "array", "items": {"type": "string"}}, "severity": {"enum": ["Mild", "Moderate", "Severe"], "type": "string"}, "clinical_significance": {"enum": ["High", "Medium", "Low"], "type": "string"}}}]}, "description": "List of emotions detected - either strings (combined mode) or objects with details (text-only mode)"}}}', 'additional', false, 1002, 'system', 'balanced', 'medical_terms', NULL, true, '2025-11-11 02:48:48.088627+00', '2025-12-26 16:18:34.713211+00', 'active', NULL, NULL, NULL, false, NULL, false, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.segment_definitions VALUES ('8c91d4eb-2595-48b4-8150-c7f5f8d25a3f', 'REPORT_METADATA', 'Report Metadata', '### 14. REPORT METADATA

**Description:** Healthcare facility and provider information. Ultra-concise format.

**Extraction Rules:**
- ✅ Include doctor''s qualifications with name (e.g., MD, DM, MBBS)
- ✅ Use DD-MM-YYYY for dates
- ✅ Ultra-concise format - direct facts only
- ❌ Do NOT include formal verification fields (prepared_by, checked_by) - those are for discharge summaries only

**Example:**
`{"doctors_name": "Dr. Rajesh Kumar, MD, DM (Cardiology)", "specialty": "Cardiology", "hospital_clinic_name": "Apollo Hospitals", "location": "Chennai", "date_of_consultation": "15-01-2025"}`', '{"type": "object", "properties": {"location": {"type": "string"}, "specialty": {"type": "string"}, "doctors_name": {"type": "string"}, "date_of_consultation": {"type": "string"}, "hospital_clinic_name": {"type": "string"}}}', 'additional', false, 14, 'system', 'concise', 'as_spoken', 'Healthcare facility and provider information', true, '2025-11-04 09:26:52.762118+00', '2025-11-22 09:56:18.978736+00', 'active', NULL, NULL, NULL, false, NULL, false, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.segment_definitions VALUES ('a893b91e-1e02-4f4c-9e19-dd18f97a76a7', 'DISCHARGE_CONDITION', 'Discharge Condition', '### 12. DISCHARGE CONDITION

**Description:** Patient''s clinical status at time of discharge.

**Extraction Rules:**
- ✅ **Condition at Discharge**: Overall clinical stability (stable, improving, with ongoing issues)
- ✅ **Functional Status**: Mobility level (ambulatory, requires assistance, bedbound) and self-care ability
- ✅ **Pain Level**: Pain assessment (numeric scale if mentioned)
- ✅ **Vital Signs at Discharge**: Final vital signs when mentioned
- ✅ **Pending Investigations**: Tests awaiting results that need follow-up
- ✅ Note any devices/drains/tubes remaining (NJ tube, catheter, drain)
- ❌ Do NOT repeat admission diagnosis (focus on current state)

**Example - Post-Surgical:**
```
Condition: "Good clinical condition with NJ tube and right drain in situ"
Functional Status: "Ambulatory, able to perform self-care activities independently"
Pain Level: "Minimal pain, controlled with oral analgesics"
Vital Signs: "Stable"
```

**Example - With Ongoing Symptoms:**
```
Condition: "Improved with ongoing mild shortness of breath on exertion"
Functional Status: "Requires assistance with ambulation"
Pain Level: "3/10"
Vital Signs: "BP 130/85 mmHg, stable on current medications"
```', '{"type": "object", "properties": {"pain_level": {"type": "string"}, "functional_status": {"type": "string"}, "condition_at_discharge": {"type": "string"}, "pending_investigations": {"type": "string"}, "vital_signs_at_discharge": {"type": "string"}}}', 'core', false, 11, 'system', 'balanced', 'medical_terms', 'Patient condition and functional status at discharge', true, '2025-11-05 06:19:30.422688+00', '2025-11-29 08:01:22.358072+00', 'active', NULL, NULL, NULL, false, NULL, false, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.segment_definitions VALUES ('9ea26ce1-9364-4091-a7d3-b287c62c3d9e', 'ALLERGY', 'Allergy (KG Cardio)', '**ALLERGY:** Extract patient''s drug/substance allergies.

 Fields:
 - has_allergy: "Yes" if any allergy is affirmed, otherwise "No Known Allergy"
 - details: Specific details about the allergen and reaction (e.g., "Penicillin - rash", "Sulfa drugs - swelling"). Empty string if has_allergy is "No Known Allergy"

 Only extract drug/medication/substance allergies — food intolerances go in details only if clinically relevant.', '{"type": "object", "properties": {"details": {"type": "string", "description": "Specific allergy details (substance, reaction). Empty string if no allergy."}, "has_allergy": {"type": "string", "description": "''Yes'' or ''No Known Allergy''"}}}', 'core', false, 999, NULL, 'balanced', 'medical_terms', NULL, true, '2026-04-06 00:16:18.797458+00', '2026-04-20 11:20:04.999554+00', 'active', NULL, NULL, NULL, false, NULL, false, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.segment_definitions VALUES ('07e1d59b-a68e-4314-b8d8-0598fee958b2', 'OBG_RISK_ASSESSMENT', 'Obstetrics Risk Assessment Score', '**Description:** Gestosis score for pre-eclampsia risk.

**Format:**
```json
{
  "gestosis_score": [
    {"factor": "Primigravida", "score": "1"},
    {"factor": "Short Duration Of Sperm Exposure", "score": "1"}
  ],
  "total_score": "2"
}
```

**Common Risk Factors:**
- Primigravida (Score 1)
- Age >35 or <18 (Score 1)
- Short Duration Of Sperm Exposure (Score 1)
- Family history of PIH (Score 1)
- Previous history of PIH (Score 2)
- Multiple pregnancy (Score 1)
- Diabetes mellitus (Score 1)
- Chronic hypertension (Score 2)', '{"type": "object", "properties": {"total_score": {"type": "string", "description": "Total risk score"}, "gestosis_score": {"type": "array", "items": {"type": "object", "properties": {"score": {"type": "string", "description": "Score value"}, "factor": {"type": "string", "description": "Risk factor"}}}, "description": "Gestosis risk factors"}}, "description": "Risk assessment scoring"}', 'core', false, 6, 'system', 'balanced', 'medical_terms', NULL, true, '2025-12-01 03:30:47.514475+00', '2025-12-01 05:58:35.114784+00', 'active', NULL, NULL, NULL, false, NULL, false, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.segment_definitions VALUES ('82c4e896-b56e-4554-a6fb-b3d869f8ed62', 'TREATMENT_COMPLIANCE_LIKELIHOOD', 'Treatment Compliance Likelihood', '## Treatment Compliance Likelihood

Assess the likelihood that the patient will follow the complete treatment plan:

**Positive Indicators:**
- Understanding of treatment importance
- Commitment to follow instructions
- Questions about proper adherence
- History of good compliance (if mentioned)
- Support system in place
- Clear follow-up plans

**Negative Indicators:**
- Resistance to treatment suggestions
- Expressed doubts about necessity
- Financial barriers to compliance
- Logistical challenges (transportation, work)
- Lack of understanding
- Previous non-compliance (if mentioned)
- No follow-up scheduled

**Assessment Levels:**
- **High (80-100%)**: Strong commitment, good understanding, resources available
- **Moderate (50-79%)**: Some concerns but likely to comply
- **Low (20-49%)**: Multiple barriers, significant doubts
- **Very Low (0-19%)**: Unlikely to follow plan

Provide evidence-based assessment with specific factors.', '{"type": "object", "required": ["likelihood", "positive_factors", "negative_factors", "confidence"], "properties": {"notes": {"type": "string", "description": "Additional observations"}, "source": {"enum": ["text_only", "audio_only", "combined", "text_higher", "audio_higher", "both_agree"], "type": "string", "description": "Analysis source mode"}, "mismatch": {"type": "boolean", "description": "Whether text and audio analysis disagreed"}, "rationale": {"type": "string", "description": "Combined rationale from text and audio analysis"}, "confidence": {"enum": ["Low", "Medium", "High"], "type": "string", "description": "Confidence in this assessment"}, "likelihood": {"enum": ["Very Low", "Low", "Moderate", "High"], "type": "string", "description": "Overall likelihood of treatment compliance"}, "key_barriers": {"type": "array", "items": {"type": "object", "properties": {"evidence": {"type": "string"}, "severity": {"enum": ["Minor", "Moderate", "Major"], "type": "string"}, "barrier_type": {"enum": ["Financial", "Logistical", "Understanding", "Motivation", "Fear/Anxiety", "Social support", "Other"], "type": "string"}}}, "description": "Primary barriers to compliance"}, "combined_score": {"type": "number", "description": "Numeric score for likelihood (combined mode)"}, "recommendations": {"type": "array", "items": {"type": "string"}, "description": "Suggestions to improve compliance"}, "text_likelihood": {"type": "string", "description": "Text analysis likelihood level"}, "audio_likelihood": {"type": "string", "description": "Audio analysis likelihood level"}, "negative_factors": {"type": "array", "items": {"type": "string"}, "description": "Barriers to compliance"}, "positive_factors": {"type": "array", "items": {"type": "string"}, "description": "Factors supporting compliance"}}}', 'additional', false, 1004, 'system', 'balanced', 'medical_terms', NULL, true, '2025-11-11 02:48:48.088627+00', '2025-12-27 06:17:43.163154+00', 'active', NULL, NULL, NULL, false, NULL, false, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.segment_definitions VALUES ('4cedf331-dc62-4aac-8d13-c27c1092752d', 'CHIEF_COMPLAINTS', 'Chief Complaints (KG Cardio)', '**CHIEF_COMPLAINTS:** Extract the patient''s presenting complaints as a single narrative string.

 **Format:** Comma-separated list with optional severity/duration inline.
 - "Chest pain for 3 days (severe), Breathlessness since last week, Swelling of legs"
 - "Palpitations on exertion, Dizziness"

 **Rules:**
 - Do NOT use bullets or line breaks — single-line narrative.
 - Convert to medical terminology: "sleepless nights" → "Insomnia", "difficulty breathing" → "Dyspnea", "leaking urine" → "Stress urinary incontinence"
 - Include severity and duration inline when mentioned.
 - Do NOT repeat the same complaint.
 - Do NOT include established diagnoses or disease names (e.g., ESRD, Diabetes, Hypertension, CAD). Only include what the patient is feeling/experiencing as symptoms.
- Do NOT restate the diagnosis as a chief complaint. If the doctor says "this patient has ESRD", that is a diagnosis, not a complaint. The complaint would be "Dyspnea" or "Bilateral pedal edema".
- Empty string "" if no complaints mentioned.', '{"type": "string", "description": "Present complaints as a single narrative string. Empty string if no complaints."}', 'core', false, 999, NULL, 'balanced', 'medical_terms', NULL, true, '2026-04-06 00:16:55.900393+00', '2026-04-06 00:16:55.900393+00', 'active', NULL, NULL, NULL, false, NULL, false, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.segment_definitions VALUES ('5089ce29-f142-4d99-a7f1-1a5ab31f28bb', 'OBG_ANTENATAL', 'Antenatal chart', '**Description:** Comprehensive antenatal information.

**Required Fields:**

**Mode of Conception:**
- Values: Spontaneous, IVF, IUI, ICSI, Ovulation induction

**UPT (Urine Pregnancy Test):**
```json
{
  "result": "UPT Positive",
  "test_name": "Urine Pregnancy Test",
  "rchid": "to get"
}
```

**Father Blood Group:** "A positive"

**Pregnancy Details:**
```json
{
  "lmp": "9.10.25",
  "edd": "16.7.26",
  "pre_pregnancy_weight": "53 kg",
  "blood_group_mother": "B positive"
}
```

**Assessment Table (Visit Tracking):**
```json
[
  {
    "date_of_visit": "26.11.25",
    "gestation_in_weeks": "6 w + 6 d",
    "weight": "53.9 kg",
    "bp": "115/ 66 mmHg"
  }
]
```

**Extraction Rules:**
- ✅ Calculate EDD from LMP (LMP + 280 days)
- ✅ Track weight gain across visits
- ✅ Record BP at each visit
- ✅ Calculate gestational age accurately', '{"type": "object", "properties": {"upt": {"type": "object", "properties": {"rchid": {"type": "string", "description": "RCHID status"}, "result": {"type": "string", "description": "UPT Positive/Negative"}, "test_name": {"type": "string", "description": "Urine Pregnancy Test"}}, "description": "Urine Pregnancy Test details"}, "assessment": {"type": "array", "items": {"type": "object", "properties": {"bp": {"type": "string", "description": "BP at visit"}, "weight": {"type": "string", "description": "Weight at visit"}, "date_of_visit": {"type": "string", "description": "Visit date"}, "gestation_in_weeks": {"type": "string", "description": "Gestation in weeks + days"}}}, "description": "Assessment visits table"}, "pregnancy_details": {"type": "object", "properties": {"edd": {"type": "string", "description": "Expected Date of Delivery"}, "lmp": {"type": "string", "description": "Last Menstrual Period date"}, "blood_group_mother": {"type": "string", "description": "Mother''s blood group"}, "pre_pregnancy_weight": {"type": "string", "description": "Pre-pregnancy weight"}}, "description": "Pregnancy details"}, "father_blood_group": {"type": "string", "description": "Father''s blood group"}, "mode_of_conception": {"type": "string", "description": "Spontaneous, IVF, IUI, etc."}}, "description": "Antenatal chart"}', 'core', false, 7, 'system', 'balanced', 'medical_terms', NULL, true, '2025-12-01 03:31:58.717059+00', '2025-12-01 05:59:15.563648+00', 'active', NULL, NULL, NULL, false, NULL, false, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.segment_definitions VALUES ('ad988c59-53b9-477b-ab16-54051ae30109', 'ALLERGIES', 'Aosta Allergies', '**Description:** Known allergies stated separately.

### Extraction Rules
1. **Include all allergy types** — Medications, food, environmental (dust, pollen)
2. **Comma-separated if multiple** — "Penicillin, Sulfa drugs, Peanuts"
3. **Use "NKDA" if explicitly stated** — No Known Drug Allergies
4. **Use empty string if not discussed** — Do NOT assume NKDA unless stated
5. **Include reaction if mentioned** — "Penicillin (causes rash)"

### Example

```json
{
  "Allergies": "Penicillin"
}
```', '{"type": "string", "description": "Known allergies or ''NO KNOWN ALLERGY'' if none"}', 'core', false, 1, 'system', 'balanced', 'medical_terms', 'Cloned from ALLERGIES: Cloned from ALLERGIES: None', true, '2025-12-30 06:28:16.9339+00', '2025-12-30 06:28:16.9339+00', 'active', NULL, NULL, 'ALLERGIES', true, '2025-12-30 06:28:16.9339+00', true, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.segment_definitions VALUES ('c417f5e6-72a9-498f-9fc7-f9009d45f61f', 'TREATMENT_SUMMARY', 'Treatment Summary', '**Description:** High-level summary of treatments administered and patient response.

**Extraction Rules:**
- ✅ **Treatment Summary**: What was DONE (procedures, medications, interventions) - NOT what the problem WAS
- ✅ **Patient Response**: How patient responded (improvement, stable, deterioration)
- ✅ **Complications**: Any adverse events with their management
- ✅ Include dates when procedures were performed
- ✅ Summarize overall clinical course concisely
- ❌ Do NOT repeat diagnosis or detailed procedure steps (those go in Diagnosis and Treatment Details)

**Example - Surgical Treatment:**
```
Treatment Summary: "Laparoscopic Whipple''s procedure performed on 29.09.2025. Patient monitored in ICU post-operatively."
Patient Response: "Patient extubated on POD 1. Recovery was uneventful. Discharged in good clinical condition."
Complications: []
```

**Example - With Complications:**
```
Treatment Summary: "Emergency appendectomy performed under general anesthesia."
Patient Response: "Post-operative recovery progressing well after infection management."
Complications: "Wound infection on POD 3, resolved with antibiotics and wound care by POD 7"
```', '{"type": "object", "properties": {"complications": {"type": "array", "items": {"type": "string"}}, "patient_response": {"type": "string"}, "treatment_summary": {"type": "string"}}}', 'core', false, 3, 'system', 'balanced', 'medical_terms', 'Summary of treatments administered and patient response', true, '2025-11-05 06:19:30.422688+00', '2025-12-01 05:52:25.961651+00', 'active', NULL, NULL, NULL, false, NULL, false, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.segment_definitions VALUES ('35618b37-7353-462a-9cd8-7d86848c8208', 'TREATMENT_PLAN', 'Aosta Treatment Plan', 'Extract follow-up timeline and conditions, and other instructions combining diet, activity, monitoring, and warning signs into one field. Mention referrals if any along with referred to Doctor name and specialty (e.g. Refer to Dr. Gowri ENT specialist) and Include procedures planned (e.g. Schedule for endoscopy next week)

***Example:***
```
json
{
  "TreatmentPlan": "Rest, hydration, and symptomatic treatment. Antihistamines for allergic symptoms. Lifestyle modifications to reduce dust exposure."
}
```', '{"type": "string", "description": "Overall treatment approach and strategy"}', 'core', false, 5, 'system', 'balanced', 'simple_terms', 'Cloned from TREATMENT_PLAN: Cloned from TREATMENT_PLAN: Cloned from TREATMENT_PLAN_SIMPLE: Combined: Prescription + Follow-up + Other instructions (diet/activity/monitoring/warning signs)', true, '2025-12-30 06:30:47.472842+00', '2026-04-20 11:19:51.600461+00', 'active', NULL, NULL, 'TREATMENT_PLAN', true, '2025-12-30 06:30:47.472842+00', true, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.segment_definitions VALUES ('9adeac20-9152-44ba-b9cb-b5c61f48e78a', 'PSG_COURSE_IN_HOSPITAL', 'PSG Course in Hospital', '**PSG_COURSE_IN_HOSPITAL:**
Extract the course of hospital stay including treatment progress.

**Required Fields:**
- course_in_hospital: Narrative of hospital stay

***Example:***
```json
{ "course_in_hospital": "Patient underwent surgery on POD 0, post-op recovery uneventful. Started oral feeds on POD 1. Mobilized on POD 2. Wound inspection satisfactory." }
```', '{"type": "object", "required": ["course_in_hospital"], "properties": {"course_in_hospital": {"type": "string", "description": "Course of hospital stay"}}}', 'core', false, 1024, 'system', 'balanced', 'medical_terms', 'Course in hospital for PSG discharge', true, '2026-01-26 03:02:42.694847+00', '2026-01-26 03:02:42.694847+00', 'active', NULL, NULL, NULL, false, NULL, false, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.segment_definitions VALUES ('8940f8a4-57a0-462d-be6c-91a2b8796651', 'NUTRITION_RECOMMENDATION', 'Recommendation', '**Description:** Extract the consultant''s nutritional plan, recommendations, and assessment narrative as discussed in the consultation.

**Required Fields:**

- assessment_summary: 2â€“4 sentence consultant narrative connecting findings â†’ likely drivers â†’ working hypothesis. May reference pending labs/investigations or multidisciplinary review if mentioned.
- recommendations: array of actionable bullet strings â€” each one a clear, client-friendly instruction (diet swaps, meal timing, hydration, lifestyle, mind-body practices, what to avoid, what to include).

**Extraction Rules:**
- âœ… Each recommendation is one bullet â€” clear, actionable, client-friendly
- âœ… Group related instructions in one bullet (e.g., all hydration advice together)
- âœ… Include ONLY items the consultant explicitly mentioned
- âœ… Clearly state what to do AND what to avoid
- âœ… If the consultant defers the plan pending labs/team review, capture that intent in assessment_summary and use [] for recommendations
- âŒ Empty array [] if no specific recommendations discussed
- âŒ Do NOT add general nutrition advice not stated by the consultant
- âŒ Do NOT duplicate behavior data already captured in other segments

**Example:**
```json
{
  "assessment_summary": "Nutritional assessment has been completed based on the initial consultation, dietary history, and available clinical data. A comprehensive review will be undertaken upon receipt of relevant laboratory investigations. Findings will be further evaluated in conjunction with the multidisciplinary team to ensure an integrated approach to care.",
  "recommendations": [
    "Shift dinner to before 7 pm and keep it light to reduce post-meal heaviness",
    "Increase water intake gradually from 1.5 to 2.5 litres per day",
    "Replace evening fried snacks with fruit or nuts 3 days per week initially",
    "Walk 20 minutes after lunch to reduce afternoon energy crash",
    "Personalized nutrition plan to be communicated after consolidation of all assessment inputs"
  ]
}
```', '{"type": "object", "properties": {"recommendations": {"type": "array", "items": {"type": "string"}, "description": "Actionable plan bullets stated by the consultant"}, "assessment_summary": {"type": "string", "description": "sentence consultant synthesis connecting findings to working hypothesis"}}}', 'core', false, 999, NULL, 'balanced', 'medical_terms', NULL, true, '2026-04-29 17:00:04.215857+00', '2026-04-29 17:00:04.215857+00', 'active', NULL, NULL, NULL, false, NULL, false, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.segment_definitions VALUES ('a7fa540a-023a-47bc-874d-4aa3f3fc8fa0', 'DIAGNOSIS', 'Diagnosis (Roga)', '**Description:** Extract the final Ayurvedic diagnosis (Roga = disease) as stated by the consultant. This is the consolidated diagnostic statement that names the disease in Ayurvedic terminology, typically combining dosha involvement, tissue/channel impairment, and the disease category â€” often with an English explanation in parentheses.

**Sanskrit-English glossary for this segment:**
- **Roga** = disease / illness â€” the named Ayurvedic diagnosis

**Required Field:**
- **roga_diagnosis** â€” Free text. The full Ayurvedic diagnosis as stated by the consultant, including Sanskrit terminology, case (often capitalised by tradition), and any English explanation the consultant adds in parentheses. Use "" if not stated.

**Extraction Rules:**
- âœ… Preserve the consultant''s verbatim phrasing â€” including capitalisation (Ayurvedic diagnoses are often written in ALL CAPS by convention), Sanskrit transliteration, and any explanatory English in parentheses
- âœ… Preserve typos or spelling variants if they appear in the original (e.g., "Impairement" instead of "Impairment" â€” do not correct)
- âœ… Use "" (empty string) if not stated
- âŒ Do NOT abbreviate or shorten the diagnosis
- âŒ Do NOT translate Sanskrit terms unless the consultant did so themselves
- âŒ Do NOT fabricate a diagnosis from the SAMPRAPTI findings â€” only capture what the consultant explicitly stated

**Example (from the sample filled client):**
```json
{
  "roga_diagnosis": "PITTA VATA ANUBANDHA RAKTHA DHUSTI (Impairement of blood due to heat)"
}
```

*(Note: "Impairement" is a typo on the source form. Preserve it verbatim â€” do not auto-correct to "Impairment".)*', '{"type": "object", "properties": {"roga_diagnosis": {"type": "string"}}}', 'core', false, 999, NULL, 'balanced', 'medical_terms', NULL, true, '2026-05-25 17:39:04.054716+00', '2026-05-25 17:39:04.054716+00', 'active', NULL, NULL, NULL, false, NULL, false, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.segment_definitions VALUES ('8df3ced0-04e6-41f6-9e60-0a737c25c6d1', 'HISTORY', 'History (KG Cardio)', '**HISTORY:** Extract family medical history as a single narrative string.

 **Format:** Concatenate family members with their conditions. Examples:
 - "Father: Diabetes (since 10 years). Mother: Hypertension. Brother: MI at age 50."
 - "No significant family history."

 **Rules:**
 - Use ". " (period+space) between family members.
 - Include duration when mentioned.
 - Include relationship (Father, Mother, Brother, Sister, Maternal Grandfather, Paternal Aunt, etc.).
 - "" (empty string) if no family history mentioned.
 - Do NOT include patient''s own habits (smoking/alcohol/tobacco) — those go in COMORBIDITIES.', '{"type": "object", "properties": {"family_history": {"type": "string", "description": "Narrative family medical history string"}}}', 'core', false, 999, NULL, 'balanced', 'medical_terms', NULL, true, '2026-04-06 00:29:01.697436+00', '2026-04-06 00:29:01.697436+00', 'active', NULL, NULL, NULL, false, NULL, false, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.segment_definitions VALUES ('d4932137-5e5d-4c5d-891e-1b46ae446652', 'FOLLOW_UP', 'PSG Follow up', 'Extract follow-up date, notes and other advice instructions combining diet, activity, monitoring, and warning signs. 

***Example:***
```
json
{
  "notes": "Come back in 2 weeks on and bring your previous blood reports",
  "follow_up_date": "10-12-2025",
  "other_instructions": "Increase protein intake, avoid spicy food and avoid heavy lifting. Contact immediately if fever >102°F, severe headache, or breathing difficulty"
}
```', '{"type": "object", "properties": {"notes": {"type": "string", "description": "Instructions on what to bring for next review"}, "follow_up_date": {"type": "string", "description": "Date of follow up in DD-MM-YYYY format"}, "other_instructions": {"type": "string", "description": "Non prescription instructions such as diet, physiotherapy etc. or N/A"}}}', 'core', false, 5, 'system', 'balanced', 'simple_terms', 'Cloned from TREATMENT_PLAN: Cloned from TREATMENT_PLAN: Cloned from TREATMENT_PLAN_SIMPLE: Combined: Prescription + Follow-up + Other instructions (diet/activity/monitoring/warning signs)', true, '2025-12-29 06:13:48.736372+00', '2025-12-29 06:13:48.736372+00', 'active', NULL, NULL, 'TREATMENT_PLAN', true, '2025-12-29 06:13:48.736372+00', true, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.segment_definitions VALUES ('3d09f85d-0283-45d3-a86c-bba6835ee53d', 'HOSPITAL_COURSE', 'Hospital Course', '### 11. HOSPITAL COURSE

**Description:** Chronological narrative of patient''s hospital stay from admission to discharge.

**Extraction Rules:**
- ✅ Organize by post-operative days (POD) or hospital days
- ✅ **Summary**: Overall hospital stay summary
- ✅ **Daily Progress**: Array of daily notes with: day identifier, date (DD-MM-YYYY), clinical status, interventions, response, plan
- ✅ Document significant events chronologically
- ✅ Note changes in clinical status (improving, stable, deteriorating)
- ✅ Include complications with their management
- ✅ Record ICU transfers or ward changes
- ✅ List specialist consultations requested
- ❌ Do NOT repeat diagnosis or full vitals (only changes)

**Example Daily Progress Entry:**
```json
{
  "day": "POD 1",
  "date": "30-09-2025",
  "clinical_status": "Stable, extubated",
  "interventions": "Maintained on IV fluids, chest physiotherapy initiated",
  "response": "Tolerating well",
  "plan": "Continue IV fluids, monitor vitals"
}
```', '{"type": "object", "properties": {"summary": {"type": "string"}, "transfers": {"type": "string"}, "complications": {"type": "string"}, "consultations": {"type": "string"}, "daily_progress": {"type": "string"}}}', 'core', false, 10, 'system', 'detailed', 'medical_terms', 'Narrative of hospital stay from admission to discharge with daily progress', true, '2025-11-05 06:19:30.422688+00', '2025-11-29 08:00:48.106553+00', 'active', NULL, NULL, NULL, false, NULL, false, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.segment_definitions VALUES ('a35204d6-99b2-4486-9e13-17eb70d1ed56', 'REFERRAL_DETAILS', 'Referral Details Radiology', 'Capture the referring physician (and any onward referrals) for a
radiation oncology consult. The dictation is being recorded to
generate a consult letter addressed TO the referring physician —
the salutation "Dear Dr. {{ referred_by }}," depends on this segment.

The very first sentence of every radiology dictation names that
physician — capture it in `referred_by`. Match any of these opening
forms (case-insensitive):
- "Letter to Dr. <Name>"
- "Dear Dr. <Name>"
- "New patient letter to Dr. <Name>"
- "New consult letter to Dr. <Name>"
- "Hi, letter to Dr. <Name>"
- "Hi, dictating a letter to Dr. <Name>"
- "Dictating about <Patient> to Dr. <Name>"
- "Letter regarding <Patient> to Dr. <Name>"

Fields:
- referred_by: name of the referring physician with title preserved
  (e.g. "Dr. Saravanan"). Drop greetings ("Hi", "Okay", "So") and
  filler. This is REQUIRED — virtually every radiology dictation
  opens with it. If the opening line names the physician, NEVER
  leave this empty.
- referred_to: usually "" for radiation oncology consults. Onward
  referrals (e.g. "I''''ll send her to genetics", "med onc referral")
  belong to DISCUSSION_CONSENT_CLOSING.onward_referrals — do NOT
  duplicate them here.
- reason_for_referral: usually "" for radiology consults.
- referral_urgency: usually "" for radiology consults.
- referral_location: usually "" for radiology consults.

Examples (real opening lines from Dharan radiology dictations):
  "Okay, this is a new consult letter to Dr. Saravanan. Patient is
   Mrs. Lakshmi Krishnan, fifty-eight years..."
      → referred_by: "Dr. Saravanan"
  "Hi, dictating a letter to Dr. Anitha Raghavan. Forty-two-year-old
   lady, Ms. Priya Mohan..."
      → referred_by: "Dr. Anitha Raghavan"
  "Dear Dr. Hari, this is regarding Mrs. Vijaya Bhaskar — sixty-seven
   years..."
      → referred_by: "Dr. Hari"
  "Letter to Dr. Meena. New patient — Mrs. Kavitha Devi,
   forty-nine-year-old lady..."
      → referred_by: "Dr. Meena"
  "Dear Dr. Sundaram, dictating about Mrs. Saraswathy Iyer,
   sixty-three..."
      → referred_by: "Dr. Sundaram"
  "Letter to Dr. Padmaja. Mrs. Janaki Ramamurthy, eighty-one years..."
      → referred_by: "Dr. Padmaja"
  "New patient letter to Dr. Mahalingam. Mr. Murugan Selvaraj,
   fifty-six years..."
      → referred_by: "Dr. Mahalingam"
  "Hi, letter to Dr. Lalitha. Patient is Mr. Tenzin Wangchuk,
   thirty-eight years old..."
      → referred_by: "Dr. Lalitha"
  "Letter to Dr. Subramanian. Mr. Krishnamurthy Iyer, sixty-eight..."
      → referred_by: "Dr. Subramanian"
  "Letter to Dr. Vijayakumar. Mr. Ramesh Chandra, sixty-five years..."
      → referred_by: "Dr. Vijayakumar"
  "Dear Dr. Anand. Mr. Suresh Pillai, seventy-two years..."
      → referred_by: "Dr. Anand"
  "Letter to Dr. Pradeep. Mr. Anil Kumar Verma, sixty-nine,
   biochemical recurrence post-radical-prostatectomy..."
      → referred_by: "Dr. Pradeep"
  "Letter to Dr. Ravichandran. Mr. Balasubramanian Nair, sixty-four
   years..."
      → referred_by: "Dr. Ravichandran"
  "Hi, letter to Dr. Mohan Ramachandran. Mrs. Geeta Ramaswamy,
   fifty-nine years..."
      → referred_by: "Dr. Mohan Ramachandran"
  "Letter to Dr. Sankar. Mr. Devasahayam Joseph, seventy-six years..."
      → referred_by: "Dr. Sankar"

Rules:
- ✅ Capture the doctor name verbatim with "Dr." title preserved.
- ✅ Multi-word doctor names (e.g. "Dr. Anitha Raghavan", "Dr. Mohan
  Ramachandran") MUST be captured in full — do not truncate to first
  name only.
- ✅ Use "" for fields not stated (referred_to / reason_for_referral /
  referral_urgency / referral_location are usually "" for radiology).
- ❌ Do NOT include onward referrals here — those belong to
  DISCUSSION_CONSENT_CLOSING.onward_referrals.
- ❌ Do NOT add titles, specialties, or hospital names the doctor
  didn''''t say.
- ❌ Do NOT include greeting words ("Hi", "Okay", "Dear", "So") in the
  captured name.

Output strictly the JSON schema below.

**MRN capture (BUG-017):**
The opening sentence often names the MRN immediately after the patient
name and age, e.g. "MRN four-four-two-one-eight-seven" or "MRN 4-4-2-1-8-7"
or "MRN 442187". Capture into the `mrn` field as a CONTIGUOUS digit string
with NO separators, NO spaces, NO hyphens. Apply the universal numeric
normalization rule from the system prompt.

Examples (real opening lines):
- "MRN 4-4-2-1-8-7" → mrn: "442187"  (Script 1.1)
- "MRN four-four-two-one-eight-seven" → mrn: "442187"
- "MRN nine-zero-three-three-five-one" → mrn: "903351"  (Script 1.3)
- "MRN seven-seven-one-two-zero-three" → mrn: "771203"  (Script 4.1)
- "MRN three-three-eight-nine-six-two" → mrn: "338962"  (Script 3.1)
- "MRN — get from front sheet, I''''ll dictate it later" → mrn: ""
  (doctor explicitly defers; do NOT fabricate)

If the doctor doesn''''t say MRN at all, use "".', '{"type": "object", "properties": {"mrn": {"type": "string"}, "referred_by": {"type": "string"}, "referred_to": {"type": "string"}, "referral_urgency": {"type": "string"}, "referral_location": {"type": "string"}, "reason_for_referral": {"type": "string"}}}', 'core', false, 0, 'system', 'balanced', 'medical_terms', 'Radiation oncology variant of REFERRAL_DETAILS — captures referring physician from the dictation opening line ("Letter to Dr. X", "Dear Dr. Y", etc.).', true, '2026-04-30 07:13:10.213526+00', '2026-04-30 07:13:10.213526+00', 'active', NULL, NULL, 'REFERRAL_DETAILS', true, '2026-04-30 07:13:10.213526+00', false, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.segment_definitions VALUES ('44d40b2f-f9c7-4c3a-9426-7b36a67854de', 'SUMMARY', 'Summary Of Visit', '**Description:** Extract the consultant''s narrative summary of the case â€” a free-text synthesis that ties together findings from the examinations and the Nidhana Panchaka framework into a working clinical impression. This is the consultant''s prose explanation, distinct from the structured diagnostic conclusions in SAMPRAPTI and the named diagnosis in DIAGNOSIS.

**Required Field:**
- **summary** â€” Free text. A 2â€“4 sentence (or longer if the consultant elaborates) clinical narrative as articulated by the consultant. Use "" if not stated.

**Extraction Rules:**
- âœ… Capture the consultant''s wording as closely as possible, preserving Sanskrit terminology, clinical reasoning, and any reference to pending investigations
- âœ… If the consultant defers the summary pending labs or team review, capture that intent verbatim (e.g., "Detailed summary to follow after lab review")
- âœ… Use "" (empty string) if not stated
- âŒ Do NOT fabricate a summary by stitching together findings from other segments â€” only capture what the consultant explicitly said as a summary
- âŒ Do NOT duplicate the named diagnosis here (that belongs in DIAGNOSIS) unless the consultant restated it as part of their summary
- âŒ Do NOT include treatment recommendations here (those belong in PRESCRIPTION and EXTERNAL_THERAPY_AND_DOCUMENTS)

**Example (when the consultant leaves the summary blank on the form, as in the sample client):**
```json
{
  "summary": ""
}
```

**Example (when the consultant provides a summary):**
```json
{
  "summary": "Client presents with Pitta-Vata constitution and early-stage Rakta dushti driven by Ahita Ahara vihara. Rogi bala is high, Roga bala is less, suggesting good prognosis with timely intervention. Will reassess after one cycle of Shamana chikitsa."
}
```', '{"type": "object", "properties": {"summary": {"type": "string"}}}', 'core', false, 999, NULL, 'balanced', 'medical_terms', NULL, true, '2026-05-25 17:39:39.978426+00', '2026-05-25 17:42:33.565112+00', 'active', NULL, NULL, NULL, false, NULL, false, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.segment_definitions VALUES ('49779fc4-f680-4a20-93c0-acdf86516684', 'IMAGING', 'Imaging', '**Description:** Doctor''s review and interpretation of imaging discussed in today''s visit. Distinct from PRIOR_IMAGING (which is the longitudinal list of past imaging) â€” this captures the doctor''s current visit assessment of imaging findings and BIRADS categorization.

**Sub-fields:**

1. **imaging** â€” General imaging review notes from the doctor in this visit. Free text. Captures the doctor''s overall imaging assessment or recent imaging being reviewed.
   - Examples: "Mammogram done outside dated 20-04-2026 reviewed", "Recent USG shows suspicious lesion", "MRI breast pending"

2. **ultrasound** â€” Specific findings from ultrasound or mammogram + ultrasound discussed/done in this visit. Free text.
   - Examples: "USG: Right breast 2.5cm hypoechoic lesion at 10 o''clock with irregular margins, internal vascularity", "Bilateral mammogram + USG: BI-RADS 2, benign-appearing cyst left breast"

3. **birads_category** â€” BIRADS category and findings. Free text as the doctor documents it (e.g., "BIRADS 4a", "BIRADS 2", "BIRADS 0 â€” needs additional imaging").
   - Examples: "BIRADS 4a â€” suspicious, biopsy recommended", "BIRADS 2 â€” benign", "BIRADS 5 â€” highly suggestive of malignancy"

**Extraction Rules:**
- âœ… Capture doctor''s current visit imaging interpretation
- âœ… Preserve BIRADS category exactly as stated (free text â€” do not force into enum)
- âœ… Include laterality and lesion location if mentioned
- âŒ Do NOT duplicate prior imaging entries here (those go to PRIOR_IMAGING)
- âŒ Do NOT fabricate BIRADS if not stated â€” leave as empty string', '{"type": "object", "properties": {"imaging": {"type": "string"}, "ultrasound": {"type": "string"}, "birads_category": {"type": "string"}}}', 'core', false, 999, 'system', 'balanced', 'medical_terms', NULL, true, '2026-05-27 14:14:05.212711+00', '2026-05-27 14:14:05.212711+00', 'active', NULL, NULL, NULL, false, NULL, false, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.segment_definitions VALUES ('4c510b2f-4f9b-4319-9a00-fc723a64c8e4', 'GENERAL_EXAMINATION', 'General Examination (KG Cardio)', '**GENERAL_EXAMINATION:** Classify physical examination findings into 5 body-area buckets.

 **face**: Facial findings — pallor, cyanosis (central/peripheral), facial appearance, moon face, puffiness.
 Examples: "Pallor present", "No cyanosis", "Mild facial puffiness"

 **eyes**: Eye findings — icterus, jaundice, scleral findings, conjunctival pallor, pupillary reactions.
 Examples: "No icterus", "Conjunctival pallor present", "Pupils equal and reactive"

 **neck**: Neck findings — JVP (jugular venous pressure), lymphadenopathy, thyroid enlargement, cervical masses, carotid bruits.
 Examples: "JVP normal, 2 cm above sternal angle", "No cervical lymphadenopathy", "Thyroid not enlarged"

 **legs**: Lower limb findings — pedal edema, clubbing, cyanosis of lower limbs, varicose veins, ankle swelling.
 Examples: "Pedal edema bilateral, grade 2", "No clubbing", "No varicose veins"

 **others**: Any general examination finding that doesn''t fit the above — general appearance, build, nutrition status, hydration, etc.
 Examples: "Well-built, well-nourished, comfortable at rest", "Mildly dehydrated"

 **Rules:**
 - Each field is a string. "" (empty) if not examined or not mentioned.
 - Do NOT put system-specific findings here (CVS/RS/CNS/Abdomen go in SYSTEMIC_EXAMINATION).', '{"type": "object", "properties": {"eyes": {"type": "string", "description": "Findings in eyes"}, "face": {"type": "string", "description": "Findings in face region"}, "legs": {"type": "string", "description": "Findings in lower limbs"}, "neck": {"type": "string", "description": "Findings in neck region"}, "others": {"type": "string", "description": "Findings not fitting above categories"}}}', 'core', true, 8, 'system', 'concise', 'medical_terms', 'Simplified general examination for KG Cardiology Initial Assessment', true, '2026-02-16 16:05:51.39735+00', '2026-04-06 00:32:37.31116+00', 'active', NULL, NULL, NULL, false, NULL, false, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.segment_definitions VALUES ('a7439be4-b900-42fb-9e32-4fdb26172f32', 'PAST_MEDICAL_HISTORY', 'History Radiology', 'Extract pre-existing conditions, ongoing medications, and known
allergies — i.e., the patient''s medical background NOT related to the
current cancer treatment course.

Fields:
- comorbidities: comma-separated list of chronic / pre-existing
  conditions with duration when mentioned (e.g., "Type 2 Diabetes
  for 8 years, Hypertension, Hypothyroidism").
- current_medications: list of medicines the patient is CURRENTLY
  taking, with dose and frequency if stated. Each item as one string.
- allergies: known true allergies (drug / food / environmental) with
  reaction described if mentioned. Use [] if none stated.

Rules:
- ✅ "Currently taking" means the patient is actively on the
  medication AT the time of consult.
- ❌ Do NOT include medications the patient stopped — describe those in
  comorbidities ("Hypertension, previously on Amlodipine 5mg, stopped
  1 month ago").
- ❌ Do NOT include cancer-specific past treatment (chemo, surgery,
  prior RT, recent hormonal therapy) — those go to
  INITIAL_OUTSIDE_TREATMENT.
- ❌ Do NOT include drug class side-effect warnings or contraindications
  as allergies. Only true immune-mediated reactions or stated
  intolerances.
- ✅ Use [] for empty lists, "" for empty strings.

**Conjoined dictation routing examples (BUG-001):**
The doctor often joins comorbidities and medications in one breath.
Split correctly so diseases land in `comorbidities` and drug strings
in `current_medications`:

- "diabetic for eight years on Metformin five hundred BD,
   hypertensive for five years on Telmisartan forty"
   → comorbidities: "Type 2 Diabetes for 8 years, Hypertension for 5 years"
   → current_medications: ["Metformin 500mg BD", "Telmisartan 40mg"]

- "type two diabetes for fifteen years on Metformin one gram BD plus
   Glimepiride two OD, hypertensive on Telmisartan-Amlodipine,
   hypothyroid on Eltroxin seventy-five, BMI thirty-four so class one
   obesity"
   → comorbidities: "Type 2 Diabetes for 15 years, Hypertension, Hypothyroidism, Class 1 obesity (BMI 34)"
   → current_medications: ["Metformin 1g BD", "Glimepiride 2mg OD", "Telmisartan-Amlodipine", "Eltroxin 75mcg"]

- "hypertension on Amlodipine, hypothyroidism on Eltroxin fifty,
   osteoarthritis bilateral knees. She''''s on paracetamol PRN and
   recently they started Tramadol fifty TDS for the back pain"
   → comorbidities: "Hypertension, Hypothyroidism, Bilateral knee osteoarthritis"
   → current_medications: ["Amlodipine", "Eltroxin 50mcg", "Paracetamol PRN", "Tramadol 50mg TDS"]

Routing rules:
- Diseases (with duration when stated) → `comorbidities`
- Drug names + dose + frequency → `current_medications`
- "for X years" attaches to the disease, not the drug
- BMI / class-of-obesity → `comorbidities`', '{"allergies": ["string"], "comorbidities": "string", "current_medications": ["string"]}', 'core', false, 3, 'system', 'balanced', 'medical_terms', NULL, true, '2026-04-26 16:30:47.596416+00', '2026-04-30 07:14:21.135165+00', 'active', NULL, NULL, NULL, false, NULL, false, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.segment_definitions VALUES ('3a37d1ba-2bab-4395-9c29-9e5437276505', 'INVESTIGATION_IMAGING', 'Imaging Radiology', 'Extract imaging investigations done prior to or for this consult, with
findings as the doctor described or read out.

Fields:
- imaging: list of imaging studies, each as one string in the format
  "<modality> <region> [date]: <findings>".
  Examples:
   "MRI Pelvis 12-03-2026: Lower rectal mass 4cm from anal verge,
    extending to mesorectal fascia, multiple enlarged mesorectal
    nodes."
   "PET-CT 05-03-2026: FDG-avid lesion in left breast UOQ with
    ipsilateral axillary nodal uptake. No distant metastasis."

Rules:
- ✅ Use DD-MM-YYYY for the study date if stated; "" if not.
- ✅ Capture the size, location, nodal status, and metastatic status
  if the doctor mentioned them.
- ❌ Do NOT add findings the doctor did not state.
- ❌ Do NOT include biopsy / HPR results — those go to
  INVESTIGATIONS_BIOPSY.
- ❌ Use [] if no imaging was discussed.

**Cross-segment routing — what belongs HERE vs elsewhere (BUG-003):**
- ✅ HERE (INVESTIGATION_IMAGING): MRI, CT, PET, USG, X-ray, bone scan,
   mammogram, PSMA PET findings.
- ❌ NOT HERE:
   - Histopathology / IHC / receptor status / Gleason → INVESTIGATIONS_BIOPSY
   - Hb / platelets / WBC / creatinine etc. → INVESTIGATIONS_BLOODWORKS
   - TNM / FIGO staging → IMPRESSION_AND_PLAN.cancer_staging

Conjoined-dictation routing example:
- "MRI shows a fairly bulky cervical mass, five-point-eight cm, with
   bilateral parametrial involvement... PET shows the cervical primary,
   bilateral pelvic nodes the largest about one-point-eight cm, but no
   para-aortic spread and no distant disease. Biopsy is moderately
   differentiated squamous cell. So she''''s a FIGO three B... Bloods —
   Hb is ten-point-two..."
   → imaging[]: ["MRI Pelvis: bulky cervical mass 5.8 cm with bilateral parametrial involvement", "PET: cervical primary FDG-avid, bilateral pelvic nodes (largest 1.8 cm), no para-aortic / distant disease"]
   → (biopsy text → INVESTIGATIONS_BIOPSY.hpr_findings)
   → (FIGO IIIB → IMPRESSION_AND_PLAN.cancer_staging)
   → (Hb 10.2 → INVESTIGATIONS_BLOODWORKS.hb_g_dl)', '{"imaging": ["string"]}', 'core', false, 6, 'system', 'balanced', 'medical_terms', NULL, true, '2026-04-26 16:33:00.343227+00', '2026-04-30 07:14:21.135165+00', 'active', NULL, NULL, NULL, false, NULL, false, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.segment_definitions VALUES ('03d5df9c-0e9c-432d-bcd9-0f5f30c3ab01', 'PATIENT_INFORMATION', 'Patient Information', '**Description:** Extract basic demographics and admission details. Do NOT extract any patient-identifying information.

**HIPAA PHI EXCLUSION - Do NOT extract:**
- Patient name (use "the patient" instead)
- Patient address
- Patient phone/contact number
- Registration/MRN numbers
- IP numbers

**Extraction Rules:**
- Age must be numeric value only
- Convert admission/discharge dates to DD-MM-YYYY format
- Include ward details if mentioned
- Use "" for any field not mentioned

**Example:**
"Patient John Doe, 45 years old, admitted on January 15th" → `{"age": "45", "gender": "", "admission_date": "15-01-2025"}`
Note: Name is NOT extracted.', '{"type": "object", "properties": {"age": {"type": "string"}, "gender": {"type": "string"}, "ward_name": {"type": "string"}, "bed_number": {"type": "string"}, "admission_date": {"type": "string"}, "discharge_date": {"type": "string"}}}', 'core', true, 999, 'system', 'balanced', 'medical_terms', 'Basic demographics and admission details', true, '2025-11-05 06:19:30.422688+00', '2026-03-24 02:27:50.226336+00', 'active', NULL, NULL, NULL, false, NULL, false, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.segment_definitions VALUES ('6f29d691-ba6d-4ca2-9206-356e37126aa7', 'VITALS', 'Raster Vitals', '**Description:** Complete vital signs in numbers and string where relevant. Unit is not required as that is auto computed. If any vital parameter is not in transcript, then leave it blank or 0. Don''t make any value as negative. 

**Required Fields:**
- systolic_bp (mmHg): 170
- diastolic_bp (mmHg): 80
- pulse (bpm): 74
- temperature(F): 96.80
- bmi: 34.63
- height (cm): 155.0
- weight (kg): 83.20
- Spo2 (%): 98
- waist_circumference (cm): 86
- head_circumference (cm): 50
- pain_score: 5
- intervention_for_pain: "Continue painkiller medicine"
- notes: "all vitals appear to be within normal range"
- pregnancy_status: "yes"
- respiratory_rate (Bpm): 15
- at_room_oxygen_support: "With O2"
- grbs (mg/dL): Random blood sugar / GRBS value. Use "" if not measured.

**Extraction Rules:**
- ✅ Calculate BMI if height/weight provided
- ✅ leave unmeasured vitals as blank or as 0. No negative values
- at_room_oxygen_support is to be populated from within these values "At room", "With O2", "BIPAM"
- pregnancy_status is either "yes" or "no"
- pain_score is within 1 to 10', '{"type": "object", "properties": {"bmi": {"type": "number", "description": "BMI value - calculate if height/weight provided (kg/m2 auto-computed)"}, "grbs": {"type": "number", "description": "GRBS / Random Blood Sugar value (mg/dL)"}, "spo2": {"type": "number", "description": "SpO2 percentage value (% auto-computed)"}, "notes": {"type": "string", "description": "Additional notes about vitals"}, "pulse": {"type": "number", "description": "Pulse rate value (bpm auto-computed)"}, "height": {"type": "number", "description": "Height value (cm auto-computed)"}, "weight": {"type": "number", "description": "Weight value (kg auto-computed)"}, "pain_score": {"type": "number", "description": "Pain score (0-10 scale)"}, "systolic_bp": {"type": "number", "description": "Systolic blood pressure value (mmHg auto-computed)"}, "temperature": {"type": "number", "description": "Temperature value (F auto-computed)"}, "diastolic_bp": {"type": "number", "description": "Diastolic blood pressure value (mmHg auto-computed)"}, "pregnancy_status": {"type": "string", "description": "Pregnancy status (yes/no)"}, "respiratory_rate": {"type": "number", "description": "Respiratory rate value (Bpm auto-computed)"}, "head_circumference": {"type": "number", "description": "Head circumference value (cm auto-computed)"}, "waist_circumference": {"type": "number", "description": "Waist circumference value (cm auto-computed)"}, "intervention_for_pain": {"type": "string", "description": "Description of pain intervention if any"}, "at_room_oxygen_support": {"type": "string", "description": "Oxygen support status (e.g., ''At room'', ''With O2'', ''BIPAM'')"}}, "description": "Vital signs measurements - leave unmeasured vitals as null"}', 'core', false, 2, 'system', 'balanced', 'medical_terms', 'Cloned from VITALS: Cloned from VITALS: None', true, '2025-12-30 11:38:59.496014+00', '2026-04-03 03:54:23.006863+00', 'active', NULL, NULL, 'VITALS', true, '2025-12-30 11:38:59.496014+00', false, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.segment_definitions VALUES ('11b2a653-f444-4ecc-8a56-c1c17387431c', 'INVESTIGATIONS_BLOODWORKS', 'Bloodwork Radiology', 'Extract baseline blood investigation values from the encounter.

Fields (all strings, units WITHOUT spaces; "" if not stated):
- hb_g_dl
- platelets_lakhs_mm3
- wbc_cells_mm3
- anc_cells_mm3
- neutrophils_pct
- creatinine_mg_dl
- albumin_mg_dl
- sodium_meq_l
- potassium_meq_l
- calcium_mg_dl

Rules:
- ✅ Numeric value only, no units in the value
  (e.g., "11.2" not "11.2 g/dL"). Field name carries the unit.
- ✅ If only one of WBC / ANC / Neutrophils is stated, leave the others
  as "".
- ❌ Do NOT infer or compute one value from another.
- ❌ Do NOT include values from past investigations (those belong in
  PRESENTING_COMPLAINTS or INITIAL_OUTSIDE_TREATMENT context only).
  Include here ONLY values discussed as the current baseline.

**Routing example (Script 2.1 — BUG-004):**
"Hb is ten-point-two, that''''s a bit low but expected with the bleeding,
 platelets two-point-eight lakhs, WBC eight-and-a-half thousand,
 ANC five thousand two hundred, neutrophils sixty-five percent.
 Creatinine zero-point-eight, albumin three-point-six, sodium one-three-eight,
 potassium four-point-two, calcium nine-point-one"
   → hb_g_dl: "10.2"
   → platelets_lakhs_mm3: "2.8"
   → wbc_cells_mm3: "8500"           (8.5 thousand → 8500 cells/mm3)
   → anc_cells_mm3: "5200"
   → neutrophils_pct: "65"
   → creatinine_mg_dl: "0.8"
   → albumin_mg_dl: "3.6"
   → sodium_meq_l: "138"
   → potassium_meq_l: "4.2"
   → calcium_mg_dl: "9.1"

Notes:
- "thousand" for WBC / ANC means thousands of cells/mm3 — multiply.
- "lakhs" for platelets — keep value as-is, field name is lakhs/mm3.
- Doctor''''s narrative aside ("a bit low but expected") is NOT captured;
   only the value goes in the field.', '{"hb_g_dl": "string", "sodium_meq_l": "string", "albumin_mg_dl": "string", "anc_cells_mm3": "string", "calcium_mg_dl": "string", "wbc_cells_mm3": "string", "neutrophils_pct": "string", "potassium_meq_l": "string", "creatinine_mg_dl": "string", "platelets_lakhs_mm3": "string"}', 'core', false, 8, 'system', 'balanced', 'medical_terms', NULL, true, '2026-04-26 16:35:14.37037+00', '2026-04-30 07:14:21.135165+00', 'active', NULL, NULL, NULL, false, NULL, false, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.segment_definitions VALUES ('1d85665a-1baf-4bd8-bd99-18a1b78fe6a7', 'PRESCRIPTION', 'PSG Prescription', 'Extract prescription with medication details (name with strength, type, frequency, route of intake, dose in morning-afternoon-evening-night format such as for example, 1-0-0-1, duration, timing, remarks). For Discharge cases, these are medications to be followed upon discharge. 

**Extraction Rules**

Name must include strength — Extract as "Paracetamol 500mg" not just "Paracetamol". If strength not mentioned, extract name only without guessing.
Dose uses M-A-E-N format — Map frequency to pattern: OD morning = 1-0-0-0, OD night = 0-0-0-1, BD = 1-0-0-1, TDS = 1-1-1-0, SOS/PRN = SOS
Type uses standard abbreviations — Tab, Cap, Syp, Inj, Cream, Drops, Inhaler, Spray, Powder, Gel
✅ **durationDays MUST be a number in days**: Convert all durations to days.                                                                                                          
    "1 month" → "30", "2 weeks" → "14", "3 months" → "90", "1 year" → "365", "6 weeks" → "42".                                                                                            
    If doctor says "continue" or "lifelong", or doesn''t mention, use "".
Route defaults to Oral — For tablets/capsules/syrups if not specified. Other routes: IV, IM, Topical, Inhalation, Nasal, Sublingual
Capture special instructions in remarks — Tapering schedules, "do not crush", "avoid alcohol", "gargle after use", "alternate days", storage instructions
Extract each medication separately — Do NOT combine multiple medicines into one entry. Do NOT fabricate medications not mentioned.
✅ **Patient-mentioned meds the doctor doesn''t address**: If the patient mentions taking
     medications on their own ("I''m on BP tablets", "she''s been taking pain meds") but the
     doctor does NOT explicitly continue/modify/prescribe them in this visit, do NOT include
     them in prescription. They belong in HISTORY only.
✅ **No vague placeholders**: If the doctor says "I''ll prescribe tablets for 3 months",
     "give him pain meds", or any equivalent without naming a specific drug, return an
     EMPTY array []. Do NOT invent a name like "Tablets for pain management" or "Pain
     medication". The doctor will write the actual prescription on paper.

***Example:***
```
json
{
  "prescription": [
    {
      "name": "Paracetamol 500mg",
      "remarks": "Continue until fever subsides",
      "dose": "1-0-0-1",
      "type": "Tab",
      "route": "Oral",
      "start_date": "11-12-2025",
      "timeToTake": "After meals",
      "frequency": "Twice a day",
      "durationDays": "5"
    }
  ]
}
```', '{"type": "array", "items": {"type": "object", "properties": {"dose": {"type": "string", "description": "Time to take the medicine e.g. 1-0-0-1"}, "name": {"type": "string", "description": "Name of medicine - formulary or brand name"}, "type": {"type": "string", "description": "Form of medicine - e.g. Tablet or syrup"}, "route": {"type": "string", "description": "How to intake - e.g. Oral"}, "remarks": {"type": "string"}, "frequency": {"type": "string", "description": "How many times to take the medicine e.g. Twice a day"}, "start_date": {"type": "string", "description": "Date to start the prescription in DD-MM-YYYY format"}, "timeToTake": {"type": "string", "description": "Instructions on how to take the medicine - e.g. before food, after food"}, "durationDays": {"type": "string", "description": "Length of prescription e.g. 2 days, 3 weeks"}}}}', 'core', false, 13, 'system', 'balanced', 'simple_terms', 'Cloned from PRESCRIPTION: Cloned from TREATMENT_PLAN: Cloned from TREATMENT_PLAN_SIMPLE: Combined: Prescription + Follow-up + Other instructions (diet/activity/monitoring/warning signs)', true, '2025-12-29 09:01:23.093071+00', '2026-05-06 03:20:37.238163+00', 'active', NULL, NULL, 'PRESCRIPTION', true, '2025-12-29 09:01:23.093071+00', true, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.segment_definitions VALUES ('e5b91cb1-cb06-4507-9c14-42130824bdb9', 'EMERGENCY_CONTACT', 'Emergency Contact', '### EMERGENCY CONTACT (Only if discussed)                                                                                                                                               
                                                            
  **Description:** Single-line emergency guidance combining warning signs and contact info.
                                                                                                                                                                                          
  **Extraction Rules:**
  - ✅ Extract ONLY if emergency contact or warning signs were discussed                                                                                                                  
  - ✅ Combine warning signs + contact details into one natural sentence
  - ✅ Format: "Contact [name/hospital] at [number] if you experience [warning signs]"                                                                                                    
  - ✅ If multiple contacts mentioned, separate with semicolons                                                                                                                           
  - ❌ Return "" (empty string) if not discussed at all                                                                                                                                               
  - ❌ Do NOT fabricate contact numbers not mentioned in the conversation                                                                                                                 
                                                                                                                                                                                          
  **Examples:**                                                                                                                                                                           
  - "Contact Dr.Suresh at 9842210174 if you experience fever with chills, vomiting, or severe abdominal pain"
  - "Visit Emergency (0422-4305720) for breathing difficulty or chest pain; call Dr. Ravi at 9003932323 for medication queries"                                                      
  - "Seek immediate care at Apollo ER (044-28296000, 24/7) if blood pressure exceeds 180/120 or severe headache with vision changes"', '{"type": "string"}', 'additional', false, 17, 'system', 'balanced', 'simple_terms', 'Emergency contact information and warning signs (only if discussed)', true, '2025-11-04 09:26:52.762118+00', '2026-03-23 02:29:52.437719+00', 'active', NULL, NULL, NULL, false, NULL, false, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.segment_definitions VALUES ('85a55bd8-6324-4d4f-a52e-7182f0923e3c', 'HISTORY', 'History and Chief Complaints', 'Extract patient history including chief complaints with duration, history of present illness as ONE sentence, current medications (name/dosage/frequency only), past medical and surgical history, past investigations and other history combining family/social/allergies

**Extraction Rules:**
- Chief Complaints: Extract key symptoms in ultra-brief medical terminology. Include ALL symptoms (primary + associated) in priority order. Convert to medical terminology: "sleepless nights" → "Insomnia", "difficulty breathing" → "Dyspnea". Include duration with "×" notation (× 2d = for 2 days)
- History of present illness: Characterize in one line the onset, severity and progression where relevant. Include negative findings in history if explicitly mentioned (e.g., "No altered bowel movements")
- Past Medical History: Previous medical conditions and hospitalizations
- Past Surgical History: Mention Previous surgeries along with year of procedure
- Other History: Includes details on family medical conditions, birth history, allergy etc. 
- Current medications: medication_name, dosage and frequency (1-0-0, 1-0-1). Use standard medical notation: OD = Once Daily, BD = Twice Daily, TDS = Three times daily, QID = Four times daily
- Past Investigations: Previously done investigations with results mentioned during consultation (e.g., "previous Echo showed EF 45%", "last HbA1c was 7.2%")

**Examples:**
["Headache, dizziness × 2d post-medication discontinuation. Sever, started 2 days ago and gradually worsening", "Fatigue, palpitations. No chest pain"]', '{"type": "object", "properties": {"other_history": {"type": "string", "description": "Combined family, social and allergic history"}, "chief_complaints": {"type": "array", "items": {"type": "string"}, "description": "Array of symptoms in medical terminology with duration (e.g., Headache x 2d)"}, "current_medications": {"type": "array", "items": {"type": "object", "properties": {"dosage": {"type": "string"}, "frequency": {"type": "string"}, "medication_name": {"type": "string"}}}, "description": "Current medications with name, dosage, frequency only"}, "past_investigations": {"type": "array", "items": {"type": "object", "properties": {"date": {"type": "string"}, "result": {"type": "string"}, "test_name": {"type": "string"}}}}, "past_medical_history": {"type": "string", "description": "Comma-separated previous medical conditions or N/A"}, "past_surgical_history": {"type": "string", "description": "Comma-separated previous surgeries with years or N/A"}, "history_of_present_illness": {"type": "string", "description": "ONE SENTENCE combining onset, progression, severity, negative findings"}}}', 'core', false, 1, 'system', 'balanced', 'medical_terms', 'Cloned from HISTORY_SIMPLE: Combined: Chief complaints + HPI (one sentence) + Current medications + Past medical/surgical + Other history', true, '2025-11-25 04:52:17.075269+00', '2026-03-24 02:25:53.457383+00', 'active', NULL, NULL, 'HISTORY_SIMPLE', true, '2025-11-25 04:52:17.075269+00', false, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.segment_definitions VALUES ('ea107436-9fb0-4a8b-8ee4-81c163edbeac', 'SYSTEMIC_EXAMINATION', 'Systemic Examination (KG Cardio)', '**SYSTEMIC_EXAMINATION:** Bucket system-specific examination findings into 5 fixed keys.

 **cvs** (Cardiovascular System): Heart sounds, murmurs, rhythm, apex beat, heaves/thrills, peripheral pulses.
 Examples: "S1S2 normal, no murmurs, apex beat in 5th ICS MCL", "Systolic murmur grade 3/6 at aortic area"

 **rs** (Respiratory System): Breath sounds, air entry, crepitations, wheezes, chest expansion, percussion.
 Examples: "B/L equal air entry, no added sounds, vesicular breath sounds", "Crepitations at bilateral lung bases"

 **abdomen_gi** (Abdomen / GI): Abdominal tenderness, organomegaly, bowel sounds, ascites, masses.
 Examples: "Soft, non-tender, no organomegaly, bowel sounds present", "Hepatomegaly 3 cm below costal margin"

 **cns** (Central Nervous System): Mental status, cranial nerves, motor/sensory, reflexes, coordination, gait.
 Examples: "Conscious, oriented, no focal neurological deficit", "Power 4/5 in right upper limb"

 **local_examination**: Any focused/local exam (e.g., joint, skin, musculoskeletal, ENT, genitourinary) not covered above.
 Examples: "Right knee: mild swelling, no warmth", "Thyroid: diffuse enlargement, soft consistency"

 **Rules:**
 - Each field is a string. "" (empty) if that system not examined or not mentioned.
 - Do NOT include general examination findings (pallor, icterus, edema — those go in GENERAL_EXAMINATION).', '{"type": "object", "properties": {"rs": {"type": "string", "description": "Respiratory system findings"}, "cns": {"type": "string", "description": "Central nervous system findings"}, "cvs": {"type": "string", "description": "Cardiovascular system findings"}, "abdomen_gi": {"type": "string", "description": "Abdomen / GI system findings"}, "local_examination": {"type": "string", "description": "Any local/focused exam findings not in above systems"}}}', 'core', false, 999, NULL, 'balanced', 'medical_terms', NULL, true, '2026-04-06 00:35:07.118932+00', '2026-04-06 00:35:07.118932+00', 'active', NULL, NULL, NULL, false, NULL, false, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.segment_definitions VALUES ('584ee68b-a58c-4ac4-801a-f3bf87a3145a', 'EXAMINATION_GYN', 'Examination for Gyn Radiology', 'Extract gynecologic-site examination findings, brachytherapy plan, and
any gyn-specific workup details from the encounter.

Fields:
- per_vaginal_exam: PV findings — external genitalia, cervix
  involvement (which lip / fornix / vaginal wall), vaginal extension
  with length in cm if stated.
- per_rectal_exam: PR findings — rectal mucosa, parametrial
  involvement (right/left, NMD = node-mass distance or distance to
  pelvic wall) as the doctor stated.
- parametrial_involvement: e.g., "Right parametrium involved up to
  midway; left parametrium free." Use "" if not stated.
- vaginal_extension_cm: numeric string in cm if stated. Else "".
- examination_under_anaesthesia: "Yes" / "No" / "" — was an EUA done
  or planned.
- brachytherapy_planned: "Yes" / "No" / "" — only if explicitly stated.
- brachytherapy_modality: e.g., "MR-guided intracavitary",
  "Interstitial", "Intracavitary + interstitial", or "" if not stated.
- brachytherapy_fractions_planned: numeric string of fractions, or "".
- menopausal_status: "Premenopausal" / "Postmenopausal" /
  "Perimenopausal" / "" if not stated.
- additional_site_notes: anything else gyn-specific (e.g., bladder
  filling protocol, hydronephrosis status, fertility preservation
  conversation).

Rules:
- ✅ Capture only what the doctor stated. Brachytherapy fields stay
  "" unless explicitly mentioned.
- ❌ Do NOT include items already in COMMON_EXAM (neck, abdomen,
  spine).
- ❌ Use "" for fields not stated.

**Conjoined-narrative split example (Script 2.1 — BUG-005):**
"Examined her with consent. ECOG one, KPS eighty, conscious and
 cooperative, no acute distress. Neck and abdomen unremarkable, spine
 non-tender. On the per-vaginal — external genitalia look normal, the
 growth is involving both the anterior and posterior lips of cervix,
 both fornices are obliterated, extending into the upper vagina, length
 roughly four centimetres. Per rectal — rectal mucosa is smooth, but
 the right parametrium is involved up to the side wall, no mucosal
 disease, and on the left the parametrium is involved up to the medial
 two-thirds."
   → per_vaginal_exam: "External genitalia normal; growth involving anterior and posterior lips of cervix; bilateral fornices obliterated; vaginal extension into upper vagina, length 4 cm"
   → per_rectal_exam: "Rectal mucosa smooth; right parametrium involved up to side wall; left parametrium involved up to medial two-thirds; no mucosal disease"
   → parametrial_involvement: "Right parametrium up to pelvic side wall; left parametrium up to medial two-thirds"
   → vaginal_extension_cm: "4"
   → (Consent, ECOG, KPS, neck, abdomen, spine items belong to COMMON_EXAM)', '{"per_rectal_exam": "string", "per_vaginal_exam": "string", "menopausal_status": "string", "vaginal_extension_cm": "string", "additional_site_notes": "string", "brachytherapy_planned": "string", "brachytherapy_modality": "string", "parametrial_involvement": "string", "examination_under_anaesthesia": "string", "brachytherapy_fractions_planned": "string"}', 'core', false, 14, 'system', 'balanced', 'medical_terms', NULL, true, '2026-04-27 01:57:30.779119+00', '2026-04-30 07:15:32.52397+00', 'active', NULL, NULL, NULL, false, NULL, false, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.segment_definitions VALUES ('a103e3a1-9ea1-4821-b301-c900135e39ac', 'WOUND_EXAMINATION', 'Wound Examination (KG Reassess)', 'Extract the post-operative wound examination. healing_status should be "healing_well" or "gaping" based on the doctor''s comment, or empty if not assessed. discharge should describe any drainage if mentioned (color, amount, consistency); empty if no discharge.', '{"type": "object", "properties": {"discharge": {"type": "string", "description": "Free-text description of any wound discharge (e.g. ''serous, minimal'' or ''purulent, moderate''). Empty if no discharge or not mentioned."}, "healing_status": {"type": "string", "description": "''healing_well'' or ''gaping'' based on the doctor''s comment. Empty if no wound or not commented on."}}}', 'core', false, 999, 'system', 'balanced', 'medical_terms', NULL, true, '2026-04-13 12:05:35.18138+00', '2026-04-13 12:05:35.18138+00', 'active', NULL, NULL, NULL, false, NULL, false, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.segment_definitions VALUES ('acb1cca9-658c-4674-8989-8f0855a3174f', 'INVESTIGATIONS_DONE', 'Investigation Done (KG Reassess)', 'List all investigations the patient has already had done and which are being discussed/reviewed in this visit. For each, capture the test name, category (Laboratory, Imaging, or Other), and the date if stated. Return an empty array if none.', '{"type": "array", "items": {"type": "object", "properties": {"date": {"type": "string", "description": "Test date in DD-MM-YYYY format if stated, empty otherwise"}, "name": {"type": "string", "description": "Full test/study name (e.g. ''ECG'', ''2D Echo'', ''Troponin I'')"}, "type": {"type": "string", "description": "Category: Laboratory | Imaging | Other"}}}, "description": "Investigations already performed and reviewed during this visit"}', 'core', false, 999, 'system', 'balanced', 'medical_terms', NULL, true, '2026-04-13 12:05:35.18138+00', '2026-04-13 12:05:35.18138+00', 'active', NULL, NULL, NULL, false, NULL, false, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.segment_definitions VALUES ('246380c9-2960-4b4d-b315-553475e2bbb5', 'SYSTEMIC_EXAMINATION', 'Systemic Examination (KG Reassess)', 'Extract systemic examination findings for the four systems shown on the form: CVS (cardiovascular), RS (respiratory), P/A (per abdomen), and CNS (central nervous system). Use "Normal" for any system not examined or not mentioned.', '{"type": "object", "properties": {"pa": {"type": "string", "description": "Per abdomen findings (e.g. ''Soft, non-tender, no organomegaly''). ''Normal'' if not examined."}, "rs": {"type": "string", "description": "Respiratory system findings (e.g. ''Bilateral air entry equal, clear''). ''Normal'' if not examined."}, "cns": {"type": "string", "description": "Central nervous system findings (e.g. ''Conscious, oriented, no focal deficit''). ''Normal'' if not examined."}, "cvs": {"type": "string", "description": "Cardiovascular system findings (e.g. ''S1 S2 normal, no murmur''). ''Normal'' if not examined."}}}', 'core', false, 999, 'system', 'balanced', 'medical_terms', NULL, true, '2026-04-13 12:05:35.18138+00', '2026-04-20 11:13:14.558229+00', 'active', NULL, NULL, NULL, false, NULL, false, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.segment_definitions VALUES ('3c639fd0-cea8-4ab0-9db8-4492fbc8b9d3', 'CHIEF_COMPLAINTS', 'Chief Complaints (KG Reassess)', 'Listen for each of the 17 cardiac re-assessment symptoms. For each symptom: set present = "Yes" if the patient reports it (for normal_bowel_habits and normal_bladder_habits, set "Yes" only if the patient confirms NORMAL habits); otherwise leave as empty string if unreported. If explicitly stated as "No", then set "No". When present="Yes", also fill duration (e.g. "3 days", "2 weeks") if stated, and description (free-text severity/character/triggers) if mentioned. The 17 symptoms are: pain over surgical site, chest pain, breathlessness, palpitations, pedal edema, giddiness, fatigue, PND, orthopnea, shoulder pain, body pain, normal bowel habits, normal bladder habits, loss of appetite, decreased sleep, sweating, ambulation.

Default to "" (empty string) if not explicitly stated. ', '{"type": "object", "properties": {"pnd": {"type": "object", "properties": {"present": {"type": "string", "description": "''Yes'' if patient reports paroxysmal nocturnal dyspnea, otherwise ''No''"}, "duration": {"type": "string"}, "description": {"type": "string"}}}, "fatigue": {"type": "object", "properties": {"present": {"type": "string", "description": "''Yes'' if patient reports fatigue/tiredness, otherwise ''No''"}, "duration": {"type": "string"}, "description": {"type": "string"}}}, "sweating": {"type": "object", "properties": {"present": {"type": "string", "description": "''Yes'' if patient reports abnormal sweating/diaphoresis, otherwise ''No''"}, "duration": {"type": "string"}, "description": {"type": "string"}}}, "body_pain": {"type": "object", "properties": {"present": {"type": "string", "description": "''Yes'' if patient reports generalized body pain, otherwise ''No''"}, "duration": {"type": "string"}, "description": {"type": "string"}}}, "giddiness": {"type": "object", "properties": {"present": {"type": "string", "description": "''Yes'' if patient reports giddiness/dizziness, otherwise ''No''"}, "duration": {"type": "string"}, "description": {"type": "string"}}}, "orthopnea": {"type": "object", "properties": {"present": {"type": "string", "description": "''Yes'' if patient reports orthopnea (breathlessness lying flat), otherwise ''No''"}, "duration": {"type": "string"}, "description": {"type": "string"}}}, "ambulation": {"type": "object", "properties": {"present": {"type": "string", "description": "''Yes'' if ambulation issues mentioned (difficulty walking), ''No'' if patient is ambulating normally"}, "duration": {"type": "string"}, "description": {"type": "string"}}}, "chest_pain": {"type": "object", "properties": {"present": {"type": "string", "description": "''Yes'' if patient reports chest pain, otherwise ''No''"}, "duration": {"type": "string"}, "description": {"type": "string"}}}, "pedal_edema": {"type": "object", "properties": {"present": {"type": "string", "description": "''Yes'' if patient reports pedal/leg swelling, otherwise ''No''"}, "duration": {"type": "string"}, "description": {"type": "string"}}}, "palpitations": {"type": "object", "properties": {"present": {"type": "string", "description": "''Yes'' if patient reports palpitations, otherwise ''No''"}, "duration": {"type": "string"}, "description": {"type": "string"}}}, "shoulder_pain": {"type": "object", "properties": {"present": {"type": "string", "description": "''Yes'' if patient reports shoulder pain, otherwise ''No''"}, "duration": {"type": "string"}, "description": {"type": "string"}}}, "breathlessness": {"type": "object", "properties": {"present": {"type": "string", "description": "''Yes'' if patient reports breathlessness/dyspnea, otherwise ''No''"}, "duration": {"type": "string"}, "description": {"type": "string"}}}, "decreased_sleep": {"type": "object", "properties": {"present": {"type": "string", "description": "''Yes'' if patient reports decreased/disturbed sleep, otherwise ''No''"}, "duration": {"type": "string"}, "description": {"type": "string"}}}, "loss_of_appetite": {"type": "object", "properties": {"present": {"type": "string", "description": "''Yes'' if patient reports loss of appetite, otherwise ''No''"}, "duration": {"type": "string"}, "description": {"type": "string"}}}, "normal_bowel_habits": {"type": "object", "properties": {"present": {"type": "string", "description": "''Yes'' if bowel habits are NORMAL, ''No'' if abnormal/constipation/diarrhea reported"}, "duration": {"type": "string", "description": "Duration of abnormality if reported"}, "description": {"type": "string", "description": "Description of any abnormality if mentioned"}}}, "normal_bladder_habits": {"type": "object", "properties": {"present": {"type": "string", "description": "''Yes'' if bladder habits are NORMAL, ''No'' if abnormal urinary symptoms reported"}, "duration": {"type": "string"}, "description": {"type": "string"}}}, "pain_over_surgical_site": {"type": "object", "properties": {"present": {"type": "string", "description": "''Yes'' if patient reports this symptom, otherwise ''No''"}, "duration": {"type": "string", "description": "Duration if stated (e.g. ''3 days'', ''2 weeks''); empty if not present or unknown"}, "description": {"type": "string", "description": "Free-text severity/character/notes if mentioned; empty otherwise"}}}}}', 'core', false, 999, 'system', 'balanced', 'medical_terms', NULL, true, '2026-04-13 12:05:35.18138+00', '2026-04-20 11:19:45.569343+00', 'active', NULL, NULL, NULL, false, NULL, false, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.segment_definitions VALUES ('9d639504-6899-455d-b5d5-8e76f6ca01c5', 'TREATMENT_PLAN', 'Treatment Plan (KG Cardio)', '**TREATMENT_PLAN:** Extract treatment plan, referrals, and follow-up date.

 **treatment_and_future_plan**: Narrative combining treatment, lifestyle advice, monitoring instructions, and contingency/warning signs. Example:
 "Continue current antihypertensives. Low-salt diet. Monitor BP twice daily. Watch for worsening dyspnea or chest pain. Drugs as per prescription."

 **consultants_referral**: If the doctor referred to another specialist, capture it explicitly. Example:
 "Refer to Nephrologist for CKD workup" or "Cardiologist opinion for valve assessment"
 "" (empty) if no referral made.

 **review_on**: Next follow-up date — ALWAYS in DD-MM-YYYY format.
 - If the doctor states an explicit date ("come on 15th April 2026"), use that → "15-04-2026"
 - If the doctor uses a RELATIVE phrase ("in 2 weeks", "after 1 month", "come back in 3 months",
   "review next week"), COMPUTE the absolute date from TODAY''S DATE (provided at the top of
   this prompt) and output as DD-MM-YYYY. Examples:
     * Today is 05-05-2026, doctor says "in 3 months" → "05-08-2026"
     * Today is 05-05-2026, doctor says "after 2 weeks" → "19-05-2026"
     * Today is 05-05-2026, doctor says "next month" → "05-06-2026"
 - If the doctor says "SOS" / "as needed" / "only if symptoms recur" with no time anchor,
   output "SOS" (this is the only non-date value allowed).
 - "" if no follow-up mentioned at all.
 - ❌ Do NOT output relative phrases like "in 3 months", "after 1 month", "in 2 weeks" —
   always resolve them to an absolute DD-MM-YYYY date using TODAY''S DATE.

 **Rules:**
 - treatment_and_future_plan is a single narrative string (no bullets).
 - If prescription present, append ". Drugs as per prescription." at the end.', '{"type": "object", "properties": {"review_on": {"type": "string", "description": "Next review date in DD-MM-YYYY format (always — compute from today if relative phrase used). Use \"SOS\" only when no time anchor is given. Empty if not mentioned."}, "consultants_referral": {"type": "string", "description": "Explicit referrals to other specialists, if any"}, "treatment_and_future_plan": {"type": "string", "description": "Narrative treatment plan including lifestyle, monitoring, and instructions"}}}', 'core', false, 999, NULL, 'balanced', 'medical_terms', NULL, true, '2026-04-06 01:07:46.99634+00', '2026-05-06 04:00:53.82633+00', 'active', NULL, NULL, NULL, false, NULL, false, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.segment_definitions VALUES ('48e61f61-0f48-48df-9137-8be243fcd467', 'EXAMINATION_RECTUM', 'Examination specific to Rectum Radiology', 'Extract rectum-specific examination findings and any rectum-specific
workup details from the encounter.

Fields:
- digital_rectal_exam: DRE findings — distance from anal verge, mass
  size and circumferential extent, mobility/fixity, sphincter tone,
  blood on glove, etc., as the doctor stated.
- inguinal_lymph_node_exam: e.g., "No palpable inguinal
  lymphadenopathy bilaterally.", or specific findings.
- lower_limb_edema: e.g., "No lower limb edema.", or stated finding.
- distance_from_anal_verge_cm: numeric string in cm if explicitly
  stated (e.g., "5"). Else "".
- circumferential_extent: e.g., "1/3 circumference",
  "annular/circumferential", or "" if not stated.
- mesorectal_fascia_status: stated involvement or proximity if
  mentioned (e.g., "Threatens mesorectal fascia anteriorly"). Else "".
- additional_site_notes: anything else specific to the rectal disease
  or planning the doctor mentioned (e.g., colostomy status, sphincter
  preservation goals).

Rules:
- ✅ Capture findings only as stated.
- ❌ Do NOT include findings already covered by COMMON_EXAM (neck,
  abdomen, spine).
- ❌ Use "" for fields not stated.

**Conjoined-narrative split example (Script 5.1 — BUG-005):**
"Examined him with consent. ECOG one, conscious cooperative, no acute
 distress. Neck clear. Abdomen soft, no organomegaly, non-tender.
 Lower limbs no edema, spine non-tender, no inguinal nodes. DRE — firm
 fungating partially circumferential mass starting six cm from anal
 verge, mobile on the underlying mesorectum, smear of blood on the
 examining finger."
   → digital_rectal_exam: "Firm fungating partially circumferential mass starting 6 cm from anal verge; mobile on underlying mesorectum; blood smear on examining finger"
   → inguinal_lymph_node_exam: "No palpable inguinal lymph nodes"
   → lower_limb_edema: "No lower limb edema"
   → distance_from_anal_verge_cm: "6"
   → circumferential_extent: "Partial / non-circumferential"
   → mesorectal_fascia_status: ""  (MRF status comes from imaging, not exam)
   → (ECOG, neck, abdomen, spine items belong to COMMON_EXAM)', '{"lower_limb_edema": "string", "digital_rectal_exam": "string", "additional_site_notes": "string", "circumferential_extent": "string", "inguinal_lymph_node_exam": "string", "mesorectal_fascia_status": "string", "distance_from_anal_verge_cm": "string"}', 'core', false, 14, 'system', 'balanced', 'medical_terms', NULL, true, '2026-04-27 01:53:17.291979+00', '2026-04-30 07:15:32.52397+00', 'active', NULL, NULL, NULL, false, NULL, false, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.segment_definitions VALUES ('0d5e6c83-a6ca-4f4d-b7aa-e77e347cc6c6', 'PRESCRIPTION', 'Prescription (KG Cardio)', 'Extract each medication that the doctor prescribes or modifies in THIS visit.
Do NOT fabricate medications. Do NOT include placeholder names.

WHAT TO INCLUDE — only medications where AT LEAST ONE of these is true:
  (a) The doctor explicitly prescribes a NEW drug ("I''ll start...", "I''ll add...", "Add...")
  (b) The doctor explicitly continues an existing drug AND names it ("Continue metformin", "Same Acitrom but reduce to 3.5mg")
  (c) The doctor changes dose / stops / replaces a named drug
  (d) The doctor says "continue all", "continue current medicines", "same medicines",
      "continue everything" or equivalent generic continue instruction. In this case,
      list EVERY medicine the patient is currently on (from current_medications / history)
      individually with full details — name, dose, duration, intake. Do NOT output
      "continue current medicines" as a single placeholder entry — expand to actual drug names.

WHAT TO EXCLUDE — leave these OUT entirely:
  ❌ Medications the patient mentions taking on their own (e.g. "she''s on tablets for dizziness")
     unless the doctor explicitly continues/modifies them in this visit (rule b/c) OR issues
     a generic continue instruction (rule d). These belong in HISTORY otherwise,
     not the prescription segment.
  ❌ Vague placeholders. If the doctor says "I''ll prescribe tablets for three months" without
     naming a drug, output an EMPTY array []. Do NOT invent a name like "Tablets for pain
     management" or "Pain medication". The doctor will write the actual prescription on paper.
  ❌ Categorical references with no specific drug ("some pain meds", "BP tablets", "diabetes tablets",
     "antibiotics") — same rule, leave the array empty unless a specific drug is named.

FIELD RULES
- name: Full name with strength, e.g., "Metformin 500mg", "Telmisartan 40mg"
- dose: M-A-E-N format (1-0-0-1). OD morning=1-0-0-0, BD=1-0-0-1, TDS=1-1-1-0, SOS=SOS, "" if not mentioned
- duration: Numeric value only as string, "" if not mentioned. e.g., "5", "14", "3"
- duration_unit: One of "Day" | "Week" | "Month". "" if not mentioned
- intake: One of "Before Food" | "After Food" | "Empty Stomach" | "Anytime". "" if not mentioned
- route: One of "Oral" | "Intravenous" | "Intramuscular" | "Subcutaneous" | "Topical" | "Inhalation" | "Sublingual". "" if not mentioned.
- intake_period: One of "Regular" | "SOS" | "STAT" | "PRN" | "Alternate Days". "" if not stated; "Regular" for normal daily dosing.
- instructions: Any special remarks, e.g., "Titrate dose", "Monitor BP". "" if none.

If the doctor did not explicitly state a value for a field, leave that field as "". Never infer
or default a value. Only `name` is mandatory; capture the medication even if every other field is blank.

If no medication meets the inclusion rules above, return [] (empty array).', '{"type": "array", "items": {"type": "object", "properties": {"dose": {"type": "string", "description": "M-A-E-N format e.g. 1-0-0-1"}, "name": {"type": "string", "description": "Drug name with strength, e.g., ''Metformin 500mg''"}, "route": {"type": "string", "description": "Oral | Intravenous | Intramuscular | Subcutaneous | Topical | Inhalation | Sublingual"}, "intake": {"type": "string", "description": "Before Food | After Food | Empty Stomach | Anytime"}, "duration": {"type": "string", "description": "Numeric duration value, e.g., ''5''"}, "instructions": {"type": "string", "description": "Special instructions or remarks"}, "duration_unit": {"type": "string", "description": "Day | Week | Month"}, "intake_period": {"type": "string", "description": "Regular | SOS | STAT | PRN | Alternate Days"}}}}', 'core', false, 4, 'system', 'balanced', 'medical_terms', NULL, true, '2026-02-16 07:52:34.478674+00', '2026-05-06 03:20:29.736549+00', 'active', NULL, NULL, NULL, false, NULL, false, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.segment_definitions VALUES ('93a79f0a-20bf-40ac-830f-952dcdc1efd1', 'TREATMENT_PLAN', 'Treatment Plan (KG Reassess)', 'Capture the treatment plan and follow-up:
(1) advice — general patient guidance (lifestyle, diet, warning signs, monitoring);
(2) treatment_and_future_plan — narrative plan including any procedures planned;
(3) consultants_referral — name/specialty of any outgoing referral to another specialist;
(4) review_on — next follow-up date, ALWAYS in DD-MM-YYYY format.

**review_on rules:**
 - If the doctor states an explicit date ("come on 15th April 2026"), use that → "15-04-2026"
 - If the doctor uses a RELATIVE phrase ("in 2 weeks", "after 1 month", "come back in 3 months",
   "review next week", "see you in 6 weeks"), COMPUTE the absolute date from TODAY''S DATE
   (provided at the top of this prompt) and output as DD-MM-YYYY. Examples:
     * Today is 05-05-2026, doctor says "in 3 months" → "05-08-2026"
     * Today is 05-05-2026, doctor says "after 2 weeks" → "19-05-2026"
     * Today is 05-05-2026, doctor says "next month" → "05-06-2026"
 - If the doctor says "SOS" / "as needed" / "only if symptoms recur" with no time anchor,
   output "SOS" (this is the only non-date value allowed).
 - "" if no follow-up mentioned at all.
 - ❌ Do NOT output relative phrases like "in 3 months", "after 1 month", "in 2 weeks" —
   always resolve them to an absolute DD-MM-YYYY date using TODAY''S DATE.

Use empty strings for any of (1)-(3) not mentioned.', '{"type": "object", "properties": {"advice": {"type": "string", "description": "General advice given to the patient (lifestyle, diet, warning signs, when to return). Distinct from the prescription drug list. Empty if none."}, "review_on": {"type": "string", "description": "Next review date in DD-MM-YYYY format (always — compute from today if relative phrase used). Use \"SOS\" only when no time anchor is given. Empty if not stated."}, "consultants_referral": {"type": "string", "description": "Outgoing referrals to other specialists (name and/or specialty), if any. Empty if no referral made."}, "treatment_and_future_plan": {"type": "string", "description": "Narrative treatment plan including any procedures planned and follow-up management. Empty if none."}}}', 'core', false, 999, 'system', 'balanced', 'medical_terms', NULL, true, '2026-04-13 12:05:35.18138+00', '2026-05-06 04:01:11.389612+00', 'active', NULL, NULL, NULL, false, NULL, false, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.segment_definitions VALUES ('f43a10b8-aa03-4b51-bbe2-4b626fa17ae2', 'COMORBIDITIES', 'Comorbidities', '**COMORBIDITIES:** Classify the patient''s medical conditions and habits into the 12 fixed checkboxes below.

 **Rules:**
 - Set `status` to "Yes" ONLY when the condition is explicitly affirmed by the patient or doctor.
 - Set `status` to "" (empty string) for all unmentioned conditions.
 - Set `status` to "No" for conditions that are explicitly DENIED ("denies diabetes", "no history of stroke", "non-smoker").
 - Never flip to "Yes" based on negated phrases.
 - For fields with `since`, capture duration exactly as mentioned (e.g., "10 years", "6 months", "2 yr"). Leave "" if no duration mentioned.

 **Conditions with duration (status + since):**
 - dm: diabetes, DM, T1DM, T2DM, IDDM, NIDDM, diabetic
 - ht: hypertension, HTN, high blood pressure, elevated BP
 - dlp: dyslipidemia, hyperlipidemia, high cholesterol, hypercholesterolemia
 - history_of_copd: COPD, chronic obstructive pulmonary disease, emphysema, chronic bronchitis

 **Conditions (status only):**
 - previous_mi: heart attack, MI, myocardial infarction, STEMI, NSTEMI, ACS, acute coronary syndrome
 - previous_stent: stent, PCI, angioplasty, PTCA, coronary stent placement
 - renal_failure: renal failure, CKD, CRF, ESRD, chronic kidney disease, dialysis
 - history_of_cva: stroke, CVA, cerebrovascular accident, TIA, transient ischemic attack
 - peripheral_vascular_disease: PVD, PVOD, PAD, claudication, peripheral arterial disease

 **Habits (status only):**
 - smoking: smoking, cigarette, bidi, smoker, tobacco smoke (set "No" if former smoker who has quit)
 - tobacco_chewing: tobacco chewing, gutka, pan masala, betel quid, smokeless tobacco
 - alcohol_intake: alcohol, drinking, liquor, beer, wine, spirits, drinks

 **Output example:**
 {
   "dm": {"status": "Yes", "since": "10 years"},
   "ht": {"status": "Yes", "since": "5 years"},
   "dlp": {"status": "No", "since": ""},
   "history_of_copd": {"status": "No", "since": ""},
   "previous_mi": {"status": "No"},
   "previous_stent": {"status": "No"},
   "renal_failure": {"status": "No"},
   "history_of_cva": {"status": "No"},
   "peripheral_vascular_disease": {"status": "No"},
   "smoking": {"status": "Yes"},
   "tobacco_chewing": {"status": "No"},
   "alcohol_intake": {"status": "No"}
 }', '{"type": "object", "properties": {"dm": {"type": "object", "properties": {"since": {"type": "string"}, "status": {"type": "string"}}}, "ht": {"type": "object", "properties": {"since": {"type": "string"}, "status": {"type": "string"}}}, "dlp": {"type": "object", "properties": {"since": {"type": "string"}, "status": {"type": "string"}}}, "smoking": {"type": "object", "properties": {"status": {"type": "string"}}}, "previous_mi": {"type": "object", "properties": {"status": {"type": "string"}}}, "renal_failure": {"type": "object", "properties": {"status": {"type": "string"}}}, "alcohol_intake": {"type": "object", "properties": {"status": {"type": "string"}}}, "history_of_cva": {"type": "object", "properties": {"status": {"type": "string"}}}, "previous_stent": {"type": "object", "properties": {"status": {"type": "string"}}}, "history_of_copd": {"type": "object", "properties": {"since": {"type": "string"}, "status": {"type": "string"}}}, "tobacco_chewing": {"type": "object", "properties": {"status": {"type": "string"}}}, "peripheral_vascular_disease": {"type": "object", "properties": {"status": {"type": "string"}}}}}', 'core', false, 999, NULL, 'balanced', 'medical_terms', NULL, true, '2026-04-06 00:07:12.538215+00', '2026-04-06 05:20:28.322142+00', 'active', NULL, NULL, NULL, false, NULL, false, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.segment_definitions VALUES ('12e697d9-5b46-400f-b980-c151a5c0168b', 'VITALS', 'Vitals (KG Reassess)', 'Extract ONLY the four reassessment vitals: weight (kg), SpO2 (%), pulse (bpm), and blood pressure (SBP/DBP). Output each field as a string value (no units). Leave unmeasured vitals as "".

 Fields:
 - weight: Weight in kg, e.g., "55"
 - pulse: Pulse rate in beats per minute, e.g., "78"
 - blood_pressure: Format as "SBP/DBP", e.g., "120/80". If only one value is mentioned, output that single number.
 - spo2: Oxygen saturation percentage, e.g., "98"

   - ❌ DO NOT extract height, BMI, temperature, respiratory rate, head circumference, or ANY vital not in the list above — ignore them completely even if the doctor mentions
  them.                                                                                                                                                                            
   - ❌ DO NOT place a stray number in any field just because it is the only number heard. A number without its vital name → ignore.            
   - ✅ Leave any unmeasured vital as "" (empty string).                                                                                                                           
   - ✅ Output values as strings WITHOUT units (no "kg", "cm", "bpm", "%").                                                                                                        
   - ✅ Do NOT negate measurements — "normal BP" or "unremarkable" ≠ extract.   ', '{"type": "object", "properties": {"spo2": {"type": "string", "description": "SpO2 percentage, e.g. ''98''. Empty string if not measured."}, "pulse": {"type": "string", "description": "Pulse rate in bpm, e.g. ''78''. Empty string if not measured."}, "weight": {"type": "string", "description": "Weight in kg, e.g. ''72''. Empty string if not measured."}, "blood_pressure": {"type": "string", "description": "Blood pressure as ''SBP/DBP'', e.g. ''120/80''. Empty string if not measured."}}}', 'core', false, 999, 'system', 'balanced', 'medical_terms', NULL, true, '2026-04-13 12:05:35.18138+00', '2026-04-20 11:10:11.57773+00', 'active', NULL, NULL, NULL, false, NULL, false, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.segment_definitions VALUES ('bdf92739-637c-40af-afb1-dc6d0fc35264', 'BLOOD_GROUP', 'Blood Group', '**BLOOD_GROUP:** Capture blood group and transfusion history.
                                                                 
  **Rules:**                                                                                                                                                                       
  - `blood_group`: one of "A", "B", "AB", "O" or "" if not mentioned.
  - `rh`: "Positive", "Negative" or "" if not mentioned.                                                                                                                           
  - `transfusion_history.received`: "Yes" / "No" / "" (explicit denial → "No").                                                                                                    
  - `transfusion_history.details`: free text with date/units/reason if given; "" otherwise.', '{"type": "object", "properties": {"rh": {"enum": ["", "Positive", "Negative"], "type": "string"}, "blood_group": {"enum": ["", "A", "B", "AB", "O"], "type": "string"}, "transfusion_history": {"type": "object", "properties": {"details": {"type": "string"}, "received": {"enum": ["", "Yes", "No"], "type": "string"}}}}}', 'core', false, 999, NULL, 'balanced', 'medical_terms', NULL, true, '2026-04-22 08:02:31.345027+00', '2026-04-22 08:02:31.345027+00', 'active', NULL, NULL, NULL, false, NULL, false, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.segment_definitions VALUES ('77281306-7a53-4034-a217-0a42335238f8', 'AUDIO_OTHER_EMOTIONS', 'Other Emotions (Voice)', '### Other Emotions Voice Detection (Audio-Only)

Detect medically relevant emotions beyond anxiety through voice prosody.

## Emotion Categories (use exactly):

| Emotion | Voice Indicators |
|---------|------------------|
| **Fear** | Voice tremor, higher pitch, rushed speech, breath catching |
| **Anger** | Increased volume, faster pace, clipped responses, tension |
| **Sadness** | Flat affect, slower pace, soft/quiet voice, sighing, monotone |
| **Relief** | Audible exhale, voice softening, pace normalization, lighter tone |
| **Distress** | Voice cracking, irregular breathing, pitch instability, crying sounds |
| **Hope** | Voice brightening, increased energy, upward inflection |
| **Frustration** | Sighing, exasperated tone, clipped words, tension |
| **Resignation** | Flat, defeated tone, low energy, trailing off |
| **None** | Neutral prosody throughout, no dominant emotion |

## For Each Emotion Detected:
- Identify the specific emotion
- Assess severity: Mild, Moderate, or Severe
- Note voice evidence (specific indicators heard)
- Rate clinical significance: High, Medium, or Low

## Clinical Significance Guide:
- **High**: Emotion likely to impact treatment decisions or adherence
- **Medium**: Notable but manageable, worth documenting
- **Low**: Minor, unlikely to affect care

## CRITICAL: Flag any voice indicators of suicidal ideation or severe distress

## Emotional Trajectory:
Compare voice at start vs end:
- **Improved**: Emotional state improved (e.g., fear -> relief)
- **Stable**: Emotional state remained similar
- **Worsened**: Emotional state deteriorated

## Required Output:
- emotions_detected: Array of emotion objects with emotion/severity/voice_evidence/clinical_significance
- dominant_emotion: Most prominent emotion from voice
- emotional_trajectory: Improved/Stable/Worsened
- critical_flags: Array of any critical concerns (suicidal ideation, severe distress)
- rationale: Explanation of voice evidence
- confidence: Low/Medium/High', '{"type": "object", "required": ["emotions_detected", "dominant_emotion", "emotional_trajectory", "confidence"], "properties": {"rationale": {"type": "string", "description": "Explanation of voice evidence"}, "confidence": {"enum": ["Low", "Medium", "High"], "type": "string", "description": "Confidence in assessment"}, "critical_flags": {"type": "array", "items": {"type": "string"}, "description": "Critical concerns like suicidal ideation or severe distress"}, "dominant_emotion": {"enum": ["Fear", "Anger", "Sadness", "Relief", "Distress", "Hope", "Frustration", "Resignation", "None"], "type": "string", "description": "Most prominent emotion from voice"}, "emotions_detected": {"type": "array", "items": {"type": "object", "required": ["emotion", "severity", "clinical_significance"], "properties": {"emotion": {"enum": ["Fear", "Anger", "Sadness", "Relief", "Distress", "Hope", "Frustration", "Resignation", "None"], "type": "string", "description": "The detected emotion"}, "severity": {"enum": ["Mild", "Moderate", "Severe"], "type": "string", "description": "Severity of the emotion"}, "voice_evidence": {"type": "string", "description": "Specific voice indicators (e.g., flat affect, sighing, voice tremor)"}, "clinical_significance": {"enum": ["High", "Medium", "Low"], "type": "string", "description": "Clinical significance of this emotion"}}}, "description": "All emotions detected from voice"}, "emotional_trajectory": {"enum": ["Improved", "Stable", "Worsened"], "type": "string", "description": "How emotions changed from start to end"}}}', 'additional', false, 1015, 'system', 'balanced', 'medical_terms', 'Voice-based emotion detection', true, '2025-12-16 01:23:58.849054+00', '2026-01-13 14:27:34.020171+00', 'active', NULL, NULL, NULL, false, NULL, false, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.segment_definitions VALUES ('661d28e1-0b94-414f-bdec-fb2795a334e3', 'PSG_MORBIDITY_ASSESSMENT', 'PSG Morbidity Assessment', '**PSG_MORBIDITY_ASSESSMENT:**
Extract morbidity/complication assessment during hospital stay.

**Required Fields:**
- complication_type: "Surgery Related" / "Non-Surgery Related" / "No"
- details: Complication details (if any)
- duration_exceeded: "Yes" / "No" - Was hospital stay longer than expected?
- icu_inscu_postop_days: Number of days in ICU/INSCU/Post-OP/CO
- ward_days: Number of days in ward
- reason_prolonged_stay: Reason if stay was prolonged

***Example:***
```json
{
  "complication_type": "No",
  "details": "",
  "duration_exceeded": "No",
  "icu_inscu_postop_days": "1",
  "ward_days": "3",
  "reason_prolonged_stay": ""
}
```

**Extraction Rules:**
- If no complications, set complication_type to "No"
- Calculate days from admission/discharge dates if mentioned', '{"type": "object", "required": ["complication_type", "details", "duration_exceeded", "icu_inscu_postop_days", "ward_days", "reason_prolonged_stay"], "properties": {"details": {"type": "string", "description": "Complication details"}, "ward_days": {"type": "string", "description": "Days in ward"}, "complication_type": {"type": "string", "description": "Surgery Related / Non-Surgery Related / No"}, "duration_exceeded": {"type": "string", "description": "Yes / No"}, "icu_inscu_postop_days": {"type": "string", "description": "Days in ICU/INSCU/Post-OP/CO"}, "reason_prolonged_stay": {"type": "string", "description": "Reason for prolonged stay"}}}', 'core', false, 1025, 'system', 'balanced', 'medical_terms', 'Morbidity assessment for PSG discharge', true, '2026-01-26 03:02:43.650206+00', '2026-01-26 03:02:43.650206+00', 'active', NULL, NULL, NULL, false, NULL, false, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.segment_definitions VALUES ('8f684ffd-825c-47c6-8fce-5842453c734a', 'GENERAL_EXAMINATION', 'General Examination (KG Reassess)', 'Extract the 8 general examination findings. For each, set "Yes" if the doctor explicitly states the finding is present (or intact for peripheral_pulses_intact). If explicitly stated as No, then set as "No". Default to "No" for any finding not explicitly mentioned.', '{"type": "object", "properties": {"pallor": {"type": "string", "description": "''Yes'' if pallor is present on examination, otherwise ''No''"}, "icterus": {"type": "string", "description": "''Yes'' if icterus/jaundice is present, otherwise ''No''"}, "clubbing": {"type": "string", "description": "''Yes'' if clubbing is present, otherwise ''No''"}, "cyanosis": {"type": "string", "description": "''Yes'' if cyanosis is present, otherwise ''No''"}, "jvp_raised": {"type": "string", "description": "''Yes'' if JVP is raised/elevated, otherwise ''No''"}, "pedal_edema": {"type": "string", "description": "''Yes'' if pedal edema is present on examination, otherwise ''No''"}, "varicose_veins": {"type": "string", "description": "''Yes'' if varicose veins are present, otherwise ''No''"}, "peripheral_pulses_intact": {"type": "string", "description": "''Yes'' if peripheral pulses are intact/normal, otherwise ''No''"}}}', 'core', false, 999, 'system', 'balanced', 'medical_terms', NULL, true, '2026-04-13 12:05:35.18138+00', '2026-04-20 11:12:06.361342+00', 'active', NULL, NULL, NULL, false, NULL, false, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.segment_definitions VALUES ('7afa67a6-fb21-40b9-b6d9-25e484fbb12c', 'COMBINED_OTHER_EMOTIONS', 'Combined Other Emotions Detection', '### Combined Other Emotions Detection

Identify medically relevant emotions beyond anxiety from BOTH transcript and voice.

## Emotion Categories (use these exact names):

| Emotion | TEXT Indicators | AUDIO Indicators |
|---------|-----------------|------------------|
| **Fear** | Phobia mentions, death/disability fears | Voice tremor, higher pitch, rushed speech |
| **Anger** | Frustration language, complaints | Increased volume, faster pace, clipped responses |
| **Sadness** | Hopelessness, withdrawal language | Flat affect, slower pace, soft voice, sighing |
| **Relief** | Gratitude, "thank goodness" | Audible exhale, voice softening, pace normalization |
| **Distress** | "I can''t cope", overwhelmed | Voice cracking, irregular breathing, pitch instability |
| **Hope** | Optimistic statements | Voice brightening, increased energy |
| **None** | Neutral content | Neutral prosody throughout |

## For Each Emotion Found:
- Identify the specific emotion
- Assess text evidence (what was said)
- Assess audio evidence (how it sounded)
- Rate severity: Mild, Moderate, or Severe
- Determine clinical significance: High, Medium, or Low

## Mismatch Detection:
Report if text and audio emotions conflict.
Example: Patient uses positive words but voice shows sadness.

## CRITICAL: Flag suicidal ideation as CRITICAL if present (from text or audio)

## Required Output:
- emotions_detected: Array with emotion/severity/text_evidence/audio_evidence/clinical_significance
- dominant_emotion: Most prominent emotion (text + audio combined)
- text_emotions: Array of emotions detected from text alone
- audio_dominant: Dominant emotion from audio alone
- emotional_trajectory: How emotions changed (Improved/Stable/Worsened)
- mismatch: Boolean if text/audio emotions conflict
- rationale: Explanation of combined assessment
- confidence: Low/Medium/High
- notes: Additional observations', '{"type": "object", "required": ["emotions_detected", "dominant_emotion", "mismatch", "confidence"], "properties": {"notes": {"type": "string"}, "mismatch": {"type": "boolean", "description": "True if text and audio emotions conflict"}, "rationale": {"type": "string"}, "confidence": {"enum": ["Low", "Medium", "High"], "type": "string"}, "text_emotions": {"type": "array", "items": {"type": "string"}, "description": "Emotions from text alone"}, "audio_dominant": {"type": "string", "description": "Dominant emotion from audio alone"}, "combined_score": {"type": "number", "maximum": 1, "minimum": 0}, "dominant_emotion": {"enum": ["Fear", "Anger", "Sadness", "Relief", "Distress", "Hope", "None"], "type": "string", "description": "Combined dominant emotion"}, "emotions_detected": {"type": "array", "items": {"type": "object", "required": ["emotion", "severity", "clinical_significance"], "properties": {"emotion": {"enum": ["Fear", "Anger", "Sadness", "Relief", "Distress", "Hope", "None"], "type": "string"}, "severity": {"enum": ["Mild", "Moderate", "Severe"], "type": "string"}, "text_evidence": {"type": "array", "items": {"type": "string"}, "description": "Evidence from transcript"}, "audio_evidence": {"type": "string", "description": "Evidence from voice"}, "clinical_significance": {"enum": ["High", "Medium", "Low"], "type": "string"}}}}, "emotional_trajectory": {"enum": ["Improved", "Stable", "Worsened"], "type": "string"}}}', 'additional', false, 1003, NULL, 'balanced', 'medical_terms', 'Combined multimodal detection of medically relevant emotions', true, '2026-01-13 14:27:32.409299+00', '2026-01-13 14:27:32.409299+00', 'active', NULL, NULL, NULL, false, NULL, false, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.segment_definitions VALUES ('d5e16ace-6cb0-4e13-9d4f-ed8a3c70293d', 'COMORBIDITIES_NEPHRO', 'Comorbidities Nephrology', '**COMORBIDITIES:** Classify the patient''s medical conditions and habits into the 16 fixed checkboxes below.

 **Rules:**
 - Set `status` to "Yes" ONLY when the condition is explicitly affirmed by the patient or doctor.
 - Set `status` to "" (empty string) for all unmentioned conditions.
 - Set `status` to "No" for conditions that are explicitly DENIED ("no hematuria", "denies fever", "non-smoker").
 - Never flip to "Yes" based on negated phrases.
 - For fields with `since`, capture duration exactly as mentioned (e.g., "10 years", "6 months", "2 yr"). Leave "" if no duration mentioned.

**Conditions / symptoms with duration (status + since):**                                                                                                                        
  - dm: diabetes, DM, T1DM, T2DM, IDDM, NIDDM, diabetic                                                                                                                            
  - bp: BP, hypertension, HTN, high blood pressure, elevated BP                                                                                                                    
  - hematuria: hematuria, blood in urine, red-coloured urine                                                                                                                       
  - stones: kidney stones, renal stones, ureteric stones, calculus, lithiasis                                                                                                      
  - frequency: urinary frequency, frequent urination, increased urination                                                                                                          
  - nocturia: nocturia, waking at night to urinate, nighttime urination                                                                                                            
  - straining: straining to urinate, poor urinary stream, difficulty passing urine                                                                                                 
  - dyspnoea: dyspnoea, shortness of breath, SOB, breathlessness                                                                                                                   
  - edema: edema, swelling, pedal edema, leg swelling, facial puffiness                                                                                                            
  - cough: cough                                                                                                                                                                   
  - fever: fever, pyrexia, elevated temperature                                                                                                                                    
  - skin_rash: skin rash, rash, eruption, dermatitis                                                                                                                               
  - pruritus: pruritus, itching, itchy skin              
  - nausea: nausea, feeling sick, queasy                                                                                                                                           
  - vomiting: vomiting, throwing up, emesis    

 **Habits (status only):**
 - smoking: smoking, cigarette, bidi, smoker, tobacco smoke (set "No" if former smoker who has quit)

 **Output example:**                                    
  {                                                                                                                                                                                
    "dm": {"status": "Yes", "since": "5 years"},                                                                                                                                   
    "bp": {"status": "Yes", "since": "3 years"},
    "smoking": {"status": "No"},                                                                                                                                                   
    "hematuria": {"status": "Yes", "since": "2 weeks"},  
    "stones": {"status": "No", "since": ""},                                                                                                                                       
    "frequency": {"status": "Yes", "since": "1 month"},                                                                                                                            
    "nocturia": {"status": "Yes", "since": "1 month"},
    "straining": {"status": "", "since": ""},                                                                                                                                      
    "dyspnoea": {"status": "No", "since": ""},           
    "edema": {"status": "Yes", "since": "2 weeks"},                                                                                                                                
    "cough": {"status": "", "since": ""},                
    "fever": {"status": "", "since": ""},                                                                                                                                          
    "skin_rash": {"status": "No", "since": ""},          
    "pruritus": {"status": "No", "since": ""},                                                                                                                                     
    "nausea": {"status": "No", "since": ""},                                                                                                                                       
    "vomiting": {"status": "No", "since": ""}
  }', '{"type": "object", "properties": {"bp": {"type": "object", "properties": {"since": {"type": "string"}, "status": {"type": "string"}}}, "dm": {"type": "object", "properties": {"since": {"type": "string"}, "status": {"type": "string"}}}, "cough": {"type": "object", "properties": {"since": {"type": "string"}, "status": {"type": "string"}}}, "edema": {"type": "object", "properties": {"since": {"type": "string"}, "status": {"type": "string"}}}, "fever": {"type": "object", "properties": {"since": {"type": "string"}, "status": {"type": "string"}}}, "nausea": {"type": "object", "properties": {"since": {"type": "string"}, "status": {"type": "string"}}}, "stones": {"type": "object", "properties": {"since": {"type": "string"}, "status": {"type": "string"}}}, "smoking": {"type": "object", "properties": {"status": {"type": "string"}}}, "dyspnoea": {"type": "object", "properties": {"since": {"type": "string"}, "status": {"type": "string"}}}, "nocturia": {"type": "object", "properties": {"since": {"type": "string"}, "status": {"type": "string"}}}, "pruritus": {"type": "object", "properties": {"since": {"type": "string"}, "status": {"type": "string"}}}, "vomiting": {"type": "object", "properties": {"since": {"type": "string"}, "status": {"type": "string"}}}, "frequency": {"type": "object", "properties": {"since": {"type": "string"}, "status": {"type": "string"}}}, "hematuria": {"type": "object", "properties": {"since": {"type": "string"}, "status": {"type": "string"}}}, "skin_rash": {"type": "object", "properties": {"since": {"type": "string"}, "status": {"type": "string"}}}, "straining": {"type": "object", "properties": {"since": {"type": "string"}, "status": {"type": "string"}}}}}', 'core', false, 999, 'system', 'balanced', 'medical_terms', 'Cloned from COMORBIDITIES: None', true, '2026-04-22 08:03:21.668203+00', '2026-04-22 08:20:01.737732+00', 'active', NULL, NULL, 'COMORBIDITIES', true, '2026-04-22 08:03:21.668203+00', true, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.segment_definitions VALUES ('d63d7e9e-e6cf-44d6-9e45-5517dc0fc8d0', 'COMBINED_DOCTOR_STYLE', 'Combined Doctor Communication Style', '### Combined Doctor Communication Style Assessment

Analyze doctor''s communication from BOTH what they say AND how they sound.

## Style Categories (use these exact terms):

| Style | TEXT Indicators | AUDIO Indicators |
|-------|-----------------|------------------|
| **Empathetic** | Validating statements, "I understand" | Soft tone, voice matching patient distress, warm delivery |
| **Collaborative** | Asks for input, shared decisions | Questioning tone, pauses for patient, encouraging responses |
| **Clinical** | Professional, fact-based | Neutral tone, efficient pace, information-focused |
| **Authoritative** | Directive language, confident | Confident tone, clear instructions |
| **Rushed** | Abbreviated explanations, interrupts | Fast pace, talks over patient, incomplete sentences |
| **Dismissive** | Minimizes concerns, condescending | Sighs, condescending voice, talks over patient |
| **Detached** | Emotionally unavailable language | Cold/mechanical tone, no warmth in voice |
| **Evasive** | Vague answers, deflects | Hesitant answers, avoids direct responses |

## Voice Warmth Levels:
- Cold, Neutral, Warm, Very Warm

## Key Assessment Areas:
1. **Use of empathetic statements** vs dismissive responses
2. **Medical jargon level** and explanation quality
3. **Active listening signals** (reflecting back, summarizing) vs interrupting
4. **Reassurance timing and effectiveness**
5. **Response to patient concerns** and questions
6. **Time given for patient** to ask questions
7. **Tone consistency** throughout consultation

## Impact Assessment:
- How doctor''s style affected patient anxiety (Reduced/No effect/Increased)
- Clarity of treatment plan communication
- Trust-building effectiveness

## Mismatch Detection:
Report if verbal content contradicts voice tone.
Example: Uses empathetic words but sounds rushed/dismissive in tone.

## Required Output:
- primary_style: Dominant combined style
- secondary_style: Secondary style if applicable
- text_style: Style from words alone
- audio_style: Style from voice alone
- voice_warmth: Cold/Neutral/Warm/Very Warm
- tone_consistency: How consistent was the tone
- mismatch: Boolean if words and tone contradict
- empathy_indicators: Specific empathetic behaviors (text + audio)
- communication_strengths: Positive aspects
- areas_for_improvement: What could be better
- patient_anxiety_impact: Reduced/No effect/Increased
- clarity_rating: Excellent/Good/Fair/Poor
- rationale: Explanation of combined assessment
- confidence: Low/Medium/High', '{"type": "object", "required": ["primary_style", "voice_warmth", "mismatch", "patient_anxiety_impact", "confidence"], "properties": {"notes": {"type": "string"}, "mismatch": {"type": "boolean", "description": "True if words and tone contradict"}, "rationale": {"type": "string"}, "confidence": {"enum": ["Low", "Medium", "High"], "type": "string"}, "text_style": {"type": "string", "description": "Style from verbal content alone"}, "audio_style": {"type": "string", "description": "Style from voice tone alone"}, "voice_warmth": {"enum": ["Cold", "Neutral", "Warm", "Very Warm"], "type": "string"}, "primary_style": {"enum": ["Empathetic", "Collaborative", "Clinical", "Authoritative", "Rushed", "Dismissive", "Detached", "Evasive"], "type": "string"}, "clarity_rating": {"enum": ["Excellent", "Good", "Fair", "Poor"], "type": "string"}, "secondary_style": {"enum": ["Empathetic", "Collaborative", "Clinical", "Authoritative", "Rushed", "Dismissive", "Detached", "Evasive"], "type": "string"}, "tone_consistency": {"enum": ["Highly consistent", "Mostly consistent", "Variable", "Inconsistent"], "type": "string"}, "empathy_indicators": {"type": "array", "items": {"type": "string"}}, "areas_for_improvement": {"type": "array", "items": {"type": "string"}}, "patient_anxiety_impact": {"enum": ["Reduced", "No effect", "Increased"], "type": "string"}, "communication_strengths": {"type": "array", "items": {"type": "string"}}}}', 'additional', false, 1005, NULL, 'balanced', 'medical_terms', 'Combined multimodal doctor communication style assessment', true, '2026-01-13 14:27:32.409299+00', '2026-01-13 14:27:32.409299+00', 'active', NULL, NULL, NULL, false, NULL, false, NULL, NULL) ON CONFLICT DO NOTHING;
