INSERT INTO public.segment_definitions VALUES ('0e55730b-ed6b-4462-81d7-086bec90b400', 'COMBINED_CONGRUENCE_SUMMARY', 'Combined Congruence Summary', '### Congruence Analysis Summary

After analyzing all segments, provide a comprehensive summary of TEXT vs AUDIO congruence.

## Purpose of Congruence Analysis
Detect when what a patient SAYS differs from how they SOUND - this reveals hidden concerns, masked emotions, or unexpressed distress that impacts clinical care.

## Synthesize Findings From All Segments

Review mismatches detected in:
- COMBINED_ANXIETY: Did text and audio anxiety levels match?
- COMBINED_FINANCIAL_CONCERNS: Did expressed concerns match voice stress?
- COMBINED_OTHER_EMOTIONS: Did stated emotions match voice prosody?
- COMBINED_COMPLIANCE: Did verbal agreement match voice confidence?
- COMBINED_DOCTOR_STYLE: Did doctor''s words match their tone?

## Calculate Overall Congruence Score

Score from 0.0 to 1.0:
- **1.0**: Perfect alignment - text and audio agree on all segments
- **0.75-0.99**: High congruence - minor mismatches, clinically insignificant
- **0.50-0.74**: Moderate congruence - some notable mismatches
- **0.25-0.49**: Low congruence - significant mismatches, hidden concerns likely
- **0.0-0.24**: Very low congruence - major mismatches, patient masking significant distress

## Identify Incongruent Moments

For each significant mismatch, document:
- **Segment**: Which area showed the mismatch
- **Text finding**: What was expressed verbally
- **Audio finding**: What voice revealed
- **Timestamp reference**: When this occurred (if identifiable)
- **Clinical significance**: High/Medium/Low impact on care
- **Interpretation**: What the mismatch might mean clinically

Example:
```
"Patient said ''I feel much better now'' at consultation end,
but voice remained tremulous with elevated pitch.
This suggests patient may be minimizing ongoing distress
to avoid concerning the doctor or appearing weak."
```

## Generate Clinical Recommendations

Based on congruence findings, recommend specific actions:

**Critical (Score < 0.3):**
- Urgent mental health referral
- Direct follow-up from doctor
- Care coordinator involvement

**High Priority (Score 0.3-0.5):**
- Schedule early follow-up call
- Financial counseling if financial mismatch detected
- Treatment adherence support if compliance mismatch

**Medium Priority (Score 0.5-0.7):**
- Emotional support resources
- Patient feedback collection
- Family involvement consideration

**Low Priority (Score > 0.7):**
- Standard follow-up appropriate
- Telehealth option for convenience

## Required Output:
- overall_congruence_score: 0.0-1.0 numeric score
- congruence_level: Very Low/Low/Moderate/High/Very High
- total_mismatches: Count of segments with significant mismatches
- mismatch_summary: Brief text summary of key mismatches
- incongruent_moments: Array of detailed mismatch objects
- clinical_recommendations: Array of prioritized recommendations
- intervention_priority: CRITICAL/HIGH/MEDIUM/LOW/NONE
- key_findings: Most important congruence insights
- confidence: Low/Medium/High', '{"type": "object", "required": ["overall_congruence_score", "congruence_level", "total_mismatches", "intervention_priority", "confidence"], "properties": {"confidence": {"enum": ["Low", "Medium", "High"], "type": "string", "description": "Confidence in congruence analysis"}, "key_findings": {"type": "array", "items": {"type": "string"}, "description": "Most important congruence insights"}, "areas_of_concern": {"type": "array", "items": {"type": "string"}, "description": "Specific areas requiring attention"}, "congruence_level": {"enum": ["Very Low", "Low", "Moderate", "High", "Very High"], "type": "string", "description": "Categorical congruence level"}, "mismatch_summary": {"type": "string", "description": "Brief text summary of key mismatches found"}, "total_mismatches": {"type": "integer", "minimum": 0, "description": "Count of segments with significant text-audio mismatches"}, "incongruent_moments": {"type": "array", "items": {"type": "object", "required": ["segment", "text_finding", "audio_finding", "clinical_significance"], "properties": {"segment": {"type": "string", "description": "Which segment showed mismatch"}, "text_finding": {"type": "string", "description": "What was expressed verbally"}, "audio_finding": {"type": "string", "description": "What voice revealed"}, "interpretation": {"type": "string", "description": "Clinical meaning of this mismatch"}, "timestamp_reference": {"type": "string", "description": "When this occurred if identifiable"}, "clinical_significance": {"enum": ["High", "Medium", "Low"], "type": "string"}}}, "description": "Detailed list of incongruent moments"}, "intervention_priority": {"enum": ["CRITICAL", "HIGH", "MEDIUM", "LOW", "NONE"], "type": "string", "description": "Highest priority intervention level needed"}, "clinical_recommendations": {"type": "array", "items": {"type": "object", "required": ["recommendation", "priority", "reason"], "properties": {"reason": {"type": "string", "description": "Why this is recommended based on findings"}, "priority": {"enum": ["CRITICAL", "HIGH", "MEDIUM", "LOW"], "type": "string"}, "recommendation": {"type": "string", "description": "Specific recommended action"}, "source_mismatches": {"type": "array", "items": {"type": "string"}, "description": "Which mismatches triggered this"}}}, "description": "Prioritized clinical recommendations"}, "overall_congruence_score": {"type": "number", "maximum": 1, "minimum": 0, "description": "Overall text-audio congruence score from 0.0 to 1.0"}}}', 'additional', false, 1006, NULL, 'balanced', 'medical_terms', 'Comprehensive summary of text-audio congruence with clinical recommendations', true, '2026-01-13 14:27:32.409299+00', '2026-01-13 14:27:32.409299+00', 'active', NULL, NULL, NULL, false, NULL, false, NULL, NULL) ON CONFLICT DO NOTHING;
