INSERT INTO public.segment_definitions VALUES ('5ca07ed1-5694-43a5-94aa-404ba11f1613', 'VISIT_SUMMARY', 'PSG Visit Summary', '**VISIT_SUMMARY:**
Extract a concise summary of the entire visit.

**CRITICAL: NEVER include patient names or any identifying information. Use "the patient" instead of names.**

**Required Fields:**
- visit_summary: A brief summary of the visit including chief complaints, key findings, diagnosis, and plan

***Example:***
```json
{
  "visit_summary": "The patient, a 45-year-old male, presented with chest pain for 3 days. Known hypertensive on regular medication. Examination revealed stable vitals, mild pedal edema. Advised ECG and Echo. Continued on anti-hypertensives with addition of aspirin. Follow-up in 1 week."
}
```

**Extraction Rules:**
- Summarize the key points of the consultation
- Include demographics (age, gender only), chief complaints, relevant findings, and plan
- Keep it concise but comprehensive
- Do NOT include patient name, phone, address, MRN, or any identifying information', '{"type": "object", "properties": {"visit_summary": {"type": "string", "description": "Summary of the visit"}}}', 'additional', false, 12, 'system', 'balanced', 'medical_terms', 'Concise summary of the entire consultation visit', true, '2026-01-26 02:31:09.256757+00', '2026-02-26 15:00:27.023327+00', 'active', NULL, NULL, NULL, false, NULL, false, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.segment_definitions VALUES ('e8a31025-946d-4ffc-84ad-634a1d8d70c7', 'CLINICAL_NOTES', 'Clinical notes (KG Cardio)', '**CRITICAL: NEVER include patient names or any identifying information. Use "the patient" instead of names.**

Extract clinical notes from the consultation.

### Has Patient Improved
If this is a follow-up/reassessment visit, note whether the patient reports improvement since the last visit. Use the patient''s own words or the doctor''s assessment. Leave empty if not mentioned or if this is a first visit.
 - Include compliance context if discussed: missed follow-ups, stopped medications, didn''t follow diet/exercise plan, skipped investigations.
  - Example: "No improvement. Patient stopped Atorvastatin 2 weeks ago on own. Did not get Echo done as advised. Not following low-salt diet."
### Treatment
Numbered list of medications with name, strength, dosage, frequency, duration, and special instructions.

### Instructions
All non-medication instructions: lifestyle modifications, workplace precautions, warning signs.

### Follow-up
Specific date/timeframe, fasting requirements, what to bring.', '{"type": "object", "properties": {"follow_up": {"type": "string"}, "treatment": {"type": "string"}, "instructions": {"type": "string"}, "has_patient_improved": {"type": "string", "description": "Whether patient has improved since last visit"}}}', 'core', false, 5, 'system', 'balanced', 'medical_terms', NULL, false, '2026-02-16 07:52:34.478674+00', '2026-04-06 01:15:02.405127+00', 'active', NULL, NULL, NULL, false, NULL, false, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.segment_definitions VALUES ('1020beb4-7714-4c6e-9e41-2c49acf5ad7a', 'INVESTIGATIONS', 'Investigations', 'Extract ordered diagnostics tests and investigations with dates.
  **Type categorization:**
  - "Laboratory" — Blood tests, urine tests, cultures, biopsies (CBC, HbA1c, Lipid Profile, etc.)                                                                
  - "Imaging" — X-ray, CT, MRI, Ultrasound, etc.                                                                                                                 
  - "Other" — ECG, Echo, PFT, Endoscopy, and other investigations                                                                                                
                                                                                                                                                                 
  **Extraction Rules:**                                                                                                                                          
  - ✅ Extract each test as a separate object with name, type, and date              
  - ✅ INCLUDE only investigations the doctor explicitly orders or instructs to be done                                                                          
  - ✅ Use DD-MM-YYYY date format. Use "" if no date mentioned                                                                                                
  - ❌ Do NOT include past investigations already done — whether mentioned in the transcript ("your previous Echo showed...", "last time CBC was...") OR appearing in the PATIENT HISTORY / past summaries section that was injected earlier in this prompt. Those are historical context, not new orders. → these belong in HISTORY_OF_PRESENT_ILLNESS under the "Recent labs:" label, with the values verbatim.
  - ✅ DO include tests the doctor explicitly re-orders for this visit (e.g., "let''s repeat the CBC" → include CBC here, even if it appears in history).                                                  
- ❌ Do NOT include investigations mentioned with conditional/tentative language (e.g., "let''s see if we need", "we might need", "if symptoms don''t improve then we''ll do", "may require", "consider doing"). These conditional investigations belong ONLY in the Treatment Plan & Advice segment. Only include investigations that the doctor has definitively ordered or confirmed.
                                                                                                    
                                                                                                                                                                 
  **Example:**                                                                                                                                                   
  ```json                                                                            
  [                                                                                                                                                              
    {"name": "Complete Blood Count (CBC)", "type": "Laboratory", "date": "15-11-2024"},                                                                          
    {"name": "HbA1c", "type": "Laboratory", "date": ""},                                                                                                      
    {"name": "X-Ray Chest PA View", "type": "Imaging", "date": "14-11-2024"},                                                                                    
    {"name": "ECG", "type": "Other", "date": "15-11-2024"}                                                                                                       
  ]', '{"type": "array", "items": {"type": "object", "properties": {"date": {"type": "string", "description": "Test date in DD-MM-YYYY format"}, "name": {"type": "string", "description": "Full test/study name (e.g., ''Complete Blood Count'', ''X-Ray Chest PA View'', ''ECG'')"}, "type": {"type": "string", "description": "Category: Laboratory, Imaging, or Other"}}}}', 'core', false, 6, 'system', 'balanced', 'medical_terms', 'Cloned from INVESTIGATIONS_SIMPLE: Laboratory tests, imaging studies, and other diagnostic tests', true, '2025-11-25 05:24:42.045255+00', '2026-04-26 02:08:53.141114+00', 'active', NULL, NULL, 'INVESTIGATIONS_SIMPLE', true, '2025-11-25 05:24:42.045255+00', false, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.segment_definitions VALUES ('00318c8f-9454-478b-9ee6-39bbe5b6c403', 'CHIEF_COMPLAINTS', 'Chief Complaints', '**Description:** Ultra-brief symptom names in medical terminology. Include ALL symptoms (primary + associated) in priority order

**Extraction Rules:**
- ✅ Convert to medical terminology: "sleepless nights" → "Insomnia", "difficulty breathing" → "Dyspnea", "leaking urine" → "Stress urinary incontinence"
- ✅ Be ultra-brief, no elaboration
- ✅ Include duration with "for" notation (e.g. for 2 days)
- ✅ Include ALL symptoms mentioned by patient but in priority order. Primary complaint first followed by other symptoms. 
- ❌ Do NOT write narratives or repeat in other segments
- ❌ Do NOT include established diagnoses or disease names (e.g., ESRD, Diabetes, Hypertension, CAD). Only include what the patient is feeling/experiencing as symptoms.
- ❌ Do NOT restate the diagnosis as a chief complaint. If the doctor says "this patient has ESRD", that is a diagnosis, not a complaint. The complaint would be "Dyspnea" or "Bilateral pedal edema".

**Examples:**
["Headache, dizziness for 2 days post-medication discontinuation", "Fatigue, palpitations"]', '{"type": "array", "items": {"type": "string"}}', 'core', false, 2, 'system', 'concise', 'medical_terms', 'Cloned from CHIEF_COMPLAINTS: Primary presenting symptoms in medical terminology', true, '2025-11-28 07:04:03.006195+00', '2026-04-20 11:21:27.996587+00', 'active', NULL, NULL, 'CHIEF_COMPLAINTS', true, '2025-11-28 07:04:03.006195+00', false, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.segment_definitions VALUES ('10009d87-9dab-4c29-aa87-b56fc6e1a7d6', 'PSYCHOLOGY_OP_ASSESS', 'OP Psychology Assessment', 'Assess patient''s mental health during a natural outpatient conversation. Assess it in the form of the parts below

**Part A — Emotional Distress & Stress (past 2 weeks)**                                                                                                                        
  Score each item as an integer between 0–3: 0 = Not at all, 1 = Few days, 2 = Many days, 3 = Almost daily.

**List of items**
  1. Felt worried or tense                                                                                                                                                       
  2. Noticed a change in appetite (eating more or less than usual)                                                                                                               
  3. Felt less motivated to do usual activities                                                                                                                                  
  4. Felt stressed because of health or life situation                                                                                                                           
  5. Felt worried about recovery or future

 **Part B — Daily Life & Wellbeing (past 2 weeks)**                                                                                                                             
  Score each item as an integer between 0 or 1: 1 = Yes, 0 = No.                   
**List of items**                                                                                                                                                                                 
  6. Had trouble sleeping                               
  7. Felt tired most of the time                                                                                                                                                 
  8. Lost interest in things usually enjoyed            
  9. Health or stress affecting daily routine                                                                                                                                    
  10. Felt lonely or lacking emotional support

If any item is not dicussed or picked up during the conversation, mark the score as null.
Based on total score (which is sum of items and parts), - populate the `interpretation` and ''recommended_action''. — 

''interpretation'' based on `total_score`, use these exact labels:                                                                                                           
    - 0–3: "No distress"
    - 4–7: "Mild concern"                                                                                                                                                        
    - 8–11: "Moderate distress"                                                                                                                                                  
    - 12–15: "High distress"
    - 16–20: "Severe distress"                                                                                                                                                   
 `recommended_action` — based on `interpretation`, use these exact labels:
    - No distress → "Routine care"                                                                                                                                               
    - Mild concern → "Monitor – Brief counselling / psychological first aid"
    - Moderate distress → "Consider psychologist referral"                                                                                                                       
    - High distress → "Refer to psychologist"                                                                                                                                    
    - Severe distress → "Urgent psychological support – Refer to a psychiatrist"', '{"type": "object", "required": ["items", "part_a_score", "part_b_score", "total_score", "answered_count", "interpretation", "recommended_action", "score_reliability_note", "clinical_summary", "confidence"], "properties": {"items": {"type": "array", "items": {"type": "object", "required": ["question_no", "answered", "verbal_evidence", "voice_evidence", "score", "voice_override_applied", "reasoning", "item_description"], "properties": {"score": {"type": ["integer", "null"], "description": "Integer score: Part A 0-3, Part B 0-1. null when answered is false."}, "answered": {"type": "boolean", "description": "True only if the topic was genuinely touched in conversation, directly or indirectly"}, "reasoning": {"type": "string", "description": "One-line integration of verbal + voice into the score, or ''not discussed'' when unanswered"}, "question_no": {"type": "integer", "description": "OMH-Q10 question number (1 through 10)"}, "voice_evidence": {"type": "string", "description": "Paralinguistic observation (tremor, pace, pitch, hesitation, etc.); empty string if nothing distinctive"}, "verbal_evidence": {"type": "string", "description": "Short quote or faithful paraphrase; empty string if nothing verbal"}, "item_description": {"type": "string", "description": "Short description of item for which response is recorded"}, "voice_override_applied": {"type": "boolean", "description": "True when voice cues drove the final score against the verbal response"}}}, "description": "Exactly 10 entries, one per OMH-Q10 question in order 1..10"}, "confidence": {"enum": ["Low", "Medium", "High"], "type": "string", "description": "Confidence in the overall assessment"}, "total_score": {"type": "integer", "description": "part_a_score + part_b_score (0-20)"}, "part_a_score": {"type": "integer", "description": "Sum of answered scores for questions 1-5 (0-15)"}, "part_b_score": {"type": "integer", "description": "Sum of answered scores for questions 6-10 (0-5)"}, "answered_count": {"type": "integer", "description": "Number of items with answered=true (0-10)"}, "interpretation": {"enum": ["No distress", "Mild concern", "Moderate distress", "High distress", "Severe distress"], "type": "string", "description": "Distress tier based on total_score"}, "clinical_summary": {"type": "string", "description": "1-2 sentence psychologist-style impression integrating evidence across items"}, "recommended_action": {"enum": ["Routine care", "Monitor – Brief counselling / psychological first aid", "Consider psychologist referral", "Refer to psychologist", "Urgent psychological support – Refer to a psychiatrist"], "type": "string", "description": "Clinical action matching the interpretation tier"}, "score_reliability_note": {"type": "string", "description": "Non-empty caveat only when answered_count < 7; empty string otherwise"}}, "description": "OMH-Q10 outpatient mental health screening inferred from conversation + voice"}', 'core', false, 999, 'system', 'balanced', 'medical_terms', NULL, true, '2026-04-24 08:36:18.408104+00', '2026-04-24 08:43:00.217526+00', 'active', NULL, NULL, NULL, false, NULL, false, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.segment_definitions VALUES ('98b87dcc-392f-49d7-a063-2bfb4fb281d1', 'PRESCRIPTION', 'Prescription', 'Extract prescription with medication details (name with strength, form if mentioned, morning/noon/evening/night quantities, duration, timing, remarks). For Discharge cases, these are medications to be followed upon discharge. If the form (tablet, syrup, capsule, drops, injection, etc.) is mentioned or clearly implied, include it in the "form" field. If not mentioned, omit or leave empty.

**Extraction Rules***
âœ… **durationDays MUST be a number in days**: Convert all durations to days.                                                                                                          
    "1 month" â†’ "30", "2 weeks" â†’ "14", "3 months" â†’ "90", "1 year" â†’ "365", "6 weeks" â†’ "42".                                                                                            
    If doctor says "continue" or "lifelong", or doesn''t mention, use "".
 âœ… **SOS / PRN / As-needed medicines**: When doctor says "if needed", "when required", "SOS", "PRN", or equivalent in other languages (Tamil: "thevaipadda/à®¤à¯‡à®µà¯ˆà®ªà¯à®ªà®Ÿà¯à®Ÿà®¾", Hindi: "zaroorat padne par", Telugu: "avasaramaithe"):
     - Set morning_qty/noon_qty/evening_qty/night_qty all to "0"
     - Put "SOS" or "As needed" in the remarks field along with the condition
       (e.g., "SOS - take if fever above 100Â°F", "As needed for pain")
     - âŒ Do NOT treat "if needed" / "thevaipattaa" as a medicine name â€” it is an instruction qualifier
âœ… **"Continue current medicines"**: When doctor reviews the patient''s current medications                                                                                              
     and says "continue", "same medicines", "continue all":                                                                                                                               
     - Extract EACH medicine individually into the prescription with full details                                                                                                         
     - These medicines should appear in BOTH current_medications (History) AND prescription                                                                                               
     - Do NOT output "continue current medicines" as a prescription entry â€” list actual names

***Example:***
```
json
{
  "prescription": [
    {
      "name": "Paracetamol 500mg",
      "form": "Tablet",
      "remarks": "Take after food",
      "morning_qty": "1",
      "noon_qty": "0",
      "evening_qty": "1",
      "night_qty": "1",
      "timeToTake": "After meals",
      "durationDays": "5"
    },
    {
      "name": "Amoxicillin 500mg",
      "form": "Capsule",
      "remarks": "Complete the full course",
      "morning_qty": "1",
      "noon_qty": "0",
      "evening_qty": "0",
      "night_qty": "1",
      "timeToTake": "Before meals",
      "durationDays": "7"
    },
    {
      "name": "Vitamin D3 60000 IU",
      "form": "",
      "remarks": "Once weekly",
      "morning_qty": "1",
      "noon_qty": "0",
      "evening_qty": "0",
      "night_qty": "0",
      "timeToTake": "After breakfast",
      "durationDays": "28"
    },
    {
      "name": "Paracetamol 650mg",
      "form": "Tablet",
      "remarks": "SOS - take if fever above 100Â°F",
      "morning_qty": "0",
      "noon_qty": "0",
      "evening_qty": "0",
      "night_qty": "0",
      "timeToTake": "As needed",
      "durationDays": ""
    }
  ]
}
```', '{"type": "array", "items": {"type": "object", "properties": {"form": {"type": "string"}, "name": {"type": "string"}, "remarks": {"type": "string"}, "noon_qty": {"type": "string"}, "night_qty": {"type": "string"}, "timeToTake": {"type": "string"}, "evening_qty": {"type": "string"}, "morning_qty": {"type": "string"}, "durationDays": {"type": "string"}}}}', 'core', false, 999, NULL, 'balanced', 'medical_terms', NULL, true, '2026-05-25 17:41:11.357555+00', '2026-05-25 17:41:11.357555+00', 'active', NULL, NULL, NULL, false, NULL, false, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.segment_definitions VALUES ('b530bc7a-66ba-49a2-8443-f9c1592ccb3b', 'RECOMMENDATION_ADVISE', 'Recommendation and Advise', '**Description:** Doctor''s complete plan for the patient â€” clinical recommendations, management actions, patient advice, and review/follow-up instructions. Consolidated from four form fields (Recommendation, Management, Advise, Review Remarks) into one segment with four sub-fields preserving the doctor''s mental model.

**Sub-fields:**

1. **recommendation** â€” Clinical recommendations from the doctor â€” what investigations/biopsies/imaging/referrals are recommended. Free text.
   - Examples: "Core needle biopsy of right breast lesion under USG guidance", "MRI breast bilateral for further evaluation", "Surgical oncology referral for definitive management"

2. **management** â€” Management plan â€” surgical/medical/oncological management decisions. Free text.
   - Examples: "Plan for wide local excision with sentinel lymph node biopsy", "Neoadjuvant chemotherapy followed by surgery", "Conservative management with 6-month follow-up USG"

3. **advise** â€” Patient-facing advice â€” lifestyle, medication, what to do/avoid before next visit. Free text.
   - Examples: "Stop OCP immediately. Continue current medications. Self breast examination monthly. Avoid HRT.", "Stop aspirin 5 days before biopsy. Report any new lumps or skin changes immediately."

4. **review_remarks** â€” Follow-up/review instructions and timing. Free text â€” capture review date, what to bring, what will be discussed.
   - Examples: "Review in 1 week with biopsy report", "Follow-up after 3 months with repeat USG", "Review on 15-06-2026 for surgery planning"

**Extraction Rules:**
- âœ… Keep recommendation, management, and advise distinct â€” they serve different downstream uses
- âœ… For `review_remarks`, always try to capture timing (review in X weeks/months) and what to bring
- âœ… Use patient-friendly language in `advise` (doctor â†’ patient)
- âœ… Use clinical language in `recommendation` and `management` (doctor â†’ record)
- âŒ Do NOT duplicate the same content across sub-fields â€” pick the most appropriate one
- âŒ Do NOT fabricate plans not stated by the doctor â€” leave as "" if not mentioned
- âŒ Do NOT put diagnoses or examination findings here', '{"type": "object", "properties": {"advise": {"type": "string"}, "management": {"type": "string"}, "recommendation": {"type": "string"}, "review_remarks": {"type": "string"}}}', 'core', false, 999, 'system', 'balanced', 'medical_terms', NULL, true, '2026-05-27 14:14:05.445866+00', '2026-05-27 14:14:05.445866+00', 'active', NULL, NULL, NULL, false, NULL, false, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.segment_definitions VALUES ('de4d22e5-b448-4abc-9bb0-467022f1173e', 'PSYCHOLOGY_IP_ASSESS', 'IP Psychology assessment', 'Assess patient''s mental health during a natural inpatient (ward/bedside) conversation. Assess it in the form of the parts below.                                               
                                                         
  **Part A — Emotional & Situational Concerns**                                                                                                                                  
  Score each item as an integer between 0–3: 0 = Not at all, 1 = Sometimes, 2 = Often, 3 = Almost always.
                                                                                                                                                                                 
  **List of items**                                      
  1. Experiencing stress or emotional strain related to being hospitalized                                                                                                       
  2. Worry or concern regarding current health condition or recovery
  3. Low mood, sadness, or emotional discouragement
  4. Concern about family members or responsibilities at home
  5. Discomfort due to being away from usual home or daily environment
                                                                                                                                                                                 
  **Part B — Well-being & Daily Functioning**                                                                                                                                    
  Score each item as an integer between 0–3: 0 = Not at all, 1 = Sometimes, 2 = Often, 3 = Almost always.
                                                                                                                                                                                 
  **List of items**                                      
  6. Difficulty falling asleep, staying asleep, or getting adequate rest
  7. Noticeable reduction or change in appetite or food intake                                                                                                                   
  8. Persistent tiredness or reduced energy levels
  9. Difficulty maintaining hopefulness or a positive outlook                                                                                                                    
  10. Reduced interest in talking or engaging with others                                                                                                                        
  
  If any item is not discussed or picked up during the conversation, mark the score as null.                                                                                     
  Based on total score (which is the sum of all items across both parts), populate the `interpretation` and `recommended_action`.
                                                                                                                                                                                 
  `interpretation` based on `total_score`, use these exact labels:                                                                                                               
    - 0–5:   "No significant distress"
    - 6–10:  "Mild emotional stress"                                                                                                                                             
    - 11–15: "Emotional concern present"                                                                                                                                         
    - 16–20: "Moderate distress"
    - 21–30: "High distress"                                                                                                                                                     
                                                         
  `recommended_action` — based on `interpretation`, use these exact labels:                                                                                                      
    - No significant distress → "Routine observation"
    - Mild emotional stress → "Provide reassurance / Brief counselling"                                                                                                          
    - Emotional concern present → "Monitor / consider psychologist referral"
    - Moderate distress → "Refer to psychologist"                                                                                                                                
    - High distress → "Immediate referral to psychologist"', '{"type": "object", "required": ["items", "part_a_score", "part_b_score", "total_score", "answered_count", "interpretation", "recommended_action", "score_reliability_note", "clinical_summary", "confidence"], "properties": {"items": {"type": "array", "items": {"type": "object", "required": ["question_no", "answered", "verbal_evidence", "voice_evidence", "score", "voice_override_applied", "reasoning"], "properties": {"score": {"type": ["integer", "null"], "description": "Integer score 0–3 for both Part A and Part B. null when answered is false."}, "answered": {"type": "boolean", "description": "True only if the topic was genuinely touched in conversation, directly or indirectly"}, "reasoning": {"type": "string", "description": "One-line integration of verbal + voice into the score, or ''not discussed'' when unanswered"}, "question_no": {"type": "integer", "description": "Question number (1 through 10)"}, "voice_evidence": {"type": "string", "description": "Paralinguistic observation (tremor, pace, pitch, hesitation, etc.); empty string if nothing distinctive"}, "verbal_evidence": {"type": "string", "description": "Short quote or faithful paraphrase; empty string if nothing verbal"}, "voice_override_applied": {"type": "boolean", "description": "True when voice cues drove the final score against the verbal response"}}}, "description": "Exactly 10 entries, one per question in order 1..10"}, "confidence": {"enum": ["Low", "Medium", "High"], "type": "string", "description": "Confidence in the overall assessment"}, "total_score": {"type": "integer", "description": "part_a_score + part_b_score (0–30)"}, "part_a_score": {"type": "integer", "description": "Sum of answered scores for questions 1–5 (0–15)"}, "part_b_score": {"type": "integer", "description": "Sum of answered scores for questions 6–10 (0–15)"}, "answered_count": {"type": "integer", "description": "Number of items with answered=true (0–10)"}, "interpretation": {"enum": ["No significant distress", "Mild emotional stress", "Emotional concern present", "Moderate distress", "High distress"], "type": "string", "description": "Distress tier based on total_score"}, "clinical_summary": {"type": "string", "description": "1–2 sentence psychologist-style impression integrating evidence across items"}, "recommended_action": {"enum": ["Routine observation", "Provide reassurance / Brief counselling", "Monitor / consider psychologist referral", "Refer to psychologist", "Immediate referral to psychologist"], "type": "string", "description": "Clinical action matching the interpretation tier"}, "score_reliability_note": {"type": "string", "description": "Non-empty caveat only when fewer than 70% of items were answered (<7 of 10); empty string otherwise"}}, "description": "Inpatient psychology assessment (10 items, 0–30) inferred from conversation + voice"}', 'core', false, 999, 'system', 'balanced', 'medical_terms', NULL, true, '2026-04-24 08:36:47.260132+00', '2026-04-24 08:42:54.312067+00', 'active', NULL, NULL, NULL, false, NULL, false, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.segment_definitions VALUES ('dbcc139f-faee-4653-bd5d-0f3bd62b4974', 'TREATMENT_PLAN', 'Treatment Plan & Prescription', 'Extract prescription details, follow-up timeline, and other instructions combining diet, activity, monitoring, and warning signs. Prescription details should contain medication details such as medicine name with strength, dosage, frequency, duration, timing etc. and separate each medicine details using commas and numbers

Always include strength with medicine name e.g. Dolo 650mg

**Scope rules for prescription field**
- Only include medications the doctor explicitly prescribes or modifies in this visit.
- Do NOT include medications the patient mentions on their own ("I''m on BP tablets")
  unless the doctor explicitly continues / modifies them.
- If the doctor says "I''ll prescribe tablets for 3 months" or "give him pain meds" without
  naming a specific drug, leave the prescription string empty (""). Do NOT invent
  placeholder names like "Tablets for pain management" or "Pain medication".

***Example:***
```
json
{
  "follow_up": "Come back in 2 weeks on 10-12-2025 and bring your previous blood reports",
  "other_instructions": "Increase protein intake, avoid spicy food and avoid heavy lifting. Contact immediately if fever >102°F, severe headache, or breathing difficulty",
  "prescription": "Doctor prescribed: 1) Amoxicillin 500 mg, Once Daily at night after meals for 4 days. 2) Vitamin D3 60000 IU, Once Weekly in the morning after breakfast for six weeks".
}
```', '{"type": "object", "properties": {"follow_up": {"type": "string", "description": "Instructions on when to come back and what to bring"}, "prescription": {"type": "string", "description": "Instructions on what medicine to take at what frequency, duration and timing"}, "other_instructions": {"type": "string", "description": "Non prescription instructions or N/A"}}}', 'core', false, 5, 'system', 'balanced', 'simple_terms', 'Cloned from TREATMENT_PLAN: Cloned from TREATMENT_PLAN_SIMPLE: Combined: Prescription + Follow-up + Other instructions (diet/activity/monitoring/warning signs)', true, '2025-12-09 16:20:45.080237+00', '2026-05-06 03:20:42.311775+00', 'active', NULL, NULL, 'TREATMENT_PLAN', true, '2025-12-09 16:20:45.080237+00', false, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.segment_definitions VALUES ('75b3e7da-7e22-45cc-b559-5ef0680bebac', 'EXTERNAL_THERAPY_AND_DOCUMENTS', 'External Therapy and Documents', '**Description:** Extract two related fields from the end of the form: External Therapy (panchakarma procedures, abhyanga, swedana, and other body-applied therapies) and Documents (references to attached reports, pending investigations, or supporting documentation). These two fields are grouped into one segment because Documents is a small one-field section that logically pairs with the consultant''s treatment plan.

**Sanskrit-English glossary for this segment:**
- **External Therapy** maps to Bahir-parimarjana chikitsa (external cleansing/treatment) â€” therapies applied to the body externally, distinct from internal medicines. Common examples include:
    - **Abhyanga** = therapeutic oil massage
    - **Swedana** = sudation / sweating therapy
    - **Shirodhara** = pouring of medicated liquid over the forehead
    - **Basti** = enema (medicated)
    - **Nasya** = nasal medication
    - **Virechana** = therapeutic purgation
    - **Vamana** = therapeutic emesis
    - **Raktamokshana** = bloodletting
    - **Kashaya seka / Pizhichil** = streaming of warm medicated liquid

**Required Fields (both free text, NO {status, remarks} wrapper):**

- **external_therapy** â€” Free text. The consultant''s prescribed external therapies, with details (medicine/taila used, body region, duration, frequency). Use "" if not stated.
- **documents** â€” Free text. References to attached or pending documents â€” lab reports, prior records, imaging, etc. Use "" if not stated.

**Extraction Rules:**
- âœ… Preserve Sanskrit therapy names verbatim (Abhyanga, Shirodhara, Virechana, etc.)
- âœ… Preserve all therapy details: type of taila/medicine used, body region, duration, frequency
- âœ… For documents, capture references precisely (e.g., "CBC, LFT pending", "Previous USG report attached")
- âœ… Use "" (empty string) for fields not stated
- âŒ Do NOT include internal medicines here â€” those go in PRESCRIPTION
- âŒ Do NOT include diagnostic findings â€” those belong in earlier segments

**Example (sample client has both fields empty on the form):**
```json
{
  "external_therapy": "",
  "documents": ""
}
```

**Example (when both are stated):**
```json
{
  "external_therapy": "Abhyanga with Chandanadi taila for 30 minutes daily for 7 days, followed by Swedana. Shirodhara with Brahmi taila on day 3, 5, 7.",
  "documents": "CBC and LFT reports pending â€” to be reviewed at next visit."
}
```', '{"type": "object", "properties": {"documents": {"type": "string"}, "external_therapy": {"type": "string"}}}', 'core', false, 999, NULL, 'balanced', 'medical_terms', NULL, true, '2026-05-25 17:42:06.705884+00', '2026-05-25 17:42:06.705884+00', 'active', NULL, NULL, NULL, false, NULL, false, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.segment_definitions VALUES ('fd568e41-c535-4e40-935b-7a8f046f5abe', 'PSYCHOLOGY_ONCO_ASSESS', 'Psychology onco health questions', 'Assess the patient''s mental health during a natural conversation, covering the past 7 days. 20 items grouped into 7 domains (A, B, C, D, E, F, H) rated on a 0–4 Likert scale,
  plus 1 Distress Thermometer item (G, 0–10) that is tracked separately.                                                                                                         
   
  **Likert scale for items Q1–Q20:** 0 = Not at all, 1 = A little bit, 2 = Moderately, 3 = Quite a bit, 4 = Very much                                                            
                                                         
  **Reverse-scored items:** Q11, Q14, Q15, Q16, Q17, Q18                                                                                                                         
    - For these, `raw_score` = observed 0–4 value; `adjusted_score` = 4 − raw_score.
    - For all other items, `adjusted_score` = `raw_score`.                                                                                                                       
    - Domain and total sums MUST use `adjusted_score`.
                                                                                                                                                                                 
  **Domains & items**                                    
                                                                                                                                                                                 
  A. Emotional Distress & Mood (Q1–Q4)                   
    1. I felt anxious, nervous, or on edge
    2. I felt sad, low, or hopeless
    3. I felt overwhelmed or unable to cope                                                                                                                                      
    4. I had little interest or pleasure in doing things
                                                                                                                                                                                 
  B. Cognitive Distress & Fear (Q5–Q7)                                                                                                                                           
    5. I worry about my illness getting worse or returning
    6. Thoughts about my illness come suddenly and disturb me                                                                                                                    
    7. I find it difficult to control these worries      
                                                                                                                                                                                 
  C. Physical & Functional Well-being (Q8–Q10)
    8. I feel physically exhausted or lacked energy                                                                                                                              
    9. My health limited my daily activities             
    10. I had difficulty sleeping due to stress or illness
                                                                                                                                                                                 
  D. Social Support & Connection (Q11–Q13)
    11. I feel emotionally supported by others  *(REVERSE-SCORED)*                                                                                                               
    12. I feel comfortable talking to someone about my illness                                                                                                                   
    13. I feel lonely or isolated
                                                                                                                                                                                 
  E. Meaning, Hope & Coping (Q14–Q16)                                                                                                                                            
    14. I feel hopeful about my future  *(REVERSE-SCORED)*
    15. I try to face my illness with strength or determination  *(REVERSE-SCORED)*                                                                                              
    16. I am able to find meaning or purpose despite my illness  *(REVERSE-SCORED)*                                                                                              
   
  F. Resilience (Q17–Q18)                                                                                                                                                        
    17. I am able to bounce back after difficult times  *(REVERSE-SCORED)*
    18. I can stay calm and focused under stress  *(REVERSE-SCORED)*                                                                                                             
   
  H. Risk Screening (Q19–Q20) — CRITICAL                                                                                                                                         
    19. I had thoughts of harming myself or giving up    
    20. My emotional distress is affecting my daily life                                                                                                                         
                                                         
  **G. Global Distress — Distress Thermometer (separate 0–10 scale)**                                                                                                            
  Infer an overall distress thermometer reading 0–10 (0 = no distress, 10 = extreme distress) from the integrated affective quality of the entire conversation and the patient''s
  voice. This is tracked as `distress_thermometer` and is NOT included in `total_score`. Use null only if nothing meaningful was observable in the conversation.                 
                                                         
  If an item (Q1–Q20) was not discussed or picked up, directly or indirectly, mark `answered: false`, `raw_score: null`, `adjusted_score: null`. Do not extrapolate an item''s    
  score from other items or other domains.               
                                                                                                                                                                                 
  **Scoring (only over answered items; reverse-adjustment already applied)**                                                                                                     
    - domain_a_score = sum of adjusted_score for Q1–Q4 (0–16)
    - domain_b_score = sum of adjusted_score for Q5–Q7 (0–12)                                                                                                                    
    - domain_c_score = sum of adjusted_score for Q8–Q10 (0–12)
    - domain_d_score = sum of adjusted_score for Q11–Q13 (0–12)                                                                                                                  
    - domain_e_score = sum of adjusted_score for Q14–Q16 (0–12)
    - domain_f_score = sum of adjusted_score for Q17–Q18 (0–8)                                                                                                                   
    - domain_h_score = sum of adjusted_score for Q19–Q20 (0–8)
    - total_score = sum of all seven domain scores (0–80)                                                                                                                        
    - answered_count = count of Q1–Q20 with `answered: true` (0–20)
                                                                                                                                                                                 
  **Interpretation** — based on `total_score`, use these exact labels:
    - 0–20:  "Minimal"                                                                                                                                                           
    - 21–40: "Mild"                                                                                                                                                              
    - 41–60: "Moderate"
    - 61–80: "Severe"                                                                                                                                                            
                                                         
  **Clinical meaning** — matching `interpretation`, use these exact labels:                                                                                                      
    - Minimal  → "Normal adjustment"
    - Mild     → "Monitor"                                                                                                                                                       
    - Moderate → "Needs psychological support"                                                                                                                                   
    - Severe   → "Immediate intervention"
                                                                                                                                                                                 
  **Clinical alerts** (always output an array; empty [] if none trigger)                                                                                                         
    - If Q19 adjusted_score ≥ 2 → add: "Immediate psychological/psychiatric referral (Q19 ≥ 2)"
    - If distress_thermometer ≥ 7 → add: "Further assessment required (Distress Thermometer ≥ 7)"                                                                                
                                                                                                                                                                                 
  **Reliability:** if fewer than 70% of items (Q1–Q20) were answered — i.e., answered_count < 14 — set `score_reliability_note` to state that the total underrepresents the      
  patient''s state and should be treated as partial. Otherwise empty string.', '{"type": "object", "required": ["items", "distress_thermometer", "distress_thermometer_evidence", "domain_a_score", "domain_b_score", "domain_c_score", "domain_d_score", "domain_e_score", "domain_f_score", "domain_h_score", "total_score", "answered_count", "interpretation", "clinical_meaning", "clinical_alerts", "score_reliability_note", "clinical_summary", "confidence"], "properties": {"items": {"type": "array", "items": {"type": "object", "required": ["question_no", "domain", "reverse_scored", "answered", "verbal_evidence", "voice_evidence", "raw_score", "adjusted_score", "voice_override_applied", "reasoning"], "properties": {"domain": {"enum": ["A_EMOTIONAL_DISTRESS", "B_COGNITIVE_FEAR", "C_PHYSICAL_FUNCTIONAL", "D_SOCIAL_SUPPORT", "E_MEANING_HOPE", "F_RESILIENCE", "H_RISK"], "type": "string", "description": "Domain for this item"}, "answered": {"type": "boolean", "description": "True only if the topic was genuinely touched in conversation, directly or indirectly"}, "raw_score": {"type": ["integer", "null"], "description": "Observed 0–4 value on the Likert scale; null when answered is false"}, "reasoning": {"type": "string", "description": "One-line integration of verbal + voice into the score, or ''not discussed'' when unanswered"}, "question_no": {"type": "integer", "description": "Question number (1 through 20)"}, "adjusted_score": {"type": ["integer", "null"], "description": "Reverse-adjusted score (4 − raw) for reverse_scored items; equal to raw_score otherwise; null when answered is false"}, "reverse_scored": {"type": "boolean", "description": "True for Q11, Q14, Q15, Q16, Q17, Q18; false otherwise"}, "voice_evidence": {"type": "string", "description": "Paralinguistic observation (tremor, pace, pitch, hesitation, etc.); empty string if nothing distinctive"}, "verbal_evidence": {"type": "string", "description": "Short quote or faithful paraphrase; empty string if nothing verbal"}, "voice_override_applied": {"type": "boolean", "description": "True when voice cues drove the final score against the verbal response"}}}, "description": "Exactly 20 entries, one per question in order 1..20"}, "confidence": {"enum": ["Low", "Medium", "High"], "type": "string", "description": "Confidence in the overall assessment"}, "total_score": {"type": "integer", "description": "Sum of all seven domain scores (0–80)"}, "answered_count": {"type": "integer", "description": "Number of items (Q1–Q20) with answered=true (0–20)"}, "domain_a_score": {"type": "integer", "description": "Sum of adjusted_score for Q1–Q4 (0–16)"}, "domain_b_score": {"type": "integer", "description": "Sum of adjusted_score for Q5–Q7 (0–12)"}, "domain_c_score": {"type": "integer", "description": "Sum of adjusted_score for Q8–Q10 (0–12)"}, "domain_d_score": {"type": "integer", "description": "Sum of adjusted_score for Q11–Q13 (0–12)"}, "domain_e_score": {"type": "integer", "description": "Sum of adjusted_score for Q14–Q16 (0–12)"}, "domain_f_score": {"type": "integer", "description": "Sum of adjusted_score for Q17–Q18 (0–8)"}, "domain_h_score": {"type": "integer", "description": "Sum of adjusted_score for Q19–Q20 (0–8)"}, "interpretation": {"enum": ["Minimal", "Mild", "Moderate", "Severe"], "type": "string", "description": "Severity tier based on total_score"}, "clinical_alerts": {"type": "array", "items": {"type": "string"}, "description": "Triggered clinical alerts; empty array if none"}, "clinical_meaning": {"enum": ["Normal adjustment", "Monitor", "Needs psychological support", "Immediate intervention"], "type": "string", "description": "Clinical meaning matching interpretation tier"}, "clinical_summary": {"type": "string", "description": "1–2 sentence psychologist-style impression integrating evidence across domains"}, "distress_thermometer": {"type": ["integer", "null"], "description": "Global distress thermometer 0–10 (separate from items total); null if nothing observable"}, "score_reliability_note": {"type": "string", "description": "Non-empty caveat only when fewer than 70% of items answered (<14 of 20); empty string otherwise"}, "distress_thermometer_evidence": {"type": "string", "description": "Short explanation of how the thermometer reading was inferred; empty string if null"}}, "description": "Oncology psychosocial assessment: 20 items across 7 domains (0–80) + Distress Thermometer (0–10); inferred from conversation + voice"}', 'core', false, 999, 'system', 'balanced', 'medical_terms', NULL, true, '2026-04-24 08:37:45.358858+00', '2026-04-24 08:42:48.377588+00', 'active', NULL, NULL, NULL, false, NULL, false, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.segment_definitions VALUES ('c82f4dd1-5d65-4c09-a563-7195f7396cc8', 'VITALSBEWELL', 'Vitals', '**Description:** Vital signs with units.

