INSERT INTO public.segment_definitions VALUES ('ddb0c15c-ea1a-4597-9a0a-507d80374d0f', 'PRIOR_IMAGING', 'Prior Imaging', '**Description:** Patient''s longitudinal breast imaging history â€” prior mammograms, ultrasounds, MRIs, etc. that the patient has brought to today''s visit or that the doctor reviews from past records. Each entry is one imaging study with its date, modality, and findings.

**Schema:** Array of imaging studies. Each item has `date`, `modality`, and `findings`.

**Field details:**

1. **date** â€” Date of the imaging study. Free text â€” DD-MM-YYYY format preferred, otherwise descriptive (e.g., "March 2024", "6 months ago").
   - Examples: "15-03-2024", "March 2024", "2023"

2. **modality** â€” Type of imaging. Free text. Standard modalities include:
   - Mammogram
   - Ultrasound (USG)
   - MRI breast
   - CT
   - PET-CT
   - Tomosynthesis (3D mammogram)
   - Examples: "Mammogram", "USG breast bilateral", "MRI breast"

3. **findings** â€” Imaging findings as reported. Free text. Include BIRADS if mentioned.
   - Examples: "Right breast 2cm hypoechoic lesion at 10 o''clock, BIRADS 4a", "Bilateral mammogram normal, BIRADS 1", "Left breast lump 1.5cm, well-defined, BIRADS 3"

**Extraction Rules:**
- âœ… Extract ALL prior imaging studies mentioned, in chronological order if possible
- âœ… One entry per imaging study â€” do not merge multiple studies into one entry
- âœ… Include BIRADS in findings if the patient/report mentions it
- âœ… If only modality is mentioned without date or findings, still create the entry with empty strings for missing fields
- âŒ Do NOT include today''s imaging review (that goes to IMAGING segment)
- âŒ Do NOT fabricate dates or findings â€” leave as "" if not mentioned
- âŒ Do NOT include ordered/recommended imaging (that goes to TREATMENT_PLAN)

**Example:**
```json
[
  {"date": "15-03-2024", "modality": "Mammogram", "findings": "Right breast 2cm mass at 10 o''clock, BIRADS 4a"},
  {"date": "20-03-2024", "modality": "USG breast", "findings": "Hypoechoic lesion 2.1cm, irregular margins, BIRADS 4b"}
]
```', '{"type": "array", "items": {"type": "object", "properties": {"date": {"type": "string", "description": "Imaging date in DD-MM-YYYY format or descriptive"}, "findings": {"type": "string", "description": "Imaging findings, include BIRADS if mentioned"}, "modality": {"type": "string", "description": "Mammogram, USG, MRI, CT, PET-CT, etc."}}}, "description": "List of prior imaging studies"}', 'core', false, 999, 'system', 'balanced', 'medical_terms', NULL, true, '2026-05-27 14:14:04.867371+00', '2026-05-27 14:14:04.867371+00', 'active', NULL, NULL, NULL, false, NULL, false, NULL, NULL) ON CONFLICT DO NOTHING;


