INSERT INTO public.radiology_toxicity_library VALUES ('06853567-84e3-4b39-8cd6-b9526f2c4782', 'aa9cd693-e0e6-4bca-ac13-1aad2498cf63', 'HN_E02', 'early', 'Skin irritation, itching, erythema, desquamation, edema, and rarely ulceration, necrosis, or bleeding.', NULL, 2, true, '2026-04-29 03:43:11.584124+00', '2026-04-29 03:43:11.584124+00') ON CONFLICT DO NOTHING;
INSERT INTO public.radiology_toxicity_library VALUES ('67def1c1-4308-4beb-8578-31362f7789c2', 'aa9cd693-e0e6-4bca-ac13-1aad2498cf63', 'HN_E03', 'early', 'Oral, pharyngeal, and laryngeal mucositis with erythema, irritation, pain, edema, discharge, and rarely ulceration, necrosis, or bleeding.', NULL, 3, true, '2026-04-29 03:43:11.584124+00', '2026-04-29 03:43:11.584124+00') ON CONFLICT DO NOTHING;
INSERT INTO public.radiology_toxicity_library VALUES ('751422cf-9b90-44f4-a850-211a455aae79', 'aa9cd693-e0e6-4bca-ac13-1aad2498cf63', 'HN_E04', 'early', 'Mouth dryness, thick sticky saliva, altered or metallic taste, anorexia, nausea, and vomiting.', NULL, 4, true, '2026-04-29 03:43:11.584124+00', '2026-04-29 03:43:11.584124+00') ON CONFLICT DO NOTHING;
INSERT INTO public.radiology_toxicity_library VALUES ('51a3c92a-f345-4f71-a680-a61ea387ee40', 'aa9cd693-e0e6-4bca-ac13-1aad2498cf63', 'HN_E05', 'early', 'Odynophagia and dysphagia, possibly requiring narcotic analgesics, IV fluids, or feeding tube; risk of pharyngeal or oesophageal obstruction, ulceration, perforation, fistula, and bleeding.', NULL, 5, true, '2026-04-29 03:43:11.584124+00', '2026-04-29 03:43:11.584124+00') ON CONFLICT DO NOTHING;
