INSERT INTO public.radiology_toxicity_library VALUES ('9f5d8456-bb57-466d-b0f5-574685ea1030', 'aa9cd693-e0e6-4bca-ac13-1aad2498cf63', 'HN_L02', 'late', 'Subcutaneous tissue fibrosis, induration, contracture, lymphedema, and rarely necrosis.', NULL, 2, true, '2026-04-29 03:43:11.584124+00', '2026-04-29 03:43:11.584124+00') ON CONFLICT DO NOTHING;
