INSERT INTO public.radiology_toxicity_library VALUES ('9dddf269-6314-40bf-85f0-fc171cd82601', 'aa9cd693-e0e6-4bca-ac13-1aad2498cf63', 'HN_L05', 'late', 'Aspiration and difficulty or pain in swallowing, possibly requiring feeding tube or dilation.', NULL, 5, true, '2026-04-29 03:43:11.584124+00', '2026-04-29 03:43:11.584124+00') ON CONFLICT DO NOTHING;
INSERT INTO public.radiology_toxicity_library VALUES ('5381b615-cec1-49ad-a103-a6d8c645bb2b', 'aa9cd693-e0e6-4bca-ac13-1aad2498cf63', 'HN_L06', 'late', 'Persistent hoarseness, arytenoid edema, chondritis, and rarely laryngeal necrosis.', NULL, 6, true, '2026-04-29 03:43:11.584124+00', '2026-04-29 03:43:11.584124+00') ON CONFLICT DO NOTHING;
