INSERT INTO public.radiology_toxicity_library VALUES ('2c797c1a-f695-4467-a75e-0339caaba26d', 'aa9cd693-e0e6-4bca-ac13-1aad2498cf63', 'HN_L14', 'late', 'Small but real risk of radiation-induced secondary malignancy.', NULL, 14, true, '2026-04-29 03:43:11.584124+00', '2026-04-29 03:43:11.584124+00') ON CONFLICT DO NOTHING;
