INSERT INTO public.radiology_toxicity_library VALUES ('a4a5c033-d696-4b80-a6d8-4cdc803f174c', '4f117867-274a-44ac-8a7a-d5d86f80f731', 'GY_BR_E01', 'early', 'Brachytherapy is performed in the operating room under anaesthesia.', 'BRACHYTHERAPY', 7, true, '2026-04-29 03:43:11.584124+00', '2026-04-29 03:43:11.584124+00') ON CONFLICT DO NOTHING;
INSERT INTO public.radiology_toxicity_library VALUES ('0845825b-f7e1-4085-8497-d3254c2cb625', '4f117867-274a-44ac-8a7a-d5d86f80f731', 'GY_BR_E02', 'early', 'Risk of infection at the applicator site during or after brachytherapy.', 'BRACHYTHERAPY', 8, true, '2026-04-29 03:43:11.584124+00', '2026-04-29 03:43:11.584124+00') ON CONFLICT DO NOTHING;
INSERT INTO public.radiology_toxicity_library VALUES ('d2204377-659d-46a8-8f71-13aad32c2842', '4f117867-274a-44ac-8a7a-d5d86f80f731', 'GY_BR_E03', 'early', 'Skin or vaginal mucosal irritation related to brachytherapy applicators.', 'BRACHYTHERAPY', 9, true, '2026-04-29 03:43:11.584124+00', '2026-04-29 03:43:11.584124+00') ON CONFLICT DO NOTHING;
INSERT INTO public.radiology_toxicity_library VALUES ('977c15bc-99d6-42a0-963f-1b544468a0d3', '4f117867-274a-44ac-8a7a-d5d86f80f731', 'GY_BR_E04', 'early', 'Risk of deep vein thrombosis or pulmonary embolism related to peri-procedural immobilization for brachytherapy.', 'BRACHYTHERAPY', 10, true, '2026-04-29 03:43:11.584124+00', '2026-04-29 03:43:11.584124+00') ON CONFLICT DO NOTHING;
INSERT INTO public.radiology_toxicity_library VALUES ('ab477750-1c2e-4a32-bfe1-2f84e1ece12c', '4f117867-274a-44ac-8a7a-d5d86f80f731', 'GY_BR_E05', 'early', 'Bleeding upon brachytherapy applicator removal.', 'BRACHYTHERAPY', 11, true, '2026-04-29 03:43:11.584124+00', '2026-04-29 03:43:11.584124+00') ON CONFLICT DO NOTHING;
INSERT INTO public.radiology_toxicity_library VALUES ('92218417-a2cf-4863-8499-a488cc84262d', '4f117867-274a-44ac-8a7a-d5d86f80f731', 'GY_L01', 'late', 'Risk of fistula formation, bowel obstruction, and stricture.', NULL, 1, true, '2026-04-29 03:43:11.584124+00', '2026-04-29 03:43:11.584124+00') ON CONFLICT DO NOTHING;
INSERT INTO public.radiology_toxicity_library VALUES ('f4a7f532-775f-4723-999b-ff0b028976c5', '4f117867-274a-44ac-8a7a-d5d86f80f731', 'GY_L02', 'late', 'Vaginal dryness and vaginal stenosis.', NULL, 2, true, '2026-04-29 03:43:11.584124+00', '2026-04-29 03:43:11.584124+00') ON CONFLICT DO NOTHING;
INSERT INTO public.radiology_toxicity_library VALUES ('eaa15ded-42a9-4743-b744-4a4542554d58', '4f117867-274a-44ac-8a7a-d5d86f80f731', 'GY_L03', 'late', 'Weakening of pelvic bones with risk of insufficiency fracture.', NULL, 3, true, '2026-04-29 03:43:11.584124+00', '2026-04-29 03:43:11.584124+00') ON CONFLICT DO NOTHING;
INSERT INTO public.radiology_toxicity_library VALUES ('43bae368-2f44-4c29-aa2c-12a6d1a709bf', '4f117867-274a-44ac-8a7a-d5d86f80f731', 'GY_L04', 'late', 'Sterility and premature menopause for premenopausal patients.', NULL, 4, true, '2026-04-29 03:43:11.584124+00', '2026-04-29 03:43:11.584124+00') ON CONFLICT DO NOTHING;
INSERT INTO public.radiology_toxicity_library VALUES ('7c67f3af-cd29-4d01-80aa-c361ce8dc436', '4f117867-274a-44ac-8a7a-d5d86f80f731', 'GY_L05', 'late', 'Long-term urinary symptoms including frequency, urgency, and rarely hematuria.', NULL, 5, true, '2026-04-29 03:43:11.584124+00', '2026-04-29 03:43:11.584124+00') ON CONFLICT DO NOTHING;
INSERT INTO public.radiology_toxicity_library VALUES ('8dbae5ea-23f2-4e05-8e52-4e5270408600', '4f117867-274a-44ac-8a7a-d5d86f80f731', 'GY_L06', 'late', 'Long-term bowel symptoms including altered habit, urgency, and rarely hematochezia.', NULL, 6, true, '2026-04-29 03:43:11.584124+00', '2026-04-29 03:43:11.584124+00') ON CONFLICT DO NOTHING;
INSERT INTO public.radiology_toxicity_library VALUES ('83266736-88a8-497f-b5ac-7e734e71adb3', '4f117867-274a-44ac-8a7a-d5d86f80f731', 'GY_L07', 'late', 'Skin atrophy, pigmentation, and telangiectasia in the irradiated region.', NULL, 7, true, '2026-04-29 03:43:11.584124+00', '2026-04-29 03:43:11.584124+00') ON CONFLICT DO NOTHING;
INSERT INTO public.radiology_toxicity_library VALUES ('a4b87cd1-1565-4f22-bc68-2bee59d0b5d4', '4f117867-274a-44ac-8a7a-d5d86f80f731', 'GY_L08', 'late', 'Small but real risk of radiation-induced secondary malignancy.', NULL, 8, true, '2026-04-29 03:43:11.584124+00', '2026-04-29 03:43:11.584124+00') ON CONFLICT DO NOTHING;
INSERT INTO public.radiology_toxicity_library VALUES ('3662d432-ca6b-4232-9ca4-0313d42a0a0f', '0632b0c0-4982-48d9-b698-37063bc5e4fe', 'BR_E01', 'early', 'Fatigue, mild dehydration, and discomfort or pain at the site of radiation.', NULL, 1, true, '2026-04-29 03:43:11.584124+00', '2026-04-29 03:43:11.584124+00') ON CONFLICT DO NOTHING;
INSERT INTO public.radiology_toxicity_library VALUES ('20ef0fd1-0789-4227-80b2-ef07830a877e', '0632b0c0-4982-48d9-b698-37063bc5e4fe', 'BR_E02', 'early', 'Skin irritation, itching, erythema, desquamation, edema, and rarely ulceration, necrosis, or bleeding.', NULL, 2, true, '2026-04-29 03:43:11.584124+00', '2026-04-29 03:43:11.584124+00') ON CONFLICT DO NOTHING;
INSERT INTO public.radiology_toxicity_library VALUES ('940d1ecc-0948-4a74-b3f5-e6e63fee421c', '0632b0c0-4982-48d9-b698-37063bc5e4fe', 'BR_E03', 'early', 'Lymphedema or swelling of the arm or forearm on the side of radiotherapy.', NULL, 3, true, '2026-04-29 03:43:11.584124+00', '2026-04-29 03:43:11.584124+00') ON CONFLICT DO NOTHING;
INSERT INTO public.radiology_toxicity_library VALUES ('f2884448-4c94-457a-b188-a0cd4b5cae4f', '0632b0c0-4982-48d9-b698-37063bc5e4fe', 'BR_E04', 'early', 'Mild breast tenderness, heaviness, and intermittent shooting pains.', NULL, 4, true, '2026-04-29 03:43:11.584124+00', '2026-04-29 03:43:11.584124+00') ON CONFLICT DO NOTHING;
INSERT INTO public.radiology_toxicity_library VALUES ('0b45218f-5745-47ae-a752-42c1d058b2e1', '0632b0c0-4982-48d9-b698-37063bc5e4fe', 'BR_SCF_E01', 'early', 'Odynophagia and dysphagia related to oesophageal dose, possibly requiring analgesics or dietary modification; rarely oesophageal obstruction, ulceration, or perforation.', 'SCF', 5, true, '2026-04-29 03:43:11.584124+00', '2026-04-29 03:43:11.584124+00') ON CONFLICT DO NOTHING;
INSERT INTO public.radiology_toxicity_library VALUES ('b2b49707-41ff-445b-a1f4-cdf03cc27a98', '0632b0c0-4982-48d9-b698-37063bc5e4fe', 'BR_L01', 'late', 'Skin atrophy, pigmentation, telangiectasia, and rarely ulceration, with possible localized hair loss in the radiation field.', NULL, 1, true, '2026-04-29 03:43:11.584124+00', '2026-04-29 03:43:11.584124+00') ON CONFLICT DO NOTHING;
INSERT INTO public.radiology_toxicity_library VALUES ('cae8565d-fee4-4d8e-961d-a422752da3c2', '0632b0c0-4982-48d9-b698-37063bc5e4fe', 'BR_L02', 'late', 'Subcutaneous tissue fibrosis, induration, contracture, lymphedema, and rarely necrosis.', NULL, 2, true, '2026-04-29 03:43:11.584124+00', '2026-04-29 03:43:11.584124+00') ON CONFLICT DO NOTHING;
INSERT INTO public.radiology_toxicity_library VALUES ('7e2627a6-c53f-4770-ac0a-cd5486d2cac8', '0632b0c0-4982-48d9-b698-37063bc5e4fe', 'BR_L03', 'late', 'Long-term breast firmness, retraction, and altered breast cosmesis.', NULL, 3, true, '2026-04-29 03:43:11.584124+00', '2026-04-29 03:43:11.584124+00') ON CONFLICT DO NOTHING;
INSERT INTO public.radiology_toxicity_library VALUES ('45e24e98-c0b8-41e5-82f6-f46691c11bd6', '0632b0c0-4982-48d9-b698-37063bc5e4fe', 'BR_L04', 'late', 'Fibrosis of the portion of the lung immediately adjacent to the breast or chest wall radiotherapy field.', NULL, 4, true, '2026-04-29 03:43:11.584124+00', '2026-04-29 03:43:11.584124+00') ON CONFLICT DO NOTHING;
INSERT INTO public.radiology_toxicity_library VALUES ('8ab3ee57-c44e-408b-a70f-5f0177eb0286', '0632b0c0-4982-48d9-b698-37063bc5e4fe', 'BR_L05', 'late', 'Small but real risk of radiation-induced secondary malignancy.', NULL, 5, true, '2026-04-29 03:43:11.584124+00', '2026-04-29 03:43:11.584124+00') ON CONFLICT DO NOTHING;
INSERT INTO public.radiology_toxicity_library VALUES ('d497362a-d63a-41e9-bbfa-a6682f1e243b', '0632b0c0-4982-48d9-b698-37063bc5e4fe', 'BR_SCF_L01', 'late', 'Radiation-induced brachial plexopathy with numbness, pain, or weakness in the neck, shoulder, or arm.', 'SCF', 6, true, '2026-04-29 03:43:11.584124+00', '2026-04-29 03:43:11.584124+00') ON CONFLICT DO NOTHING;
INSERT INTO public.radiology_toxicity_library VALUES ('7a892a7d-9ef5-4934-84d8-f97c2801d7b4', '0632b0c0-4982-48d9-b698-37063bc5e4fe', 'BR_SCF_L02', 'late', 'Rare risk of rib fracture in the irradiated region.', 'SCF', 7, true, '2026-04-29 03:43:11.584124+00', '2026-04-29 03:43:11.584124+00') ON CONFLICT DO NOTHING;
INSERT INTO public.radiology_toxicity_library VALUES ('48a11399-0bf9-48fc-8a40-4b04835c2c75', '0632b0c0-4982-48d9-b698-37063bc5e4fe', 'BR_LH_L01', 'late', 'Very rare risk of major coronary events related to incidental cardiac dose; mitigation strategies such as deep inspiration breath-hold are used to minimize this.', 'LEFT_HEART', 8, true, '2026-04-29 03:43:11.584124+00', '2026-04-29 03:43:11.584124+00') ON CONFLICT DO NOTHING;


